                    task.wait(1)
                    LP.Character.HumanoidRootPart.CFrame = CFrame.new(781, 292, 1885)
                    task.wait(1)
                    LP.Character.HumanoidRootPart.CFrame = CFrame.new(2021, 199, 822)
                    task.wait(1)
                    LP.Character.HumanoidRootPart.CFrame = CFrame.new(1768, 254, -492)
                    task.wait(1)
                    LP.Character.HumanoidRootPart.CFrame = CFrame.new(550, 221, -1515)
                    task.wait(1)
                    LP.Character.HumanoidRootPart.CFrame = CFrame.new(61, 216, 187)
                end
            end
            teleportSequence()
        end
    })

    Tab_Q:Button({
        Title = "传送到油桶旁",
        Callback = function()
            for _, v in pairs(workspace:GetDescendants()) do
                if v.Name == 'Barrel Template' and v:FindFirstChildOfClass('Part') then
                    if LP.Character and LP.Character:FindFirstChild("HumanoidRootPart") then
                        LP.Character.HumanoidRootPart.CFrame = v:FindFirstChildOfClass('Part').CFrame
                    end
                    break
                end
            end
        end
    })

    Tab_Q:Button({
        Title = "回到自己基地",
        Callback = function()
            for _, c in pairs(workspace.Tycoon.Tycoons:GetChildren()) do
                if c:FindFirstChild("Owner") and c.Owner.Value == LP then
                    for _, v in pairs(c:GetDescendants()) do
                        if v:IsA('Part') then
                            if LP.Character and LP.Character:FindFirstChild("HumanoidRootPart") then
                                LP.Character.HumanoidRootPart.CFrame = v.CFrame
                            end
                            break
                        end
                    end
                    break
                end
            end
        end
    })

    Tab_Q:Button({
        Title = "自动占点",
        Callback = function()
            local oldpos = LP.Character.HumanoidRootPart.CFrame
            local tycoon
            for _, c in pairs(workspace.Tycoon.Tycoons:GetChildren()) do
                if c:FindFirstChild("Owner") and c.Owner.Value == LP then
                    tycoon = c.Name
                    break
                end
            end
            if tostring(workspace["Game Systems"].CapturePoint['Captured Team'].Value) ~= tycoon then
                repeat
                    task.wait()
                    if LP.Character and LP.Character:FindFirstChild("HumanoidRootPart") then
                        LP.Character.HumanoidRootPart.CFrame = CFrame.new(70.7639999, 44.887001, 189) + Vector3.new(0, 5, 0)
                    end
                until tostring(workspace["Game Systems"].CapturePoint['Captured Team'].Value) == tycoon
            end
            task.wait(12)
            if LP.Character and LP.Character:FindFirstChild("HumanoidRootPart") then
                LP.Character.HumanoidRootPart.CFrame = oldpos
            end
        end
    })

    Tab_Q:Button({
        Title = "传送到零件箱子",
        Callback = function()
            local cratesFolder = workspace:FindFirstChild("Game Systems") and workspace["Game Systems"]:FindFirstChild("Crate Workspace")
            if cratesFolder then
                local farthestCrate = nil
                local farthestDistance = 0
                local hrp = LP.Character.HumanoidRootPart
                for _, crate in pairs(cratesFolder:GetChildren()) do
                    if crate.Name == "Tank Crate" and crate:IsA("BasePart") then
                        local distance = (crate.Position - hrp.Position).Magnitude
                        if distance > farthestDistance then
                            farthestDistance = distance
                            farthestCrate = crate
                        end
                    end
                end
                if farthestCrate then
                    hrp.CFrame = farthestCrate.CFrame
                end
            end
        end
    })

