    -- ================ 功能标签页 (E) ================
    local blockFDMG = false
    local fallDamageConnection = nil
    local function initHook()
        if fallDamageConnection then return end
        fallDamageConnection = game:GetService("Players").LocalPlayer.CharacterAdded:Connect(function(char)
            local humanoid = char:WaitForChild("Humanoid")
            local connection
            connection = humanoid.StateChanged:Connect(function(oldState, newState)
                if not blockFDMG then 
                    if connection then connection:Disconnect() end
                    fallDamageConnection = nil
                    return 
                end
                if oldState == Enum.HumanoidStateType.Freefall and newState == Enum.HumanoidStateType.Landed then
                    humanoid.Health = humanoid.MaxHealth
                end
            end)
        end)
        if game:GetService("Players").LocalPlayer.Character then
            local humanoid = game:GetService("Players").LocalPlayer.Character:FindFirstChildOfClass("Humanoid")
            if humanoid then
                local connection
                connection = humanoid.StateChanged:Connect(function(oldState, newState)
                    if not blockFDMG then 
                        if connection then connection:Disconnect() end
                        return 
                    end
                    if oldState == Enum.HumanoidStateType.Freefall and newState == Enum.HumanoidStateType.Landed then
                        humanoid.Health = humanoid.MaxHealth
                    end
                end)
            end
        end
    end
    local function removeHook()
        if fallDamageConnection then
            fallDamageConnection:Disconnect()
            fallDamageConnection = nil
        end
        blockFDMG = false
    end

