    Tab_Aim:Dropdown({ Title = "瞄准部位", Values = { "头部", "躯干", "脚部" }, Value = "头部", Callback = function(Value) AimLockSystem.Config.aimPart = Value end })
    Tab_Aim:Toggle({ Title = "掩体检测", Value = true, Callback = function(Value) AimLockSystem.Config.wallCheckEnabled = Value end })

    local playerList = {}
    local function updatePlayerList()
        playerList = { "全部" }
        for _, player in ipairs(Players:GetPlayers()) do
            if player ~= LocalPlayer then table.insert(playerList, player.Name) end
        end
    end
    updatePlayerList()

    local targetDropdown = Tab_Aim:Dropdown({
        Title = "锁定指定玩家",
        Values = playerList,
        Value = "全部",
        Callback = function(Value)
            if Value == "全部" then
                AimLockSystem.Config.aimlockCertainPlayer = false
                AimLockSystem.Config.selectedPlayer = nil
            else
                for _, player in ipairs(Players:GetPlayers()) do
                    if player.Name == Value then
                        AimLockSystem.Config.aimlockCertainPlayer = true
                        AimLockSystem.Config.selectedPlayer = player
                        break
                    end
                end
            end
        end
    })

    Tab_Aim:Button({ Title = "刷新玩家列表", Callback = function() updatePlayerList(); targetDropdown:Refresh(playerList) end })
