local WeaponTab = Window:Tab({
    Title = "武器修改",
    Icon = "gun",
    IconColor = Color3.fromHex("#FF4500"),
    IconShape = "Square",
    Border = true,
    Locked = false,
})

local AmmoHackActive = false
local DeathMonitor = nil
local SavedWeaponStats = {}
local WeaponLoop = nil

local function ResetWeaponStats()
    for weaponTable, stats in pairs(SavedWeaponStats) do
        for key, value in pairs(stats) do
            if type(value) == "table" then
                if weaponTable[key] then
                    for subKey, subValue in pairs(value) do
                        rawset(weaponTable[key], subKey, subValue)
                    end
                end
            else
                rawset(weaponTable, key, value)
            end
        end
    end
    SavedWeaponStats = {}
end

local function ApplyWeaponMods()
    for _, func in next, getgc(false) do
        if type(func) == "function" then
            local info = debug.getinfo(func)
            if tostring(info.name) == "fireGun" then
                local weaponTable = debug.getupvalue(func, 1)
                if not SavedWeaponStats[weaponTable] then
                    SavedWeaponStats[weaponTable] = {}
                    for key, value in pairs(weaponTable) do
                        if type(value) ~= "function" then
                            SavedWeaponStats[weaponTable][key] = value
                        end
                    end
                    for key, value in pairs(weaponTable) do
                        if type(value) == "table" then
                            SavedWeaponStats[weaponTable][key] = {}
                            for subKey, subValue in pairs(value) do
                                SavedWeaponStats[weaponTable][key][subKey] = subValue
                            end
                        end
                    end
                end
                rawset(weaponTable, "Ammo", math.huge)
                rawset(weaponTable, "Distance", math.huge)
                rawset(weaponTable, "BSpeed", 9999)
                rawset(weaponTable, "BDrop", 0)
                rawset(weaponTable, "FireRate", 2000)
                rawset(weaponTable, "MaxSpread", 0)
                rawset(weaponTable, "MinSpread", 0)
                if weaponTable.FireModes then
                    rawset(weaponTable.FireModes, "Auto", true)
                    rawset(weaponTable.FireModes, "Semi", true)
                    rawset(weaponTable.FireModes, "ChangeFiremode", true)
                end
                rawset(weaponTable, "MinRecoilPower", 0)
                rawset(weaponTable, "MaxRecoilPower", 0)
                rawset(weaponTable, "RecoilPowerStepAmount", 0)
                rawset(weaponTable, "RecoilPunch", 0)
                rawset(weaponTable, "DPunchBase", 0)
                rawset(weaponTable, "AimRecover", 1)
                rawset(weaponTable, "HPunchBase", 0)
                rawset(weaponTable, "VPunchBase", 0)
                rawset(weaponTable, "PunchRecover", 1)
                rawset(weaponTable, "SwayBase", 0)
                rawset(weaponTable, "AimRecoilReduction", math.huge)
                for key, value in next, weaponTable do
                    if type(value) == "table" then
                        for subKey, subValue in next, value do
                            if type(subValue) == "number" then
                                rawset(value, subKey, 0)
                            end
                        end
                    end
                end
            end
        end
    end
end

local function OnCharacterDeath()
    ResetWeaponStats()
    if AmmoHackActive then
        local player = game:GetService("Players").LocalPlayer
        player.CharacterAdded:Wait()
        task.wait(1)
        ApplyWeaponMods()
    end
end

local function SetupDeathHook()
    if DeathMonitor then
        DeathMonitor:Disconnect()
        DeathMonitor = nil
    end
    local player = game:GetService("Players").LocalPlayer
    DeathMonitor = player.CharacterAdded:Connect(function(char)
        local humanoid = char:WaitForChild("Humanoid")
        humanoid.Died:Connect(OnCharacterDeath)
    end)
    if player.Character then
        local humanoid = player.Character:FindFirstChild("Humanoid")
        if humanoid then
            humanoid.Died:Connect(OnCharacterDeath)
        end
    end
end

WeaponTab:Toggle({
    Title = "无限子弹",
    Default = false,
    Callback = function(value)
        AmmoHackActive = value
        if value then
            WindUI:Notify({
                Title = "武器修改",
                Content = "无限子弹已开启",
                Duration = 3
            })
            local player = game:GetService("Players").LocalPlayer
            if player.Character then
                ApplyWeaponMods()
            end
            SetupDeathHook()
            if WeaponLoop then
                WeaponLoop:Disconnect()
            end
            WeaponLoop = player.CharacterAdded:Connect(function()
                if AmmoHackActive then
                    task.wait(1)
                    ApplyWeaponMods()
                    SetupDeathHook()
                end
            end)
        else
            WindUI:Notify({
                Title = "武器修改",
                Content = "无限子弹已关闭，恢复默认",
                Duration = 3
            })
            ResetWeaponStats()
            if WeaponLoop then
                WeaponLoop:Disconnect()
                WeaponLoop = nil
            end
            if DeathMonitor then
                DeathMonitor:Disconnect()
                DeathMonitor = nil
            end
        end
    end
})

local MoveTab = Window:Tab({
    Title = "飞行模式",
    Icon = "feather",
    IconColor = Color3.fromHex("#00CED1"),
    IconShape = "Square",
    Border = true,
    Locked = false,
})

local Player = game:GetService("Players").LocalPlayer
local WalkSpeedActive = false
local WalkSpeedValue = 16
local WalkSpeedConnection = nil
local NoclipActive = false
local NoclipConnection = nil

local function UpdateWalkSpeed()
    if WalkSpeedActive then
        local character = Player.Character
        if character and character:FindFirstChild("Humanoid") then
            character.Humanoid.WalkSpeed = WalkSpeedValue
        end
    end
end

local function StartNoclip()
    NoclipActive = true
    if NoclipConnection then NoclipConnection:Disconnect() end
    NoclipConnection = game:GetService("RunService").RenderStepped:Connect(function()
        if not NoclipActive then return end
        local character = Player.Character
        if character then
            for _, part in pairs(character:GetDescendants()) do
                if part:IsA("BasePart") and part.Name ~= "HumanoidRootPart" then
                    part.CanCollide = false
                end
            end
        end
    end)
end

local function StopNoclip()
    NoclipActive = false
    if NoclipConnection then
        NoclipConnection:Disconnect()
        NoclipConnection = nil
    end
    local character = Player.Character
    if character then
        for _, part in pairs(character:GetDescendants()) do
            if part:IsA("BasePart") then
                part.CanCollide = true
            end
        end
    end
end

MoveTab:Toggle({
    Title = "修改移动速度",
    Default = false,
    Callback = function(value)
        WalkSpeedActive = value
        if value then
            UpdateWalkSpeed()
            if WalkSpeedConnection then WalkSpeedConnection:Disconnect() end
            WalkSpeedConnection = Player.CharacterAdded:Connect(function()
                task.wait(0.5)
                UpdateWalkSpeed()
            end)
        else
            if WalkSpeedConnection then
                WalkSpeedConnection:Disconnect()
                WalkSpeedConnection = nil
            end
            local character = Player.Character
            if character and character:FindFirstChild("Humanoid") then
                character.Humanoid.WalkSpeed = 16
            end
        end
    end
})

MoveTab:Slider({
    Title = "移动速度值",
    Value = {Min = 16, Max = 500, Default = 16},
    Increment = 1,
    Callback = function(value)
        WalkSpeedValue = value
        if WalkSpeedActive then
            UpdateWalkSpeed()
        end
    end
})

MoveTab:Toggle({
    Title = "穿墙",
    Default = false,
    Callback = function(value)
        if value then
            StartNoclip()
        else
            StopNoclip()
        end
    end
})

