local FastInteractActive = false
local FastInteractConnection = nil
local FastInteractBind = nil

local function SetPromptHoldDuration(inst, duration)
    for _, prompt in ipairs(inst:GetDescendants()) do
        if prompt:IsA("ProximityPrompt") then
            prompt.HoldDuration = duration
        end
    end
end

local function EnableFastInteract()
    FastInteractActive = true
    local promptService = game:GetService("ProximityPromptService")
    FastInteractBind = promptService.PromptButtonHoldBegan:Connect(function(prompt)
        prompt.HoldDuration = 0.01
    end)
    SetPromptHoldDuration(workspace, 0.01)
    FastInteractConnection = workspace.DescendantAdded:Connect(function(desc)
        if desc:IsA("ProximityPrompt") and FastInteractActive then
            desc.HoldDuration = 0.01
        end
    end)
end

local function DisableFastInteract()
    FastInteractActive = false
    if FastInteractBind then
        FastInteractBind:Disconnect()
        FastInteractBind = nil
    end
    if FastInteractConnection then
        FastInteractConnection:Disconnect()
        FastInteractConnection = nil
    end
    SetPromptHoldDuration(workspace, 0.5)
end

