local NoFallDamageActive = false
local NoFallDamageConnections = {}

local function DisableFallForChar(character)
    if not character then return end
    local hum = character:FindFirstChildWhichIsA("Humanoid")
    if hum then
        hum:SetStateEnabled(Enum.HumanoidStateType.FallingDown, false)
        hum:SetStateEnabled(Enum.HumanoidStateType.Freefall, false)
        local fallConn = hum:GetPropertyChangedSignal("Health"):Connect(function()
            if NoFallDamageActive and hum and hum.Health > 0 then
                local lastHealth = hum.Health
                task.wait(0.05)
                if hum.Health < lastHealth and hum.Health ~= 0 then
                    hum.Health = lastHealth
                end
            end
        end)
        table.insert(NoFallDamageConnections, fallConn)
    end
end

local function EnableNoFallDamage()
    NoFallDamageActive = true
    local player = game:GetService("Players").LocalPlayer
    local function onCharAdded(char)
        task.wait(0.2)
        DisableFallForChar(char)
    end
    if player.Character then
        DisableFallForChar(player.Character)
    end
    local charConn = player.CharacterAdded:Connect(onCharAdded)
    table.insert(NoFallDamageConnections, charConn)
end

local function DisableNoFallDamage()
    NoFallDamageActive = false
    for _, conn in ipairs(NoFallDamageConnections) do
        conn:Disconnect()
    end
    NoFallDamageConnections = {}
    local player = game:GetService("Players").LocalPlayer
    local hum = player.Character and player.Character:FindFirstChildWhichIsA("Humanoid")
    if hum then
        hum:SetStateEnabled(Enum.HumanoidStateType.FallingDown, true)
        hum:SetStateEnabled(Enum.HumanoidStateType.Freefall, true)
    end
end

OtherTab:Toggle({
    Title = "没有落下伤害",
    Default = false,
    Callback = function(state)
        if state then
            EnableNoFallDamage()
            WindUI:Notify({Title = "其他功能", Content = "禁用落下伤害已开启", Duration = 2})
        else
            DisableNoFallDamage()
            WindUI:Notify({Title = "其他功能", Content = "禁用落下伤害已关闭", Duration = 2})
        end
    end
})

local ReviveEnabled = false
local SavedDeathPosition = nil
local ReviveCharConnection = nil
local ReviveDeathConnection = nil

local function StoreDeathPosition()
    local player = game:GetService("Players").LocalPlayer
    local char = player.Character
    if char and char:FindFirstChild("HumanoidRootPart") then
        SavedDeathPosition = char.HumanoidRootPart.CFrame
    end
end

local function TeleportToDeathPoint(character)
    if not ReviveEnabled then return end
    if SavedDeathPosition then
        task.wait(0.2)
        local root = character and character:FindFirstChild("HumanoidRootPart")
        if root then
            root.CFrame = SavedDeathPosition
            local hum = character:FindFirstChildWhichIsA("Humanoid")
            if hum then
                hum.Health = hum.MaxHealth
            end
            WindUI:Notify({Title = "原地复活", Content = "传送回死亡地点", Duration = 2})
            SavedDeathPosition = nil
        end
    end
end

local function SetupReviveHooks()
    local player = game:GetService("Players").LocalPlayer
    if ReviveCharConnection then ReviveCharConnection:Disconnect() end
    ReviveCharConnection = player.CharacterAdded:Connect(TeleportToDeathPoint)
    if ReviveDeathConnection then ReviveDeathConnection:Disconnect() end
    local function onCharacterDeath()
        if ReviveEnabled then
            StoreDeathPosition()
        end
    end
    local function onCharacterAdded(char)
        local hum = char:WaitForChild("Humanoid")
        ReviveDeathConnection = hum.Died:Connect(onCharacterDeath)
    end
    if player.Character then
        onCharacterAdded(player.Character)
    end
    player.CharacterAdded:Connect(onCharacterAdded)
end

local function EnableRevive()
    ReviveEnabled = true
    SetupReviveHooks()
    WindUI:Notify({Title = "原地复活", Content = "已开启", Duration = 2})
end

local function DisableRevive()
    ReviveEnabled = false
    if ReviveCharConnection then
        ReviveCharConnection:Disconnect()
        ReviveCharConnection = nil
    end
    if ReviveDeathConnection then
        ReviveDeathConnection:Disconnect()
        ReviveDeathConnection = nil
    end
    SavedDeathPosition = nil
    WindUI:Notify({Title = "原地复活", Content = "已关闭", Duration = 2})
end

OtherTab:Toggle({
    Title = "死亡原地复活",
    Default = false,
    Callback = function(state)
        if state then
            EnableRevive()
        else
            DisableRevive()
        end
    end
})

local function RemoveAllGatesAndDoors()
    local workspace = game:GetWorkspace()
    local tycoonSystem = workspace:FindFirstChild("Tycoon")
    if not tycoonSystem then
        WindUI:Notify({Title = "删除门", Content = "未找到Tycoon系统", Duration = 2})
        return
    end
    local tycoons = tycoonSystem:FindFirstChild("Tycoons")
    if not tycoons then return end
    local destroyedCount = 0
    for _, tycoon in pairs(tycoons:GetChildren()) do
        local purchased = tycoon:FindFirstChild("PurchasedObjects")
        if purchased then
            for _, obj in pairs(purchased:GetChildren()) do
                local name = obj.Name:lower()
                if name:find("door") or name:find("gate") then
                    obj:Destroy()
                    destroyedCount = destroyedCount + 1
                end
            end
        end
    end
    WindUI:Notify({Title = "删除门", Content = "已删除 " .. destroyedCount .. " 个门/闸门", Duration = 3})
end

OtherTab:Button({
    Title = "删除激光门或门",
    Callback = function()
        RemoveAllGatesAndDoors()
    end
})



-- ================ 轰炸护盾功能 ================
local Bases = {
    "Alpha", "Bravo", "Charlie", "Delta", "Echo", "Foxtrot", "Golf", "Hotel",
    "Juliet", "Kilo", "Lima", "Omega", "Romeo", "Sierra", "Tango", "Victor",
    "Yankee", "Zulu"
}

local SelectedBase = nil
local BombingActive = false
local BombingLoop = nil
local BombInterval = 0.1

local function GetWeaponFromBackpack()
    local player = game:GetService("Players").LocalPlayer
    local backpack = player:FindFirstChild("Backpack")
    if not backpack then return nil end
    for _, tool in ipairs(backpack:GetChildren()) do
        if tool:IsA("Tool") and tool.Name == "RPG" then
            return tool
        end
    end
    return nil
end

local function GetShieldPart(baseName)
    if not baseName then return nil end
    local tycoon = workspace:FindFirstChild("Tycoon")
    if not tycoon then return nil end
    local tycoons = tycoon:FindFirstChild("Tycoons")
    if not tycoons then return nil end
    local base = tycoons:FindFirstChild(baseName)
    if not base then return nil end
    local purchased = base:FindFirstChild("PurchasedObjects")
    if not purchased then return nil end
    local shieldModel = purchased:FindFirstChild("Base Shield")
    if not shieldModel then return nil end
    local shield = shieldModel:FindFirstChild("Shield")
    if not shield then return nil end
    local shieldPart = shield:FindFirstChild("Shield2")
    return shieldPart
end

local function FireRocket()
    if not BombingActive then return end
    local currentBase = SelectedBase
    if not currentBase then
        return
    end
    local weapon = GetWeaponFromBackpack()
    if not weapon then
        WindUI:Notify({Title = "轰炸护盾", Content = "背包中未找到RPG武器", Duration = 2})
        BombingActive = false
        return
    end
    local shieldPart = GetShieldPart(currentBase)
    if not shieldPart then
        WindUI:Notify({Title = "轰炸护盾", Content = "未找到基地 " .. currentBase .. " 的护盾", Duration = 2})
        BombingActive = false
        return
    end
    local player = game:GetService("Players").LocalPlayer
    local character = player.Character
    if not character then return end
    local rootPart = character:FindFirstChild("HumanoidRootPart")
    if not rootPart then return end
    local origin = rootPart.Position
    local targetPos = shieldPart.Position
    local args = {
        {
            Normal = Vector3.new(0, 0, 1),
            Player = player,
            HitPart = shieldPart,
            Origin = origin,
            Label = player.Name .. "Rocket" .. tostring(math.random(1, 9999)),
            Vehicle = weapon,
            Position = targetPos,
            Weapon = weapon
        }
    }
    local rocketEvent = game:GetService("ReplicatedStorage"):FindFirstChild("RocketSystem")
    if rocketEvent then
        rocketEvent = rocketEvent:FindFirstChild("Events")
        if rocketEvent then
            rocketEvent = rocketEvent:FindFirstChild("RocketHit")
            if rocketEvent then
                rocketEvent:FireServer(unpack(args))
            end
        end
    end
end

local function StartBombingLoop()
    if BombingLoop then return end
    BombingLoop = coroutine.wrap(function()
        while BombingActive do
            FireRocket()
            task.wait(BombInterval)
        end
        BombingLoop = nil
    end)
    BombingLoop()
end

local function StopBombingLoop()
    BombingActive = false
    BombingLoop = nil
end

OtherTab:Dropdown({
    Title = "选择轰炸基地",
    Values = Bases,
    Value = "",
    Callback = function(value)
        SelectedBase = value
    end
})

OtherTab:Toggle({
    Title = "轰炸护盾",
    Default = false,
    Callback = function(state)
        if state then
            if not SelectedBase then
                WindUI:Notify({Title = "轰炸护盾", Content = "请先选择一个基地", Duration = 2})
                return
            end
            BombingActive = true
            StartBombingLoop()
            WindUI:Notify({Title = "轰炸护盾", Content = "正在轰炸 " .. SelectedBase, Duration = 2})
        else
            StopBombingLoop()
            WindUI:Notify({Title = "轰炸护盾", Content = "已停止轰炸", Duration = 2})
        end
    end
})
