local PlayersService = game:GetService("Players")
local RunService = game:GetService("RunService")
local UserInputService = game:GetService("UserInputService")
local Camera = workspace.CurrentCamera
local LocalPlayer = PlayersService.LocalPlayer

local EspEnabled = false
local EspConnections = {}
local EspTexts = {}
local EspColor = Color3.fromRGB(255, 0, 0)
local EspShowName = true
local EspShowDistance = true

local function GetWeapon(plr)
    local char = plr.Character
    if not char then return "无" end
    for _, obj in ipairs(char:GetChildren()) do
        if obj:IsA("Tool") then
            return obj.Name
        end
    end
    return "无"
end

local function GetArmor(plr)
    local char = plr.Character
    if not char then return 0 end
    local humanoid = char:FindFirstChildWhichIsA("Humanoid")
    if humanoid then
        local armorAttr = humanoid:GetAttribute("Armor")
        if armorAttr then return armorAttr end
        local armorVal = humanoid:FindFirstChild("Armor")
        if armorVal and armorVal:IsA("NumberValue") then
            return armorVal.Value
        end
    end
    local armorPart = char:FindFirstChild("Armor")
    if armorPart and armorPart:IsA("NumberValue") then
        return armorPart.Value
    end
    return 0
end

local function GetState(plr)
    local char = plr.Character
    if not char then return "步行" end
    local seat = char:FindFirstChildWhichIsA("VehicleSeat")
    if seat and seat.Occupant == char then
        local vehicle = seat.Parent
        if vehicle then
            return vehicle.Name
        end
    end
    return "步行"
end

local function GetHeadPosition(plr)
    if not plr.Character then return nil end
    local head = plr.Character:FindFirstChild("Head")
    if not head then
        head = plr.Character:FindFirstChild("HumanoidRootPart")
    end
    return head and head.Position or nil
end

local function CreateEspText()
    local text = Drawing.new("Text")
    text.Size = 13
    text.Center = true
    text.Outline = true
    text.OutlineColor = Color3.new(0,0,0)
    text.Transparency = 1
    text.Visible = false
    return text
end

local function UpdateEsp()
    if not EspEnabled then return end
    for _, plr in ipairs(PlayersService:GetPlayers()) do
        if plr ~= LocalPlayer then
            local char = plr.Character
            local humanoid = char and char:FindFirstChildWhichIsA("Humanoid")
            if humanoid and humanoid.Health > 0 then
                local headPos = GetHeadPosition(plr)
                if headPos then
                    local screenPos, onScreen = Camera:WorldToViewportPoint(headPos)
                    if onScreen then
                        local distance = math.floor((headPos - (LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("HumanoidRootPart") and LocalPlayer.Character.HumanoidRootPart.Position or Vector3.new(0,0,0))).Magnitude)
                        local weapon = GetWeapon(plr)
                        local armor = GetArmor(plr)
                        local state = GetState(plr)
                        local texts = EspTexts[plr]
                        if not texts then
                            texts = { Line1 = CreateEspText(), Line2 = CreateEspText() }
                            EspTexts[plr] = texts
                        end
                        local line1Parts = {}
                        if EspShowName then table.insert(line1Parts, plr.Name) end
                        if EspShowDistance then table.insert(line1Parts, distance .. "m") end
                        table.insert(line1Parts, weapon)
                        table.insert(line1Parts, "护甲:" .. armor)
                        local line1Text = table.concat(line1Parts, " ")
                        texts.Line1.Text = line1Text
                        texts.Line1.Color = EspColor
                        texts.Line1.Position = Vector2.new(screenPos.X, screenPos.Y - 45)
                        texts.Line1.Visible = (line1Text ~= "")
                        local line2Text = state
                        texts.Line2.Text = line2Text
                        texts.Line2.Color = EspColor
                        texts.Line2.Position = Vector2.new(screenPos.X, screenPos.Y - 30)
                        texts.Line2.Visible = true
                    else
                        if EspTexts[plr] then
                            EspTexts[plr].Line1.Visible = false
                            EspTexts[plr].Line2.Visible = false
                        end
                    end
                end
            else
                if EspTexts[plr] then
                    EspTexts[plr].Line1.Visible = false
                    EspTexts[plr].Line2.Visible = false
                end
            end
        end
    end
end

local function StartEsp()
    EspEnabled = true
    local conn = RunService.RenderStepped:Connect(UpdateEsp)
    table.insert(EspConnections, conn)
end

local function StopEsp()
    EspEnabled = false
    for _, conn in ipairs(EspConnections) do
        conn:Disconnect()
    end
    EspConnections = {}
    for _, texts in pairs(EspTexts) do
        texts.Line1:Remove()
        texts.Line2:Remove()
    end
    EspTexts = {}
end
    end
})

