local AimlockEnabled = false
local IgnoreWalls = true
local PredictionEnabled = false
local PredictionFactor = 1.0
local AimlockKey = Enum.UserInputType.MouseButton2
local AimlockFOV = 150
local Whitelist = {}
local CurrentTarget = nil
local AimConnection = nil
local WhitelistDropdown = nil
local PlayerList = {}

local function IsVisible(part)
    if not IgnoreWalls then return true end
    local origin = Camera.CFrame.Position
    local direction = (part.Position - origin).Unit
    local raycastParams = RaycastParams.new()
    raycastParams.FilterType = Enum.RaycastFilterType.Blacklist
    raycastParams.FilterDescendantsInstances = {LocalPlayer.Character}
    local result = workspace:Raycast(origin, direction * (part.Position - origin).Magnitude, raycastParams)
    if result then
        local hit = result.Instance
        local hitParent = hit
        while hitParent.Parent do
            if hitParent:IsA("Model") and hitParent:FindFirstChild("Humanoid") then
                return hitParent == part.Parent
            end
            hitParent = hitParent.Parent
        end
        return false
    end
    return true
end

local function GetPredictedPosition(targetPart, targetVelocity)
    if not PredictionEnabled then return targetPart.Position end
    local bulletSpeed = 3000
    local distance = (targetPart.Position - Camera.CFrame.Position).Magnitude
    local travelTime = distance / bulletSpeed
    return targetPart.Position + targetVelocity * travelTime * PredictionFactor
end

local function GetClosestPlayerInFOV()
    local character = LocalPlayer.Character
    if not character or not character:FindFirstChild("HumanoidRootPart") then return nil, nil end
    local rootPos = character.HumanoidRootPart.Position
    local cameraCF = Camera.CFrame
    local closestAngle = AimlockFOV
    local closestPlayer = nil
    local closestPart = nil
    for _, plr in ipairs(PlayersService:GetPlayers()) do
        if plr ~= LocalPlayer and not Whitelist[plr.Name] then
            local char = plr.Character
            if char then
                local humanoid = char:FindFirstChildWhichIsA("Humanoid")
                if humanoid and humanoid.Health > 0 then
                    local head = char:FindFirstChild("Head") or char:FindFirstChild("HumanoidRootPart")
                    if head then
                        local screenPos, onScreen = Camera:WorldToViewportPoint(head.Position)
                        if onScreen then
                            local angle = (cameraCF:PointToObjectSpace(head.Position) - cameraCF:PointToObjectSpace(rootPos)).Unit
                            local angleDeg = math.deg(math.acos(angle.Z))
                            if angleDeg < closestAngle and IsVisible(head) then
                                closestAngle = angleDeg
                                closestPlayer = plr
                                closestPart = head
                            end
                        end
                    end
                end
            end
        end
    end
    return closestPlayer, closestPart
end

local function AimAtTarget()
    local target, targetPart = GetClosestPlayerInFOV()
    if target and targetPart then
        CurrentTarget = target
        local velocity = Vector3.new(0,0,0)
        if PredictionEnabled and target.Character and target.Character:FindFirstChild("HumanoidRootPart") then
            local currentPos = targetPart.Position
            task.wait(0.05)
            local newPos = targetPart.Position
            velocity = (newPos - currentPos) / 0.05
        end
        local aimPos = GetPredictedPosition(targetPart, velocity)
        local targetDir = (aimPos - Camera.CFrame.Position).Unit
        local newCF = CFrame.new(Camera.CFrame.Position, Camera.CFrame.Position + targetDir)
        Camera.CFrame = newCF
    else
        CurrentTarget = nil
    end
end

local function StartAimlock()
    if AimConnection then return end
    AimConnection = RunService.RenderStepped:Connect(function()
        if AimlockEnabled and UserInputService:IsMouseButtonPressed(AimlockKey) then
            AimAtTarget()
        end
    end)
end

local function StopAimlock()
    if AimConnection then
        AimConnection:Disconnect()
        AimConnection = nil
    end
    CurrentTarget = nil
end

