FarmTab:Toggle({
    Title = "自动出售刀具",
    Default = false,
    Callback = function(Value)
        autoSellEnabled = Value
        if autoSellEnabled then
            task.spawn(function()
                while autoSellEnabled do
                    local returnPos = rootPart.CFrame
                    rootPart.CFrame = pickupCFrame
                    task.wait(0.3)
                    
                    local pickupTimeout = 0
                    while autoSellEnabled and not character:FindFirstChild("OpenBox") and pickupTimeout < 50 do
                        if boxPrompt then fireproximityprompt(boxPrompt) end
                        task.wait(0.1)
                        pickupTimeout = pickupTimeout + 1
                    end
                    
                    if character:FindFirstChild("OpenBox") then
                        rootPart.CFrame = sellCFrame
                        local sellTimeout = 0
                        while character:FindFirstChild("OpenBox") and sellTimeout < 50 do
                            task.wait(0.1)
                            sellTimeout = sellTimeout + 1
                        end
                        task.wait(0.2) 
                    end

                    rootPart.CFrame = returnPos
                    
                    local timeLeft = sellInterval
                    while timeLeft > 0 and autoSellEnabled do
                        task.wait(1)
                        timeLeft = timeLeft - 1
                    end
                end
                WindUI:Notify({Title = "自动出售", Content = "已停止", Duration = 1})
            end)
            WindUI:Notify({Title = "自动出售", Content = "已开启，间隔" .. (sellInterval/60) .. "分钟", Duration = 2})
        else
