-- ==================== 核心变量 ====================
local Players = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService = game:GetService("RunService")
local UserInputService = game:GetService("UserInputService")
local player = Players.LocalPlayer

local isSpamming = false
local targetPlayer = nil
local vehiclesSpawned = 0
local isInvisibleMode = false
local spawnConnection = nil

-- 获取玩家列表
local function getPlayerList()
    local list = {}
    for _, p in pairs(Players:GetPlayers()) do
        if p ~= player then
            table.insert(list, p.Name)
        end
    end
    return list
end

-- 设置车辆可见性
local function setVehicleVisibility(visible)
    local processed = 0
    for _, obj in pairs(workspace:GetChildren()) do
        local isVehicle = (obj.Name:lower():find("joop") or 
                          obj.Name:lower():find("car") or 
                          obj.Name:lower():find("vehicle") or
                          obj.Name:lower():find("mobil") or
                          obj:FindFirstChild("VehicleSeat") or
                          obj:FindFirstChild("Seat"))
        if isVehicle then
            processed = processed + 1
            for _, part in pairs(obj:GetDescendants()) do
                if part:IsA("BasePart") then
                    part.Transparency = visible and 0 or 1
                    part.CanCollide = visible
                    if not visible then part.Anchored = true end
                elseif part:IsA("Decal") or part:IsA("Texture") then
                    part.Transparency = visible and 0 or 1
                elseif part:IsA("ParticleEmitter") or part:IsA("Fire") or part:IsA("Smoke") then
                    part.Enabled = visible
                elseif part:IsA("PointLight") or part:IsA("SpotLight") then
                    part.Enabled = visible
                end
            end
        end
    end
    return processed
end

-- 传送车辆到目标
local function teleportVehiclesToTarget()
    if not targetPlayer or not targetPlayer.Character or not targetPlayer.Character:FindFirstChild("HumanoidRootPart") then return end
    local targetCFrame = targetPlayer.Character.HumanoidRootPart.CFrame
    local targetPos = targetCFrame.Position + targetCFrame.LookVector * 3
    for _, obj in pairs(workspace:GetChildren()) do
        if obj.Name:lower():find("joop") or obj.Name:lower():find("car") then
            local primary = obj.PrimaryPart or obj:FindFirstChildOfClass("BasePart")
            if primary then
                primary.CFrame = CFrame.new(targetPos + Vector3.new(math.random(-4,4), 0, math.random(-3,3)))
            end
        end
    end
end

-- 生成车辆
local function spawnVehicle()
    local spawnEvent = ReplicatedStorage:FindFirstChild("SpawnCar")
    if spawnEvent then
        spawnEvent:FireServer("Joop")
        vehiclesSpawned = vehiclesSpawned + 1
        task.wait(0.1)
        teleportVehiclesToTarget()
        setVehicleVisibility(not isInvisibleMode)
    end
end

-- 持续强制隐形循环
task.spawn(function()
    while true do
        if isInvisibleMode then
            setVehicleVisibility(false)
        end
        task.wait(0.3)
    end
end)

