-- 自动开门（循环）
local doorLoop
AutoTab:Toggle({
    Title = "自动开门 (密码3842)",
    Default = false,
    Callback = function(state)
        if doorLoop then
            task.cancel(doorLoop)
            doorLoop = nil
        end
        if state then
            doorLoop = task.spawn(function()
                while true do
                    pcall(function()
                        for _, door in ipairs(game.Workspace:FindFirstChild("Doors") or {}) do
                            if door:FindFirstChild("ClickDetector") then
                                fireclickdetector(door.ClickDetector)
                            end
                        end
                    end)
                    task.wait(0.5)
                end
            end)
            WindUI:Notify({Title = "自动开门", Content = "已开启", Duration = 1})
        else
            WindUI:Notify({Title = "自动开门", Content = "已关闭", Duration = 1})
        end
    end
})

