                clearSkeleton(character)
                clearHealthESP(character)
                clearTracer(character)
                clearChams(character)
            end
        end)
        local humanoid = character:FindFirstChild('Humanoid')
        if humanoid then
            humanoid.Died:Connect(function()
                clearESP(character)
                clearSkeleton(character)
                clearHealthESP(character)
                clearTracer(character)
                clearChams(character)
            end)
        end
    end)
end)
   
