local function autoClaimRewards()
   
    for day = 1, 12 do
        Signal.InvokeServer("claimDailyReward", day)
        task.wait(0.1)
    end
    
   
    for tier = 1, 3 do
        for level = 1, 6 do
            Signal.InvokeServer("claimPlaytimeReward", tier, level)
            task.wait(0.1)
        end
    end
    
    WindUI:Notify({Title = "自动领取", Content = "奖励领取完成", Duration = 2})
end

