        local locations = {
            ["房屋"] = CFrame.new(164.408112, -93.5687103, 228.658173, 0.99991262, 0.000353183481, -0.0132142855, 8.33566993e-9, 0.999642968, 0.0267184861, 0.0132190045, -0.0267161522, 0.999555647),
