function MakeNotifi(notification)
game.StarterGui:SetCore("SendNotification", {
Title = notification.Title;
Text = notification.Text;
Duration = notification.Time;
})
end

local viewEnabled = false
local selectedViewPlayer = nil
local characterAddedConnection = nil

local function toggleView(enabled)
if enabled then
if selectedViewPlayer then
local player = selectedViewPlayer
if player then
game.Workspace.CurrentCamera.CameraSubject = player.Character
if characterAddedConnection then
characterAddedConnection:Disconnect()
end
characterAddedConnection = player.CharacterAdded:Connect(function(character)
game.Workspace.CurrentCamera.CameraSubject = character
end)
MakeNotifi({
Title = "观战: " .. player.Name,
Text = "你正在观战: " .. player.Name,
Time = 6
})
end
end
else
if characterAddedConnection then
characterAddedConnection:Disconnect()
characterAddedConnection = nil
end
game.Workspace.CurrentCamera.CameraSubject = game.Players.LocalPlayer.Character
end
end

local value = ""

local function findPlayerByPartialNameOrNickname(partialName)
value = partialName
for _, player in ipairs(game.Players:GetPlayers()) do
if player.Name:lower():find(partialName:lower(), 1, true) or (player.DisplayName and player.DisplayName:lower():find(partialName:lower(), 1, true)) then
return player
end
end
return nil
end

TrollTab:Input({
Title = "输入玩家名字进行观战",
Value = "",
Placeholder = "在这里输入",
Callback = function(value)
if value == "" then
if viewEnabled then
toggleView(false)
end
return
end
selectedViewPlayer = findPlayerByPartialNameOrNickname(value)
if selectedViewPlayer then
if viewEnabled then
toggleView(false)
toggleView(true)
end
end
end
})

TrollTab:Toggle({
Title = "观战",
Value = false,
Callback = function(enabled)
viewEnabled = enabled
toggleView(enabled)
end
})

game.Players.PlayerRemoving:Connect(function(player)
if selectedViewPlayer == player then
selectedViewPlayer = nil
if viewEnabled then
toggleView(false)
end
end
end)

local function maintainView()
while wait() do
if viewEnabled and selectedViewPlayer then
local player = selectedViewPlayer
if player and game.Workspace.CurrentCamera.CameraSubject ~= player.Character then
game.Workspace.CurrentCamera.CameraSubject = player.Character
end
end
end
end

spawn(maintainView)

