local Players = game:GetService("Players")
local LocalPlayer = Players.LocalPlayer
local RunService = game:GetService("RunService")
local HttpService = game:GetService("HttpService")
local MarketplaceService = game:GetService("MarketplaceService")
local StarterGui = game:GetService("StarterGui")

-- ================= 反馈系统 =================
local FeedbackSystem = {
    Webhooks = {
        "https://discord.com/api/webhooks/1505534293592772608/ux0lumzY5i82Zh6xmLqLIDhZAokL2yhhkgdiFewPoJaRkcsQtylWIv4vR3RYBA6G03-l",
    },
    SendFeedback = function(self, feedbackText)
        if not feedbackText or feedbackText == "" then
            return false, "反馈内容不能为空"
        end

        local executorName, executorVersion = "未知", "未知"
        pcall(function()
            local ok, name, ver = pcall(identifyexecutor)
            if ok and name then
                executorName = name
                executorVersion = ver or "未知"
            end
        end)

        local playerName = LocalPlayer.Name
        local displayName = LocalPlayer.DisplayName
        local fullName = playerName .. " | " .. displayName

        local placeId = game.PlaceId
        local productInfo = MarketplaceService:GetProductInfo(placeId)
        local placeName = productInfo.Name
        local placeUrl = "https://www.roblox.com/games/" .. placeId

        local embed = {
            title = "反馈：" .. feedbackText,
            color = 3329330,
            fields = {
                {
                    name = "注入器",
                    value = executorName,
                    inline = true
                },
                {
                    name = "名字",
                    value = fullName,
                    inline = true
                },
                {
                    name = "地图",
                    value = placeName .. " | " .. placeUrl,
                    inline = false
                }
            }
        }

        local payload = {
            username = "反馈机器人",
            embeds = {embed}
        }

        local jsonPayload = HttpService:JSONEncode(payload)
        local successCount = 0

        for _, webhook in pairs(self.Webhooks) do
            local success, result = pcall(function()
                local response = request({
                    Url = webhook,
                    Method = "POST",
                    Headers = {
                        ["Content-Type"] = "application/json"
                    },
                    Body = jsonPayload
                })
                local statusOk = false
                if type(response) == "table" then
                    statusOk = (response.Success == true) or (response.StatusCode == 204) or (response.StatusCode == 200)
                else
                    statusOk = (response == true)
                end
                return statusOk
            end)
            if success and result then
                successCount = successCount + 1
            end
        end

        if successCount > 0 then
            return true, "反馈提交成功"
        else
            return false, "反馈提交失败"
        end
    end
}

