    Title = "反馈内容",
    Placeholder = "请输入反馈内容...",
    Desc = "请输入您的反馈内容",
    Callback = function(text)
        feedbackText = text
    end
})

local function getInputText()
    if not feedbackInputObject then
        return feedbackText or ""
    end
    local text = feedbackInputObject.Value or feedbackInputObject.Text or feedbackInputObject.InputText
    if text and text ~= "" then
        return text
    end
    local realInput = feedbackInputObject:FindFirstChildWhichIsA("TextBox") or feedbackInputObject:FindFirstChild("Input")
    if realInput then
        text = realInput.Text
        if text and text ~= "" then
            return text
        end
    end
    return feedbackText or ""
end

