            return
        end

        local success, msg = FeedbackSystem:SendFeedback(text)
        if success then
            pcall(function()
                Window:Notify({
                    Title = "反馈成功",
                    Content = msg,
                    Icon = "check",
                    Duration = 3
                })
            end)
            pcall(function()
                StarterGui:SetCore("SendNotification", {
                    Title = "大寒脚本",
