                    Duration = 3
                })
            end)
        else
            pcall(function()
                Window:Notify({
                    Title = "反馈失败",
                    Content = msg,
                    Icon = "x",
                    Duration = 3
                })
            end)
            pcall(function()
                StarterGui:SetCore("SendNotification", {
                    Title = "大寒脚本",
                    Text = msg,
                    Duration = 3
                })
            end)
        end
    end
})

-- ================= 观战标签页（修复） =================
-- 修正定义：去掉空格，正确赋值
Tabs.SpectateTab = Window:Tab({ Title = "观战系统", Icon = "eye" })
-- 重要：创建局部变量指向该标签页，后面才能直接用 SpectateTab
local SpectateTab = Tabs.SpectateTab

local displayNameMode = "用户名"
local selectedPlayer = ""

-- 观战系统核心（与之前相同）
local SpectateSystem = {
    CurrentTarget = nil,
    OriginalCameraSubject = nil,
    Connection = nil,

    SpectatePlayer = function(self, playerName, displayNameMode)
        local targetPlayer = nil
        if displayNameMode == "显示名称" then
            for _, player in pairs(Players:GetPlayers()) do
                if player.DisplayName == playerName then
                    targetPlayer = player
                    break
                end
            end
        else
            for _, player in pairs(Players:GetPlayers()) do
                if player.Name == playerName then
                    targetPlayer = player
                    break
                end
            end
        end

        if not targetPlayer then
            return false, "找不到目标玩家"
        end
        if targetPlayer == LocalPlayer then
            return false, "不能观战自己"
        end

        self:StopSpectating()
        self.OriginalCameraSubject = workspace.CurrentCamera.CameraSubject
        self.CurrentTarget = targetPlayer

        local function updateCamera()
            local character = targetPlayer.Character
            if character then
                local humanoid = character:FindFirstChildOfClass("Humanoid")
                if humanoid then
                    workspace.CurrentCamera.CameraSubject = humanoid
                    return true
                end
            end
            return false
        end

        if not updateCamera() then
            self.CurrentTarget = nil
            return false, "目标角色不存在"
        end

        self.Connection = RunService.Heartbeat:Connect(function()
            if self.CurrentTarget then
                updateCamera()
            end
        end)
        return true, "开始观战"
    end,

    StopSpectating = function(self)
        if self.Connection then
            self.Connection:Disconnect()
            self.Connection = nil
        end
        if self.OriginalCameraSubject then
            workspace.CurrentCamera.CameraSubject = self.OriginalCameraSubject
            self.OriginalCameraSubject = nil
        end
        self.CurrentTarget = nil
        return true
    end
}

-- 刷新玩家列表
local function refreshPlayerList()
    local players = {}
    for _, player in pairs(Players:GetPlayers()) do
        if player ~= LocalPlayer then
            if displayNameMode == "显示名称" then
                table.insert(players, player.DisplayName)
            else
                table.insert(players, player.Name)
            end
        end
    end
    return players
end

