local playerDropdown = SpectateTab:Dropdown({
    Title = "选择玩家",
    Value = "",
    Values = refreshPlayerList(),
    Callback = function(value)
        selectedPlayer = value[1]
    end
})

-- 显示模式切换
SpectateTab:Dropdown({
    Title = "列表显示模式",
    Value = "用户名",
    Values = {"用户名", "显示名称"},
    Callback = function(value)
        displayNameMode = value[1]
        playerDropdown:Refresh(refreshPlayerList())
    end
})

-- 刷新按钮
SpectateTab:Button({
