    Desc = "切换到指定玩家视角",
    Value = false,
    Callback = function(value)
        if value then
            if selectedPlayer == "" then
                Window:Notify({
                    Title = "错误",
                    Content = "请先选择玩家",
                    Icon = "x"
                })
                return
            end
            local success, message = SpectateSystem:SpectatePlayer(selectedPlayer, displayNameMode)
            Window:Notify({
                Title = success and "成功" or "错误",
