local SelfHitboxSection = HitboxTab:Section({
    Title = "自己碰撞箱",
    Opened = true
})

SelfHitboxSection:Input({
    Title = "自己碰撞箱大小",
    Placeholder = "5",
    Callback = function(Text)
        local size = tonumber(Text)
        if not size then return end
        selfHitboxSize = size
        -- 断开旧循环
        if selfHitboxLoop then
            selfHitboxLoop:Disconnect()
            selfHitboxLoop = nil
        end
        -- 创建新循环
        selfHitboxLoop = game:GetService("RunService").RenderStepped:Connect(function()
            local player = game.Players.LocalPlayer
            if player and player.Character then
                local rootPart = player.Character:FindFirstChild("HumanoidRootPart")
                if rootPart then
                    pcall(function()
                        rootPart.Size = Vector3.new(selfHitboxSize, selfHitboxSize, selfHitboxSize)
                        rootPart.Transparency = 0.7
                        rootPart.Material = "Neon"
                        rootPart.CanCollide = false
                    end)
                end
            end
        end)
        Window:Notify({
            Title = "自己碰撞箱",
            Content = "自己碰撞箱已启动，尺寸: " .. size,
            Icon = "check"
        })
    end
})

SelfHitboxSection:Input({
    Title = "碰撞值（穿墙）",
    Placeholder = "0~1",
    Callback = function(Text)
        local val = tonumber(Text)
        if not val or val < 0 or val > 1 then
            Window:Notify({ Title = "错误", Content = "请输入0~1之间的数值", Icon = "x" })
            return
        end
        hitboxCollideValue = val
        if hitboxCollideLoop then
            hitboxCollideLoop:Disconnect()
            hitboxCollideLoop = nil
        end
        hitboxCollideLoop = game:GetService("RunService").RenderStepped:Connect(function()
            for _, player in ipairs(game.Players:GetPlayers()) do
                if player ~= game.Players.LocalPlayer and player.Character then
                    pcall(function()
                        for _, part in ipairs(player.Character:GetDescendants()) do
                            if part:IsA("BasePart") then
                                if val == 0 then
                                    part.CanCollide = false
                                    part.CanTouch = false
                                elseif val == 1 then
                                    part.CanCollide = true
                                    part.CanTouch = true
                                else
                                    part.CanCollide = false
                                    part.CanTouch = true
                                end
                            end
                        end
                    end)
                end
            end
        end)
        local statusText
        if val == 0 then statusText = "全穿墙模式"
        elseif val == 1 then statusText = "正常碰撞模式"
        else statusText = string.format("普通穿墙模式（%.2f）", val) end
        Window:Notify({ Title = "碰撞值", Content = statusText, Icon = "info" })
    end
})

SelfHitboxSection:Input({
    Title = "自己碰撞值（穿墙）",
    Placeholder = "0~1",
    Callback = function(Text)
        local val = tonumber(Text)
        if not val or val < 0 or val > 1 then
            Window:Notify({ Title = "错误", Content = "请输入0~1之间的数值", Icon = "x" })
            return
        end
        selfHitboxCollideValue = val
        if selfHitboxCollideLoop then
            selfHitboxCollideLoop:Disconnect()
            selfHitboxCollideLoop = nil
        end
        selfHitboxCollideLoop = game:GetService("RunService").RenderStepped:Connect(function()
            local player = game.Players.LocalPlayer
            if player and player.Character then
                pcall(function()
                    for _, part in ipairs(player.Character:GetDescendants()) do
                        if part:IsA("BasePart") then
                            if val == 0 then
                                part.CanCollide = false
                                part.CanTouch = false
                            elseif val == 1 then
                                part.CanCollide = true
                                part.CanTouch = true
                            else
                                part.CanCollide = false
                                part.CanTouch = true
                            end
                        end
                    end
                end)
            end
        end)
        local statusText
        if val == 0 then statusText = "自己全穿墙模式"
        elseif val == 1 then statusText = "自己正常碰撞模式"
        else statusText = string.format("自己普通穿墙模式（%.2f）", val) end
        Window:Notify({ Title = "自己碰撞值", Content = statusText, Icon = "info" })
    end
})

