                local floatDown = TweenService:Create(btn, TweenInfo.new(0.5, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut, -1, true), {Position = UDim2.new(0, 0, 0, 2)})
                currentFloatTween = {floatUp, floatDown}
