        local function extractAnswerFromReasoning(reasoning)
            if not reasoning or reasoning == "" then return nil end
            local answer = reasoning:match("答[:：]%s*(.-)$")
            if not answer then answer = reasoning:match("答案[:：]%s*(.-)$") end
            if not answer then
                local lines = {}
                for line in reasoning:gmatch("[^\n]+") do table.insert(lines, line) end
                if #lines > 0 then answer = lines[#lines] end
            end
            return answer
        end

        local function performRequest(bodyJson, retryCount)
            local success, response = pcall(function()
                local options = {
                    Url = API_URL,
                    Method = "POST",
                    Headers = {
                        ["Content-Type"] = "application/json",
                        ["Authorization"] = "Bearer " .. API_KEY
                    },
                    Body = bodyJson
                }
                if TIMEOUT then options.Timeout = TIMEOUT end
                return request_func(options)
            end)
            if not success then
                if retryCount < MAX_RETRIES then
                    addMessage("system", " 网络波动，正在重试...", true)
                    task.wait(1)
                    return performRequest(bodyJson, retryCount + 1)
                else
                    return nil, "请求执行失败"
                end
            end
            if not response then
                if retryCount < MAX_RETRIES then
                    addMessage("system", " 未收到响应，正在重试...", true)
                    task.wait(1)
                    return performRequest(bodyJson, retryCount + 1)
                else
                    return nil, "未收到响应"
                end
            end
            return response, nil
        end

        local function sendMessage()
            if not request_func then
                addMessage("system", " 执行器不支持HTTP请求，无法发送", true)
                return
            end
            local query = textBox.Text:gsub("^%s+", ""):gsub("%s+$", "")
            if query == "" then return end
            textBox.Text = ""
            addMessage("user", query)
            
            local scaleDown = TweenService:Create(sendBtn, TweenInfo.new(0.1, Enum.EasingStyle.Back), {Size = UDim2.new(0, 32, 0, 32)})
            local scaleUp = TweenService:Create(sendBtn, TweenInfo.new(0.1, Enum.EasingStyle.Back), {Size = UDim2.new(0, 40, 0, 40)})
            scaleDown:Play()
            scaleDown.Completed:Connect(function() scaleUp:Play() end)
            showParticles()
            
            local indicator, rotate, blink = showTypingIndicator()

            local systemPrompt = ROLES[currentRoleIndex].prompt
            local requestBody = {
                model = MODEL_NAME,
                messages = {
                    { role = "system", content = systemPrompt },
                    { role = "user", content = query }
                },
                temperature = 0.5,
                max_tokens = 500
            }
            local bodyJson
            if HttpService and HttpService.JSONEncode then
                local success, result = pcall(function() return HttpService:JSONEncode(requestBody) end)
                if success then bodyJson = result
                else
                    if indicator then indicator:Destroy() end
                    addMessage("system", " JSON编码失败", true)
                    return
                end
            else
                if indicator then indicator:Destroy() end
                addMessage("system", " HttpService不可用", true)
                return
            end
            local response, err = performRequest(bodyJson, 0)
            if indicator then 
                rotate:Cancel()
                blink:Cancel()
                indicator:Destroy() 
            end
            if not response then
                addMessage("system", " " .. (err or "请求失败"), true)
                return
            end
            if response.StatusCode == 200 then
                if HttpService and HttpService.JSONDecode then
                    local decodeSuccess, decodeResult = pcall(function() return HttpService:JSONDecode(response.Body) end)
                    if decodeSuccess and decodeResult then
                        local data = decodeResult
                        local choice = data.choices and data.choices[1]
                        if choice then
                            local reply = choice.message and choice.message.content
                            if reply and reply ~= "" then
                                addMessage("ai", reply)
                            else
                                local reasoning = choice.message and choice.message.reasoning_content
                                local extracted = reasoning and extractAnswerFromReasoning(reasoning)
                                if extracted and extracted ~= "" then
                                    addMessage("ai", extracted)
                                else
                                    addMessage("system", " AI未返回有效内容，请稍后重试或更换角色", true)
                                end
                            end
                        else
                            addMessage("system", " 响应格式异常", true)
                        end
                    else
                        addMessage("system", "响应解析失败，请重试", true)
                    end
                else
                    addMessage("system", "HttpService不可用，无法解析响应", true)
                end
            else
                local errMsg = string.format("HTTP %d", response.StatusCode)
                addMessage("system", errMsg, true)
            end
        end

        sendBtn.MouseButton1Click:Connect(sendMessage)
        textBox.FocusLost:Connect(function(enterPressed)
            if enterPressed then sendMessage() end
        end)

        local isCollapsed = false
        local fullSize = mainFrame.Size
        local collapsedSize = UDim2.new(0, 450, 0, 40)
        local childrenToHide = {rolePanel, rightPanel}

        local function animatePanel(collapse)
            local targetSize = collapse and collapsedSize or fullSize
            local tweenInfo = TweenInfo.new(0.25, Enum.EasingStyle.Back, Enum.EasingDirection.Out)
            local sizeTween = TweenService:Create(mainFrame, tweenInfo, {Size = targetSize})
            sizeTween:Play()
            for _, child in ipairs(childrenToHide) do
                if child then
                    child.Visible = not collapse
                end
            end
            if collapse then
                titleBar.Size = UDim2.new(1, 0, 1, 0)
            else
                titleBar.Size = UDim2.new(1, 0, 0, 40)
            end
            updateShadow()
        end

        minBtn.MouseButton1Click:Connect(function()
            isCollapsed = not isCollapsed
            animatePanel(isCollapsed)
            minBtn.Text = isCollapsed and "+" or "−"
        end)

        closeBtn.MouseButton1Click:Connect(function() screenGui:Destroy() end)

        addMessage("system", "✨AI已启动✨")
        print("免费汉化🤑🤑")
    end
})

