    local deathPosition = nil
    local deathOrientation = nil
    local function setupDeathTracking()
        local player = game.Players.LocalPlayer
        player.CharacterAdded:Connect(function(character)
            local humanoid = character:WaitForChild("Humanoid")
            humanoid.Died:Connect(function()
                local rootPart = character:FindFirstChild("HumanoidRootPart")
                if rootPart then
                    deathPosition = rootPart.Position
                    deathOrientation = rootPart.CFrame - rootPart.Position
                end
            end)
        end)
        if player.Character then
            local humanoid = player.Character:FindFirstChildOfClass("Humanoid")
            if humanoid then
                humanoid.Died:Connect(function()
                    local rootPart = player.Character:FindFirstChild("HumanoidRootPart")
                    if rootPart then
                        deathPosition = rootPart.Position
                        deathOrientation = rootPart.CFrame - rootPart.Position
                    end
                end)
            end
        end
    end
    setupDeathTracking()

    TabHandles.E:Button({
        Title = "原地重生",
        Callback = function()
            if not deathPosition then return end
            local player = game.Players.LocalPlayer
            local character = player.Character
            if character then
                local humanoid = character:FindFirstChildOfClass("Humanoid")
                if humanoid and humanoid.Health > 0 then return end
            end
            local connection
            connection = player.CharacterAdded:Connect(function(newCharacter)
                local newRootPart = newCharacter:WaitForChild("HumanoidRootPart", 5)
                local newHumanoid = newCharacter:WaitForChild("Humanoid", 5)
                if newRootPart and newHumanoid then
                    wait(0.5)
                    newRootPart.CFrame = CFrame.new(deathPosition) * deathOrientation
                    deathPosition = nil
                    deathOrientation = nil
                end
                if connection then connection:Disconnect() end
            end)
            if not character then
                local currentTeam = player.Team
                player.Team = nil
                wait(0.1)
                player.Team = currentTeam
            else
                player:LoadCharacter()
            end
            delay(10, function()
                if connection then
                    connection:Disconnect()
                    WindUI:Notify({ Title = "超时", Content = "重生过程超时", Duration = 3 })
                end
            end)
        end
    })

    -- ================ 武器标签页 (R) 子弹无限 ================
    TabHandles.R:Toggle({
        Title = "子弹无限",
        Callback = function(v)
            local Players = game:GetService("Players")
            local LocalPlayer = Players.LocalPlayer
            local gk = true 
            local uj = nil
            local deathConnection = nil
            local originalGunData = {}

            local function apn()
                for i, v in next, getgc(false) do
                    if typeof(v) == "function" then
                        local info = getinfo(v)
                        if tostring(info.name) == "fireGun" then
                            local gunTable = getupvalue(v, 1)
                            if not originalGunData[gunTable] then
                                originalGunData[gunTable] = {}
                                for key, value in pairs(gunTable) do
                                    if typeof(value) ~= "function" then
                                        originalGunData[gunTable][key] = value
                                    end
                                end
                                for key, value in pairs(gunTable) do
                                    if typeof(value) == "table" then
                                        originalGunData[gunTable][key] = {}
                                        for subKey, subValue in pairs(value) do
                                            originalGunData[gunTable][key][subKey] = subValue
                                        end
                                    end
                                end
                            end
                            rawset(gunTable, "Ammo", math.huge)
                            rawset(gunTable, "Distance", math.huge)
                            rawset(gunTable, "BSpeed", 99999)
                            rawset(gunTable, "BDrop", 0)
                            rawset(gunTable, "FireRate", 2000)
                            rawset(gunTable, "MaxSpread", 0)
                            rawset(gunTable, "MinSpread", 0)
                            rawset(gunTable.FireModes, "Auto", true)
                            rawset(gunTable.FireModes, "Semi", true)
                            rawset(gunTable.FireModes, "ChangeFiremode", true)
                            rawset(gunTable, "MinRecoilPower", 0)
                            rawset(gunTable, "MaxRecoilPower", 0)
                            rawset(gunTable, "RecoilPowerStepAmount", 0)
                            rawset(gunTable, "RecoilPunch", 0)
                            rawset(gunTable, "DPunchBase", 0)
                            rawset(gunTable, "AimRecover", 1)
                            rawset(gunTable, "HPunchBase", 0)
                            rawset(gunTable, "VPunchBase", 0)
                            rawset(gunTable, "PunchRecover", 1)
                            rawset(gunTable, "SwayBase", 0)
                            rawset(gunTable, "AimRecoilReduction", math.huge)
                            for key, value in next, gunTable do
                                if typeof(value) == "table" then
                                    for subKey, subValue in next, value do
                                        if typeof(subValue) == "number" then
                                            rawset(value, subKey, 0)
                                        end
                                    end
                                end
                            end
                        end
                    end
                end
            end

            local function resetGuns()
                for gunTable, data in pairs(originalGunData) do
                    for key, value in pairs(data) do
                        if typeof(value) == "table" then
                            if gunTable[key] then
                                for subKey, subValue in pairs(value) do
                                    rawset(gunTable[key], subKey, subValue)
                                end
                            end
                        else
                            rawset(gunTable, key, value)
                        end
                    end
                end
                originalGunData = {}
            end

            local function onCharacterDeath()
                resetGuns()
                if gk then
                    LocalPlayer.CharacterAdded:Wait()
                    task.wait(1)
                    apn()
                end
            end

            local function setupDeathListener()
                if deathConnection then deathConnection:Disconnect() end
                deathConnection = LocalPlayer.CharacterAdded:Connect(function(char)
                    local humanoid = char:WaitForChild("Humanoid")
                    humanoid.Died:Connect(onCharacterDeath)
                end)
                if LocalPlayer.Character then
                    local humanoid = LocalPlayer.Character:FindFirstChild("Humanoid")
                    if humanoid then humanoid.Died:Connect(onCharacterDeath) end
                end
            end

            gk = true
            if LocalPlayer.Character then apn() end
            setupDeathListener()
            uj = LocalPlayer.CharacterAdded:Connect(function()
                if gk then
                    task.wait(1)
                    apn()
                    setupDeathListener()
                end
            end)
        end
    })

    -- ================ RPG标签页 (T) ================
    TabHandles.T:Button({
        Title = "获取RPG",
        Callback = function()
            local Players = game:GetService("Players")
            local localPlayer = Players.LocalPlayer
            local TycoonsFolder = workspace.Tycoon.Tycoons
            local savedPosition
            local function findNearestTeleportPosition()
                local character = localPlayer.Character or localPlayer.CharacterAdded:Wait()
                local humanoidRootPart = character:WaitForChild("HumanoidRootPart")
                local playerPosition = humanoidRootPart.Position
                local closestDistance = math.huge
                local closestCFrame = nil
                for _, tycoonModel in ipairs(TycoonsFolder:GetChildren()) do
                    if tycoonModel:IsA("Model") then
                        local purchasedObjects = tycoonModel:FindFirstChild("PurchasedObjects")
                        if purchasedObjects then
                            local rpgGiver = purchasedObjects:FindFirstChild("RPG Giver")
                            if rpgGiver then
                                local prompt = rpgGiver:FindFirstChild("Prompt")
                                if prompt and prompt:IsA("BasePart") then
                                    local distance = (playerPosition - prompt.Position).Magnitude
                                    if distance < closestDistance then
                                        closestDistance = distance
                                        closestCFrame = prompt.CFrame
                                    end
                                end
                            end
                        end
                    end
                end
                return closestCFrame
            end
            local function teleportPlayer()
                local character = localPlayer.Character
                if not character then return end
                local humanoidRootPart = character:FindFirstChild("HumanoidRootPart")
                if humanoidRootPart then savedPosition = humanoidRootPart.CFrame end
                local targetCFrame = findNearestTeleportPosition()
                if targetCFrame then
                    humanoidRootPart.CFrame = targetCFrame
                    spawn(function()
                        while wait(0.5) do
                            if not character.Parent then break end
                            local backpack = localPlayer:FindFirstChild("Backpack")
                            if backpack and backpack:FindFirstChild("RPG") then
                                humanoidRootPart.CFrame = savedPosition
                                break
                            end
                        end
                    end)
                else
                    WindUI:Notify({ Title = "ERROR", Content = "未能找到附近的RPG", Duration = 4 })
                end
            end
            teleportPlayer()
            WindUI:Notify({ Title = "通知", Content = "加载成功", Duration = 1, Icon = "layout-grid" })
        end
    })

    local loopActive = false
    local rpgAttackThread = nil
    TabHandles.T:Button({
        Title = "RPG轰炸",
        Callback = function(t)
            loopActive = t
            if t then
                if rpgAttackThread then coroutine.close(rpgAttackThread) end
                rpgAttackThread = coroutine.create(function()
                    local Players = game:GetService("Players")
                    local LocalPlayer = Players.LocalPlayer
                    local ReplicatedStorage = game:GetService("ReplicatedStorage")
                    local RocketSystem = ReplicatedStorage:WaitForChild("RocketSystem")
                    local FireRocket = RocketSystem.Events.FireRocket
                    local RocketHit = RocketSystem.Events.RocketHit
                    local attackPhase = "attack"
                    local phaseStartTime = os.clock()
                    local C_NPlayers = {}
                    while loopActive do
                        local currentTime = os.clock()
                        local elapsed = currentTime - phaseStartTime
                        if not loopActive then break end
                        if attackPhase == "attack" then
                            if elapsed >= 3 then
                                attackPhase = "pause"
                                phaseStartTime = os.clock()
                            else
                                local character = LocalPlayer.Character
                                if character and character:FindFirstChild("HumanoidRootPart") then
                                    local attackPosition = character.HumanoidRootPart.Position + Vector3.new(0, 1000, 0)
                                    local weapon = character:FindFirstChild("RPG")
                                    if weapon then
                                        for _, player in ipairs(Players:GetPlayers()) do
                                            if player ~= LocalPlayer and player.Character and not table.find(C_NPlayers, player.Name) then
                                                local target = player.Character:FindFirstChild("HumanoidRootPart")
                                                if target then
                                                    FireRocket:InvokeServer(Vector3.new(), weapon, weapon, attackPosition)
                                                    RocketHit:FireServer(attackPosition, Vector3.new(), weapon, weapon, target, nil, "asdfghvcqawRocket4")
                                                    task.wait(0.3)
                                                end
                                            end
                                        end
                                    end
                                end
                            end
                        elseif attackPhase == "pause" then
                            if elapsed >= 2 then
                                attackPhase = "attack"
                                phaseStartTime = os.clock()
                            end
                        end
                        task.wait(0.1)
                    end
                end)
                coroutine.resume(rpgAttackThread)
            else
                if rpgAttackThread then coroutine.close(rpgAttackThread) end
            end
            WindUI:Notify({ Title = "通知", Content = "加载成功", Duration = 1, Icon = "layout-grid" })
        end
    })

    -- ================ 自瞄系统 ================
    local AimLockSystem = {}
    local Players = game:GetService("Players")
    local RunService = game:GetService("RunService")
    local UserInputService = game:GetService("UserInputService")
    local Workspace = game:GetService("Workspace")
    local Camera = Workspace.CurrentCamera
    local LocalPlayer = Players.LocalPlayer

    AimLockSystem.Config = {
        enabled = false,
        smoothAim = false,
        aimType = "最近玩家",
        aimPart = "头部",
        fovEnabled = false,
        showFov = false,
        fovSize = 100,
        fovColor = Color3.fromRGB(255, 255, 255),
        fovLockDistance = 1000,
        nearestPlayerDistance = 1000,
        nearestMouseDistance = 500,
        wallCheckEnabled = true,
        lerpAlpha = 0.4,
        aimlockOffsetX = 0,
        aimlockOffsetY = 0,
        ignoredPlayers = {},
        prioritizedPlayers = {},
        aimlockCertainPlayer = false,
        selectedPlayer = nil,
        rainbowFov = false,
        fovStrokeThickness = 2,
        fovGui = nil,
        fovFrame = nil,
        fovStroke = nil
    }

    AimLockSystem.State = {
        isAimingLocked = false,
        aimlockConnection = nil
    }

    function AimLockSystem.GetLocalHRP()
        if not LocalPlayer.Character then return nil end
        return LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
    end

    function AimLockSystem.IsPlayerIgnored(player)
        return AimLockSystem.Config.ignoredPlayers[player.Name] == true
    end

    function AimLockSystem.GetAimPartPosition(targetPlayer)
        if not targetPlayer or not targetPlayer.Character then return nil end
        local part = nil
        if AimLockSystem.Config.aimPart == "头部" then
            part = targetPlayer.Character:FindFirstChild("Head")
        elseif AimLockSystem.Config.aimPart == "躯干" then
            part = targetPlayer.Character:FindFirstChild("UpperTorso") or targetPlayer.Character:FindFirstChild("Torso")
        elseif AimLockSystem.Config.aimPart == "脚部" then
            local hrp = targetPlayer.Character:FindFirstChild("HumanoidRootPart")
            if hrp then return hrp.Position + Vector3.new(0, -3, 0) end
        end
        return part and part.Position or nil
    end

    function AimLockSystem.GetPriorityScore(player)
        if not player.Character or not player.Character:FindFirstChild("HumanoidRootPart") then return math.huge end
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then return math.huge end
        if player == LocalPlayer then return math.huge end
        if AimLockSystem.IsPlayerIgnored(player) then return math.huge end

        local hrp = player.Character.HumanoidRootPart
        if AimLockSystem.Config.fovEnabled then
            local screenPos, onScreen = Camera:WorldToViewportPoint(hrp.Position)
            if not onScreen then return math.huge end
            local center = Vector2.new(Camera.ViewportSize.X/2, Camera.ViewportSize.Y/2)
            local distFromCenter = (Vector2.new(screenPos.X, screenPos.Y) - center).Magnitude
            if distFromCenter > AimLockSystem.Config.fovSize/2 then return math.huge end
            if (localHRP.Position - hrp.Position).Magnitude > AimLockSystem.Config.fovLockDistance then return math.huge end
        end

        if AimLockSystem.Config.wallCheckEnabled then
            local head = player.Character:FindFirstChild("Head")
            if head then
                local origin = localHRP.Parent:FindFirstChild("Head") and localHRP.Parent.Head.Position or localHRP.Position
                local direction = head.Position - origin
                local rayParams = RaycastParams.new()
                rayParams.FilterDescendantsInstances = {LocalPlayer.Character}
                rayParams.FilterType = Enum.RaycastFilterType.Exclude
                local result = Workspace:Raycast(origin, direction, rayParams)
                if result and not result.Instance:IsDescendantOf(player.Character) then return math.huge end
            end
        end

        if AimLockSystem.Config.aimType == "最近玩家" then
            return (localHRP.Position - hrp.Position).Magnitude
        else
            local mousePos = UserInputService:GetMouseLocation()
            local screenPos = Camera:WorldToViewportPoint(hrp.Position)
            return (Vector2.new(screenPos.X, screenPos.Y) - mousePos).Magnitude
        end
    end

    function AimLockSystem.GetClosestPlayer()
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then return nil end
        local bestPlayer, bestScore = nil, math.huge
        for _, player in ipairs(AimLockSystem.Config.prioritizedPlayers) do
            local score = AimLockSystem.GetPriorityScore(player)
            if score < bestScore then bestScore = score; bestPlayer = player end
        end
        if bestPlayer then return bestPlayer end
        for _, player in ipairs(Players:GetPlayers()) do
            if table.find(AimLockSystem.Config.prioritizedPlayers, player) then continue end
            local score = AimLockSystem.GetPriorityScore(player)
            if score < bestScore then bestScore = score; bestPlayer = player end
        end
        return bestPlayer
    end

    function AimLockSystem.UpdateAimlock()
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then AimLockSystem.State.isAimingLocked = false; return end
        local targetPlayer = nil
        if AimLockSystem.Config.aimlockCertainPlayer then
            targetPlayer = AimLockSystem.Config.selectedPlayer
        else
            targetPlayer = AimLockSystem.GetClosestPlayer()
        end
        if targetPlayer then
            AimLockSystem.State.isAimingLocked = true
            local targetPosition = AimLockSystem.GetAimPartPosition(targetPlayer)
            if targetPosition then
                targetPosition = targetPosition + Vector3.new(AimLockSystem.Config.aimlockOffsetX, AimLockSystem.Config.aimlockOffsetY, 0)
                local lookDirection = (targetPosition - Camera.CFrame.Position).Unit
                if AimLockSystem.Config.smoothAim then
                    local targetCFrame = CFrame.lookAt(Camera.CFrame.Position, Camera.CFrame.Position + lookDirection)
                    Camera.CFrame = Camera.CFrame:Lerp(targetCFrame, AimLockSystem.Config.lerpAlpha)
                else
                    Camera.CFrame = CFrame.lookAt(Camera.CFrame.Position, Camera.CFrame.Position + lookDirection)
                end
            end
        else
            AimLockSystem.State.isAimingLocked = false
        end
    end

    function AimLockSystem.UpdateFOVCircle()
        if not AimLockSystem.Config.showFov then
            if AimLockSystem.Config.fovFrame then AimLockSystem.Config.fovFrame.Visible = false end
            return
        end
        if not AimLockSystem.Config.fovGui then
            AimLockSystem.Config.fovGui = Instance.new("ScreenGui")
            AimLockSystem.Config.fovGui.Name = "FOVCircle"
            AimLockSystem.Config.fovGui.IgnoreGuiInset = true
            AimLockSystem.Config.fovGui.Parent = game:GetService("CoreGui")
            AimLockSystem.Config.fovFrame = Instance.new("Frame")
            AimLockSystem.Config.fovFrame.Name = "Circle"
            AimLockSystem.Config.fovFrame.AnchorPoint = Vector2.new(0.5, 0.5)
            AimLockSystem.Config.fovFrame.Position = UDim2.new(0.5, 0, 0.5, 0)
            AimLockSystem.Config.fovFrame.BackgroundTransparency = 1
            AimLockSystem.Config.fovFrame.BorderSizePixel = 0
            AimLockSystem.Config.fovFrame.Parent = AimLockSystem.Config.fovGui
            local corner = Instance.new("UICorner")
            corner.CornerRadius = UDim.new(1, 0)
            corner.Parent = AimLockSystem.Config.fovFrame
            AimLockSystem.Config.fovStroke = Instance.new("UIStroke")
            AimLockSystem.Config.fovStroke.Thickness = AimLockSystem.Config.fovStrokeThickness
            AimLockSystem.Config.fovStroke.Parent = AimLockSystem.Config.fovFrame
        end
        local color = AimLockSystem.Config.fovColor
        if AimLockSystem.State.isAimingLocked then
            color = Color3.fromRGB(0, 255, 0)
        elseif AimLockSystem.Config.rainbowFov then
            color = Color3.fromHSV(tick() % 1, 1, 1)
        end
        AimLockSystem.Config.fovStroke.Color = color
        AimLockSystem.Config.fovFrame.Size = UDim2.new(0, AimLockSystem.Config.fovSize, 0, AimLockSystem.Config.fovSize)
        AimLockSystem.Config.fovFrame.Visible = true
    end

    function AimLockSystem.ToggleAimlock(enabled)
        AimLockSystem.Config.enabled = enabled
        if enabled then
            if not AimLockSystem.State.aimlockConnection then
                AimLockSystem.State.aimlockConnection = RunService.RenderStepped:Connect(function()
                    AimLockSystem.UpdateAimlock()
                    AimLockSystem.UpdateFOVCircle()
                end)
            end
            WindUI:Notify({ Title = "静默自瞄", Content = "已开启", Icon = "target", Duration = 3 })
        else
            if AimLockSystem.State.aimlockConnection then
                AimLockSystem.State.aimlockConnection:Disconnect()
                AimLockSystem.State.aimlockConnection = nil
            end
            AimLockSystem.State.isAimingLocked = false
            if AimLockSystem.Config.fovFrame then AimLockSystem.Config.fovFrame.Visible = false end
            WindUI:Notify({ Title = "静默自瞄", Content = "已关闭", Icon = "x-circle", Duration = 3 })
        end
    end

