                        local FLOKIV2426 = FLOKIV2396 and FLOKIV2396.Parent and FLOKIV2413()
                        
                        if not FLOKIV2426 then
                            local FLOKIV2427 = FLOKIV2415()
                            if FLOKIV2427 then
                                if FLOKIV2417(FLOKIV2427) then
                                    FLOKIV2398 = true
                                end
                            end
                        else
                            if not FLOKIV2398 then
                                FLOKIV2398 = true
                            end
                        end
                    else
                        FLOKIV2396 = nil
                        FLOKIV2398 = false
                    end
                end
                
                if FLOKIV2398 and FLOKIV2396 then
                    FLOKIV2422()
                end
                
                task.wait(FLOKIV2389)
            end
        end
        
        self.FLOKIV2306.FLOKIV2428 = FLOKIV2156.CharacterRemoving:Connect(FLOKIV2423)
        
        self.FLOKIV2306.FLOKIV2429 = FLOKIV2394.WindowFocusReleased:Connect(function()
            FLOKIV2423()
        end)
        
        self.FLOKIV2306.FLOKIV2430 = FLOKIV2394.WindowFocused:Connect(function()
            if not FLOKIV2397 then
                FLOKIV2397 = true
                task.spawn(FLOKIV2424)
            end
        end)
        
        self.FLOKIV2306.FLOKIV2317 = FLOKIV2156.CharacterAdded:Connect(function(FLOKIV2380)
            FLOKIV2157 = FLOKIV2380
            FLOKIV2212 = FLOKIV2157:WaitForChild("Humanoid")
            if not FLOKIV2397 then
                FLOKIV2397 = true
                task.spawn(FLOKIV2424)
            end
        end)
        
        if FLOKIV2403() then
            FLOKIV2424()
        else
            self.FLOKIV2307 = false
        end
        
        while FLOKIV2397 and self.FLOKIV2304 do
            task.wait(1)
        end
        
        FLOKIV2423()
    end)
end

function FLOKIV2431:FLOKIV2381()
    if not self.FLOKIV2307 then 
        return 
    end
    self.FLOKIV2307 = false
    self.FLOKIV2304 = false
    
    for _, FLOKIV2311 in pairs(self.FLOKIV2306) do
        if FLOKIV2311 then
            FLOKIV2311:Disconnect()
        end
    end
    
    self.FLOKIV2306 = {}
    
    if self.FLOKIV2383 then
        task.cancel(self.FLOKIV2383)
        self.FLOKIV2383 = nil
    end
end

