})

FunctionsTab:Toggle({
    Title = "无限体力",
    Value = false,
    Callback = function(state)
        infStamina = state
        if state then
            task.spawn(function()
                while infStamina do
                    local char = lp.Character
                    local hum = char and char:FindFirstChildOfClass("Humanoid")
                    if hum then
                        hum:SetAttribute("Stamina", 1)
                    end
                    task.wait()
                end
            end)
        end
    end
})

FunctionsTab:Toggle({
    Title = "自动通关",
    Value = false,
    Callback = function(state)
        autoRoad = state
        if state then
            task.spawn(function()
                local currentRoadIndex = 0
                while autoRoad do
                    local char = lp.Character
                    local hrp = char and char:FindFirstChild("HumanoidRootPart")
                    if not hrp then task.wait() continue end

                    local modelsFolder = workspace:FindFirstChild("models")
                    local roadsFolder = modelsFolder and modelsFolder:FindFirstChild("roads")
                    if not roadsFolder then task.wait() continue end

                    local roadParts = {}
                    for _, roadModel in ipairs(roadsFolder:GetChildren()) do
                        if roadModel:IsA("Model") and tonumber(roadModel.Name) then
                            local part = roadModel:FindFirstChildWhichIsA("BasePart")
                            if part then
                                table.insert(roadParts, {
                                    part = part,
                                    index = tonumber(roadModel.Name)
                                })
                            end
                        end
                    end

                    table.sort(roadParts, function(a, b)
                        return a.index < b.index
                    end)

                    for _, data in ipairs(roadParts) do
                        if not autoRoad then break end
                        if data.index > currentRoadIndex then
                            hrp.CFrame = data.part.CFrame * CFrame.new(0, 5, -10)
                            currentRoadIndex = data.index
                            task.wait(0.15)
                        end
                    end
                    task.wait(0.2)
                end
            end)
        end
    end
})

FunctionsTab:Toggle({
    Title = "杀戮光环",
    Value = false,
    Callback = function(state)
        killAura = state
        if state then
            task.spawn(function()
                while killAura do
                    for _, v in ipairs(workspace:GetDescendants()) do
                        if v:IsA("Model") and v:FindFirstChild("Humanoid") and not Players:GetPlayerFromCharacter(v) then
                            local gun = workspace:FindFirstChild("Pistol")
                            if gun then
                                ReplicatedStorage.Network:FindFirstChild("GunFramework_RequestDamage"):FireServer(gun, v)
                            end
                        end
                    end
                    task.wait()
                end
            end)
        end
    end
})

MainTab:Section({ Title = "愤怒机器人", Icon = "zap" })
local RagebotEnabled = false
local RagebotModule = nil
local AttackTeam = "全部"
local function LoadRagebot()
    local Players = game:GetService("Players")
    local ReplicatedStorage = game:GetService("ReplicatedStorage")
    local Workspace = game:GetService("Workspace")
    local RunService = game:GetService("RunService")
    local LocalPlayer = Players.LocalPlayer
    local Camera = Workspace.CurrentCamera
    local Config = {
        FireInterval = 0.1,
        MaxRange = 2000,
        HitMaterial = Enum.Material.Concrete,
        HitType = "player",
        SendHitInfo = false,
        Enabled = false,
        MaxAttacks = 4,
        BurstCount = 4,
        UseNetworkModule = true,
        DebugRay = false,
        RemoteOverrides = {
            Invoke = nil,
            Shoot = nil,
            Hit = nil
        }
    }
    local vector = rawget(_G, "vector")
    if type(vector) ~= "table" then
        vector = {}
        _G.vector = vector
    end
    if type(vector.create) ~= "function" then
        function vector.create(x, y, z)
            return Vector3.new(x, y, z)
        end
    end
    local Network = ReplicatedStorage:WaitForChild("Shared"):WaitForChild("Core"):WaitForChild("Network")
    local RemoteFunctions = {}
    local RemoteEvents = {}
    local Devv = require(ReplicatedStorage:WaitForChild("Devv"))
    local NetworkModule = nil
    local ClientToolsModule = nil
    local MathUtilModule = nil
    local NUIDModule = nil
    local ClientGunsModule = nil
    local ClientProjectilesModule = nil
    local ProjectileUtilModule = nil
    local ObjectsModule = nil
    local function InitGameModules()
        local ok = pcall(function()
            Devv = require(ReplicatedStorage:WaitForChild("Devv", 5))
        end)
        if not ok or not Devv then
            return false
        end
        pcall(function() ClientToolsModule = Devv.load("ClientTools") end)
        pcall(function() ClientPlayers = Devv.load("ClientPlayers") end)
        pcall(function()
            NetworkModule = Devv.load("Network")
            ClientToolsModule = Devv.load("ClientTools")
            MathUtilModule = Devv.load("MathUtil")
            NUIDModule = Devv.load("NUID")
            ClientGunsModule = Devv.load("ClientGuns")
            ClientProjectilesModule = Devv.load("ClientProjectiles")
            ProjectileUtilModule = Devv.load("ProjectileUtil")
            ObjectsModule = Devv.load("Objects")
        end)
        return true
    end
    local OverrideHitPos = nil
    local OverrideOrigin = nil
    local OriginalMakeGunProjectiles = nil
    local function HookMakeGunProjectiles()
        if not ClientGunsModule or not ClientGunsModule.MakeGunProjectiles then
            return false
        end
        if OriginalMakeGunProjectiles then
            return true
        end
        OriginalMakeGunProjectiles = ClientGunsModule.MakeGunProjectiles
        ClientGunsModule.MakeGunProjectiles = function(userId, toolId, muzzleCFrame, projectiles)
            if OverrideHitPos and OverrideOrigin and userId == LocalPlayer.UserId then
                local newProjectiles = {}
                for _, proj in ipairs(projectiles) do
                    local projId = proj[1]
                    local newCFrame = CFrame.new(OverrideOrigin, OverrideHitPos)
                    table.insert(newProjectiles, {projId, newCFrame})
                end
                return OriginalMakeGunProjectiles(userId, toolId, muzzleCFrame, newProjectiles)
            end
            return OriginalMakeGunProjectiles(userId, toolId, muzzleCFrame, projectiles)
        end
        return true
    end
    local function ScanRemotes()
        local fnCount, evCount = 0, 0
        for _, child in ipairs(Network:GetChildren()) do
            if child:IsA("RemoteFunction") then
                RemoteFunctions[child.Name] = child
                fnCount = fnCount + 1
            elseif child:IsA("RemoteEvent") or child:IsA("UnreliableRemoteEvent") then
                RemoteEvents[child.Name] = child
                evCount = evCount + 1
            end
        end
    end
    local function GetEquippedToolId()
        if ClientToolsModule and ClientToolsModule.GetLocalEquippedTool then
            local ok, tool = pcall(function()
                return ClientToolsModule.GetLocalEquippedTool()
            end)
            if ok and tool and tool.toolId then
                return tool.toolId
            end
        end
        if ClientPlayers and ClientPlayers.Get then
            local ok, playerObj = pcall(function()
                return ClientPlayers.Get()
            end)
            if ok and playerObj then
                if playerObj.GetEquippedReplica then
                    local ok2, replica = pcall(function()
                        return playerObj:GetEquippedReplica()
                    end)
                    if ok2 and replica and replica.toolId then
                        return replica.toolId
                    end
                end
                if playerObj.GetEquippedTool then
                    local ok2, tool = pcall(function()
                        return playerObj:GetEquippedTool()
                    end)
                    if ok2 and tool and tool.toolId then
                        return tool.toolId
                    end
                end
            end
        end
        return nil
    end
    local function GetEquippedTool()
        if ClientToolsModule and ClientToolsModule.GetLocalEquippedTool then
            local ok, tool = pcall(function()
                return ClientToolsModule.GetLocalEquippedTool()
            end)
            if ok and tool then
                return tool
            end
        end
        return nil
    end
    local function GetCurrentAmmo()
        local tool = GetEquippedTool()
        if tool then
            local shooter = nil
            if tool.GetComponent then
                pcall(function()
                    shooter = tool:GetComponent("Shooter")
                end)
            end
            if shooter and shooter.ammo ~= nil then
                return shooter.ammo, shooter.totalAmmo or 0
            end
            if tool.toolState then
                return tool.toolState.ammo or 0, tool.toolState.totalAmmo or 0
            end
        end
        return nil, nil
    end
    local function IsReloading()
        if ClientPlayers and ClientPlayers.Get then
            local ok, playerObj = pcall(function()
                return ClientPlayers.Get()
            end)
            if ok and playerObj and playerObj.GetPlayerProperty then
                local ok2, reloading = pcall(function()
                    return playerObj:GetPlayerProperty("reloading")
                end)
                if ok2 then
                    return reloading == true
                end
            end
        end
        return false
    end
    local ReloadRemotes = {}
    local ShotCounter = 0
    local ShotsPerMag = 5
    local function InitReloadRemotes()
        pcall(function()
            local Network = ReplicatedStorage:WaitForChild("Shared", 2)
            Network = Network and Network:WaitForChild("Core", 2)
            Network = Network and Network:WaitForChild("Network", 2)
            if Network then
                ReloadRemotes.Remote1 = Network:FindFirstChild("NjcSa3wV")
                ReloadRemotes.Remote2 = Network:FindFirstChild("f50qd9MN")
                ReloadRemotes.Remote3 = Network:FindFirstChild("4hKttO0V")
            end
        end)
    end
    local function DoReload()
        local toolId = GetEquippedToolId() or CachedToolId
        if not toolId then return false end
        if not ReloadRemotes.Remote1 then
            InitReloadRemotes()
        end
        if ReloadRemotes.Remote1 then
            pcall(function() ReloadRemotes.Remote1:FireServer(toolId) end)
            return true
        end
        if NetworkModule and NetworkModule.FireServer then
            pcall(function()
                NetworkModule.FireServer("reload", toolId)
            end)
            return true
        end
        return false
    end
    local function SyncAmmo()
        local tool = GetEquippedTool()
        if tool then
            local shooter = nil
            if tool.GetComponent then
                pcall(function()
                    shooter = tool:GetComponent("Shooter")
                end)
            end
            if shooter and shooter.UpdateAmmo then
                local newAmmo = math.max(0, (shooter.ammo or 1) - 1)
                pcall(function()
                    shooter:UpdateAmmo(newAmmo, shooter.totalAmmo)
                end)
            end
        end
    end
    local function CheckAndReload()
        if ShotCounter >= ShotsPerMag then
            return DoReload()
        end
        return false
    end
    local function CompressCFrame(cf)
        local b = buffer.create(24)
        local axis, angle = cf:ToAxisAngle()
        buffer.writef32(b, 0, cf.X)
        buffer.writef32(b, 4, cf.Y)
        buffer.writef32(b, 8, cf.Z)
        buffer.writef32(b, 12, axis.X * angle)
        buffer.writef32(b, 16, axis.Y * angle)
        buffer.writef32(b, 20, axis.Z * angle)
        return b
    end
    local CollectionService = game:GetService("CollectionService")
    local function GetTargetHitbox(character)
        for _, part in ipairs(character:GetDescendants()) do
            if part:IsA("BasePart") and CollectionService:HasTag(part, "rootHitbox") then
                return part
            end
        end
        return character:FindFirstChild("HumanoidRootPart") or character:FindFirstChild("Head")
    end
    local function GetClosestEnemy()
        local closest, minDist, closestPlayer = nil, math.huge, nil
        for _, p in ipairs(Players:GetPlayers()) do
            if p ~= LocalPlayer and p.Character then
                local hitbox = GetTargetHitbox(p.Character)
                local humanoid = p.Character:FindFirstChildOfClass("Humanoid")
                if hitbox and humanoid and humanoid.Health > 0 then
                    local dist = (hitbox.Position - Camera.CFrame.Position).Magnitude
                    if dist < minDist and dist < Config.MaxRange then
                        closest, minDist, closestPlayer = hitbox, dist, p
                    end
                end
            end
        end
        return closest, closestPlayer
    end
    local LastFireTime = 0
    local AttackCount = 0
    local CachedToolId = nil
    local AllFunctions = {}
    local AllEvents = {}
    local InvokeFn = nil
    local ShootEv = nil
    local HitEv = nil
    local function ResolveRemoteByName(name, dictionary)
        if not name then return nil end
        if dictionary and dictionary[name] then
            return dictionary[name]
        end
        return Network:FindFirstChild(name)
    end
    local function FindRemotes()
        table.clear(AllFunctions)
        table.clear(AllEvents)
        for name, remote in pairs(RemoteFunctions) do
            table.insert(AllFunctions, {name = name, remote = remote})
        end
        for name, remote in pairs(RemoteEvents) do
            table.insert(AllEvents, {name = name, remote = remote})
        end
        local overrides = Config.RemoteOverrides or {}
        InvokeFn = ResolveRemoteByName(overrides.Invoke, RemoteFunctions) or (AllFunctions[1] and AllFunctions[1].remote or nil)
        ShootEv = ResolveRemoteByName(overrides.Shoot, RemoteEvents) or (AllEvents[1] and AllEvents[1].remote or nil)
        HitEv = ResolveRemoteByName(overrides.Hit, RemoteEvents) or (AllEvents[2] and AllEvents[2].remote or nil)
    end
    local function ForEachInvokeRemote(callback)
        if InvokeFn then
            callback(InvokeFn)
            return
        end
        for _, entry in ipairs(AllFunctions) do
            callback(entry.remote)
        end
    end
    local function ForEachShootRemote(callback)
        if ShootEv then
            callback(ShootEv)
            return
        end
        for _, entry in ipairs(AllEvents) do
            callback(entry.remote)
        end
    end
    local function ForEachHitRemote(callback)
        if HitEv then
            callback(HitEv)
            return
        end
        for _, entry in ipairs(AllEvents) do
            callback(entry.remote)
        end
    end
    local ScanConfig = {
        fireScanOffset = 5.1,
        hitScanOffset = 6,
        wallbangThickness = 1.5,
        shootRadius = 5,
        targetRadius = 5,
        shootPrecision = 26,
        targetPrecision = 26
    }
    local ScanPositionsVectors = {
        Vector3.new(1, 0, 0), Vector3.new(0, 0, 1), Vector3.new(0, 1, 0),
        -Vector3.new(1, 0, 0), -Vector3.new(0, 0, 1), -Vector3.new(0, 1, 0),
        Vector3.new(1, 1, 0)/math.sqrt(2), Vector3.new(1, 0, 1)/math.sqrt(2), Vector3.new(0, 1, 1)/math.sqrt(2),
        Vector3.new(-1, 1, 0)/math.sqrt(2), Vector3.new(-1, 0, 1)/math.sqrt(2),
        -Vector3.new(1, 0, 1)/math.sqrt(2), -Vector3.new(-1, 0, 1)/math.sqrt(2), -Vector3.new(0, -1, 1)/math.sqrt(2),
        Vector3.new(1, 1, 1)/math.sqrt(3), Vector3.new(-1, 1, 1)/math.sqrt(3), Vector3.new(1, 1, -1)/math.sqrt(3),
        -Vector3.new(1, 1, 1)/math.sqrt(3), -Vector3.new(1, -1, 1)/math.sqrt(3),
        Vector3.new(1,2,0)/math.sqrt(5), Vector3.new(-1,2,0)/math.sqrt(5), Vector3.new(1,0,2)/math.sqrt(5), Vector3.new(-1,0,2)/math.sqrt(5),
        -Vector3.new(-1,0,2)/math.sqrt(5), -Vector3.new(1,0,2)/math.sqrt(5)
    }
    local function GetOffsets(firePos, targetPos, offset)
        if not offset or offset == 0 then return {firePos} end
        local offsets = {firePos}
        local cframeOffset = CFrame.new(firePos, targetPos) * CFrame.Angles(0, 0, math.rad(math.random(1, 90)))
        for _, pos in ipairs(ScanPositionsVectors) do
            table.insert(offsets, cframeOffset:PointToWorldSpace(pos * offset))
        end
        return offsets
    end
    local function CanShootFromPosition(shootPos, targetPos, targetCharacter, allowWallbang)
        local direction = (targetPos - shootPos).Unit
        local distance = (targetPos - shootPos).Magnitude
        if distance < 0.1 then return false, false end
        local raycastParams = RaycastParams.new()
        local filterList = {LocalPlayer.Character}
        if targetCharacter then
            table.insert(filterList, targetCharacter)
        end
        raycastParams.FilterDescendantsInstances = filterList
        raycastParams.FilterType = Enum.RaycastFilterType.Exclude
        raycastParams.IgnoreWater = true
        local firstRaycast = Workspace:Raycast(shootPos, direction * distance, raycastParams)
        if not firstRaycast then
            return true, false
        end
        if not allowWallbang then
            return false, false
        end
        local entryPoint = firstRaycast.Position
        local exitRayDirection = (shootPos - targetPos).Unit
        local exitRaycast = Workspace:Raycast(targetPos, exitRayDirection * distance, raycastParams)
        if not exitRaycast then
            return false, false
        end
        local exitPoint = exitRaycast.Position
        local wallThickness = (entryPoint - exitPoint).Magnitude
        if wallThickness <= ScanConfig.wallbangThickness then
            local finalDirection = (targetPos - exitPoint).Unit
            local finalDistance = (targetPos - exitPoint).Magnitude
            if finalDistance < 0.1 then return true, true end
            local finalRaycast = Workspace:Raycast(exitPoint, finalDirection * finalDistance, raycastParams)
            if not finalRaycast then
                return true, true
            end
        end
        return false, false
    end
    local function CreateDebugRay(startPos, endPos, color, duration)
        if not Config.DebugRay then return end
        local distance = (endPos - startPos).Magnitude
        local part = Instance.new("Part")
        part.Anchored = true
        part.CanCollide = false
        part.CanTouch = false
        part.CanQuery = false
        part.Size = Vector3.new(0.1, 0.1, distance)
        part.CFrame = CFrame.new(startPos, endPos) * CFrame.new(0, 0, -distance / 2)
        part.Material = Enum.Material.Neon
        part.Color = color or Color3.new(1, 0, 0)
        part.Transparency = 0.5
        part.Parent = Workspace
        task.delay(duration or 2, function()
            if part and part.Parent then
                part:Destroy()
            end
        end)
        return part
    end
    local function FindScanSolution(origin, targetPos, targetCharacter)
        local fireOffsets = GetOffsets(origin, targetPos, ScanConfig.fireScanOffset)
        local hitOffsets = GetOffsets(targetPos, origin, ScanConfig.hitScanOffset)
        local directSolutions = {}
        local wallbangSolutions = {}
        for _, firePos in ipairs(fireOffsets) do
            for _, hitPos in ipairs(hitOffsets) do
                local canShoot, isWallbang = CanShootFromPosition(firePos, hitPos, targetCharacter, true)
                if canShoot then
                    local score = (firePos - origin).Magnitude + (hitPos - targetPos).Magnitude
                    local solution = {origin = firePos, target = hitPos, score = score}
                    if not isWallbang then
                        table.insert(directSolutions, solution)
                    else
                        table.insert(wallbangSolutions, solution)
                    end
                end
            end
        end
        table.sort(directSolutions, function(a, b) return a.score < b.score end)
        table.sort(wallbangSolutions, function(a, b) return a.score < b.score end)
        if #directSolutions > 0 then
            local best = directSolutions[1]
            return best.origin, best.target, false
        end
        if #wallbangSolutions > 0 then
            local best = wallbangSolutions[1]
            return best.origin, best.target, true
        end
        return nil, nil, false
    end
    local lastShootPos = nil
    local lastShootHitPos = nil
    local lastShootPosUpdate = 0
    local function FindBestShootSolution(basePos, targetPos, targetCharacter)
        local canShoot, _ = CanShootFromPosition(basePos, targetPos, targetCharacter, false)
        if canShoot then
            return basePos, targetPos
        end
        local currentTime = tick()
        if lastShootPos and lastShootHitPos and (currentTime - lastShootPosUpdate) < 0.1 then
            local canUse, _ = CanShootFromPosition(lastShootPos, lastShootHitPos, targetCharacter, true)
            if canUse then
                return lastShootPos, lastShootHitPos
            end
        end
        local scanOrigin, scanTarget, isWallbang = FindScanSolution(basePos, targetPos, targetCharacter)
        if scanOrigin and scanTarget then
            lastShootPos = scanOrigin
            lastShootHitPos = scanTarget
            lastShootPosUpdate = currentTime
            return scanOrigin, scanTarget
        end
        for i = 1, ScanConfig.shootPrecision do
            local shootAngle = Vector3.new(math.random() * 2 - 1, math.random() * 2 - 1, math.random() * 2 - 1).Unit
            local testShootPos = basePos + shootAngle * math.random() * ScanConfig.shootRadius
            for j = 1, ScanConfig.targetPrecision do
                local targetAngle = Vector3.new(math.random() * 2 - 1, math.random() * 2 - 1, math.random() * 2 - 1).Unit
                local testTargetPos = targetPos + targetAngle * math.random() * ScanConfig.targetRadius
                local canFire, _ = CanShootFromPosition(testShootPos, testTargetPos, targetCharacter, true)
                if canFire then
                    lastShootPos = testShootPos
                    lastShootHitPos = testTargetPos
                    lastShootPosUpdate = currentTime
                    return testShootPos, testTargetPos
                end
            end
        end
        return basePos, targetPos
    end
    local LastReloadTime = 0
    local ReloadCooldown = 2.5
    local function DoAttack(targetHead, targetPlayer)
        local now = tick()
        if now - LastFireTime < Config.FireInterval then return end
        if not LocalPlayer.Character then return end
        local tool = GetEquippedTool()
        local currentAmmo = nil
        if tool then
            local shooter = nil
            if tool.GetComponent then
                pcall(function()
                    shooter = tool:GetComponent("Shooter")
                end)
            end
            if shooter then
                currentAmmo = shooter.ammo
            elseif tool.toolState then
                currentAmmo = tool.toolState.ammo
            end
        end
        if currentAmmo ~= nil and currentAmmo <= 0 then
            if now - LastReloadTime > ReloadCooldown then
                LastReloadTime = now
                DoReload()
            end
            return
        end
        local hrp = LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        if not hrp then return end
        local toolId = GetEquippedToolId()
        if not toolId then
            toolId = CachedToolId
        end
        if not toolId then return end
        CachedToolId = toolId
        local compress = (MathUtilModule and MathUtilModule.CompressCFrame) or CompressCFrame
        local camPos = Camera.CFrame.Position
        local rawTargetPos = targetHead.Position
        local targetId = tostring(targetPlayer.UserId)
        local targetCharacter = targetPlayer.Character
        local shootPos, hitPos = FindBestShootSolution(camPos, rawTargetPos, targetCharacter)
        if not hitPos then hitPos = rawTargetPos end
        if not shootPos then shootPos = camPos end
        OverrideOrigin = shootPos
        OverrideHitPos = hitPos
        local muzzleCFrame = nil
        local char = LocalPlayer.Character
        if char then
            for _, tool in ipairs(char:GetChildren()) do
                if tool:IsA("Tool") or tool:IsA("Model") then
                    local muzzle = tool:FindFirstChild("Muzzle", true) or tool:FindFirstChild("muzzle", true)
                    if muzzle and muzzle:IsA("BasePart") or (muzzle and muzzle:IsA("Attachment")) then
                        if muzzle:IsA("Attachment") then
                            muzzleCFrame = muzzle.WorldCFrame
                        else
                            muzzleCFrame = muzzle.CFrame
                        end
                        break
                    end
                end
            end
        end
        if not muzzleCFrame then
            local muzzlePos = hrp.Position + Vector3.new(0, 1.5, -1)
            muzzleCFrame = CFrame.new(muzzlePos, hitPos)
        end
        local muzzleBuffer = compress(muzzleCFrame)
        CreateDebugRay(camPos, hitPos, Color3.new(1, 0, 0), 3)
        CreateDebugRay(muzzleCFrame.Position, muzzleCFrame.Position + muzzleCFrame.LookVector * 10, Color3.new(0, 1, 0), 3)
        local direction = (hitPos - camPos).Unit
        local normal = vector.create(-direction.X, -direction.Y, -direction.Z)
        local dirVec = vector.create(direction.X, direction.Y, direction.Z)
        local hitPosition = vector.create(hitPos.X, hitPos.Y, hitPos.Z)
        local collisionPoint = vector.create(
            hitPos.X - direction.X * 0.5,
            hitPos.Y - direction.Y * 0.5,
            hitPos.Z - direction.Z * 0.5
        )
        LastFireTime = now
        AttackCount = AttackCount + 1
        SyncAmmo()
        local projectileId = NUIDModule and NUIDModule() or tostring(math.random(10000000, 99999999))
        local projectileCFrame = CFrame.new(OverrideOrigin or camPos, hitPos)
        local projectileBuffer = compress(projectileCFrame)
        local projectileEntry = {{projectileId, projectileBuffer}}
        local uncompressedEntry = {{projectileId, projectileCFrame}}
        local projectileCreated = false
        if ClientGunsModule and ClientGunsModule.MakeGunProjectiles then
            local ok, err = pcall(function()
                ClientGunsModule.MakeGunProjectiles(LocalPlayer.UserId, toolId, muzzleCFrame, uncompressedEntry)
            end)
            if ok then
                projectileCreated = true
            end
        end
        if not projectileCreated and ClientProjectilesModule and ProjectileUtilModule then
            if ProjectileUtilModule.GetProjectileTrajectory then
                local toolName = nil
                local gunData = nil
                if ClientPlayers and ClientPlayers.Get then
                    pcall(function()
                        local player = ClientPlayers.Get()
                        if player and player.GetEquippedReplica then
                            local replica = player:GetEquippedReplica()
                            if replica and replica.toolState then
                                toolName = replica.toolState.name
                                if ObjectsModule and ObjectsModule.GetData then
                                    gunData = ObjectsModule.GetData(toolName)
                                end
                            end
                        end
                    end)
                end
                if gunData and gunData.projectile then
                    local muzzleVelocity = gunData.projectile.muzzleVelocity or 500
                    local projectileType = gunData.projectileType or "Bullet"
                    pcall(function()
                        local trajectoryData = ProjectileUtilModule.GetProjectileTrajectory(
                            projectileCFrame, muzzleCFrame, muzzleVelocity, gunData
                        )
                        if ClientProjectilesModule.ProjectileObjects and ClientProjectilesModule.ProjectileObjects[projectileType] then
                            local projObj = ClientProjectilesModule.ProjectileObjects[projectileType].new({
                                projectileId = projectileId,
                                ownerId = LocalPlayer.UserId,
                                toolId = toolId,
                                toolName = toolName,
                                trajectoryData = trajectoryData,
                                explosionData = gunData.explosion and table.clone(gunData.explosion) or nil,
                                extraData = {}
                            })
                            ClientProjectilesModule.AddProjectile(projectileId, projObj)
                            projectileCreated = true
                        end
                    end)
                end
            end
        end
        local invokeResult = nil
        if Config.UseNetworkModule and NetworkModule and NetworkModule.InvokeServer then
            local ok, result = pcall(function()
                return NetworkModule.InvokeServer("shoot", toolId, muzzleBuffer, projectileEntry)
            end)
            if ok then
                invokeResult = result
            end
        else
            ForEachInvokeRemote(function(remote)
                local ok, result = pcall(function()
                    return remote:InvokeServer(toolId, muzzleBuffer, projectileEntry)
                end)
                if ok then
                    invokeResult = result
                end
            end)
        end
        if ClientProjectilesModule and ClientProjectilesModule.SetProjectileValid then
            pcall(function()
                ClientProjectilesModule.SetProjectileValid(projectileId, invokeResult)
            end)
        end
        if NetworkModule and NetworkModule.FireServer then
            pcall(function()
                NetworkModule.FireServer("Shoot")
            end)
        else
            ForEachShootRemote(function(remote)
                pcall(function()
                    remote:FireServer("Shoot")
                end)
            end)
        end
        local hitInfo = {
            normal = normal,
            direction = dirVec,
            source = "Bullet",
            massLimit = 5,
            position = hitPosition,
            hitPlayers = {targetPlayer},
            ownerId = LocalPlayer.UserId,
            material = Config.HitMaterial,
            processedPlayerId = LocalPlayer.UserId,
            hit = targetHead,
            instance = targetHead,
            speed = 3500,
            collisionPoint = collisionPoint,
            hitName = targetHead.Name,
            hitType = Config.HitType,
            playerId = targetPlayer.UserId,
            entityId = targetPlayer.UserId
        }
        if Config.SendHitInfo then
            for _, entry in ipairs(projectileEntry) do
                local projId = entry[1]
                local hitEventNames = {"projectileHit", "bulletHit", "hit", "onHit", "projectileFinished"}
                for _, eventName in ipairs(hitEventNames) do
                    pcall(function()
                        if NetworkModule and NetworkModule.FireServer then
                            NetworkModule.FireServer(eventName, projId, hitInfo)
                            NetworkModule.FireServer(eventName, targetId, toolId, hitInfo)
                            NetworkModule.FireServer(eventName, projId, CFrame.new(hitPos), targetHead)
                        end
                    end)
                end
                ForEachHitRemote(function(remote)
                    pcall(function()
                        remote:FireServer(projId, hitInfo)
                        remote:FireServer(projId, CFrame.new(hitPos), targetHead)
                        remote:FireServer(targetId, toolId, {hitInfo})
                    end)
                end)
            end
        end
        task.delay(0.1, function()
            OverrideHitPos = nil
        end)
    end
    local function MainLoop()
        if not Config.Enabled then return end
        if Config.MaxAttacks > 0 and AttackCount >= Config.MaxAttacks then
            Config.Enabled = false
            return
        end
        local targetHead, targetPlayer = GetClosestEnemy()
        if targetHead and targetPlayer then
            DoAttack(targetHead, targetPlayer)
        end
    end
    if not InitGameModules() then
        return
    end
    task.wait(0.5)
    ScanRemotes()
    FindRemotes()
    HookMakeGunProjectiles()
    InitReloadRemotes()
    local function TryGetToolId()
        local id = GetEquippedToolId()
        if id then
            CachedToolId = id
            return true
        end
        return false
    end
    TryGetToolId()
    _G.SetToolId = function(id)
        CachedToolId = id
    end
    _G.GetToolId = function()
        TryGetToolId()
        return CachedToolId
    end
    _G.StopTool = function()
        Config.Enabled = false
    end
    _G.StartTool = function(maxAttacks)
        AttackCount = 0
        Config.MaxAttacks = maxAttacks or 5
        Config.Enabled = true
    end
    _G.SetInterval = function(interval)
        Config.FireInterval = interval or 0.5
    end
    _G.UseDirectRemote = function(useDirect)
        Config.UseNetworkModule = not useDirect
    end
    _G.Reload = DoReload
    _G.GetAmmo = function()
        return GetCurrentAmmo()
    end
    _G.SetMagSize = function(size)
        ShotsPerMag = size or 5
    end
    _G.ResetShotCounter = function()
        ShotCounter = 0
    end
    RunService.Heartbeat:Connect(function()
        if not CachedToolId then
            TryGetToolId()
        end
        MainLoop()
    end)
    local function BurstFire(count)
        count = count or Config.BurstCount
        local targetHead, targetPlayer = GetClosestEnemy()
        if not targetHead or not targetPlayer then
            return
        end
        for i = 1, count do
            DoAttack(targetHead, targetPlayer)
            if i < count then
                task.wait(Config.FireInterval)
            end
        end
    end
    _G.BurstFire = BurstFire
    return {
        SetToolId = _G.SetToolId,
        GetToolId = _G.GetToolId,
        StopTool = _G.StopTool,
        StartTool = _G.StartTool,
        CompressCFrame = CompressCFrame,
        DoAttack = DoAttack,
        BurstFire = BurstFire
    }
end
