    local function RagebotLoop()
        if not RagebotEnabled or not RagebotModule then return end
        local Players = game:GetService("Players")
        local LocalPlayer = Players.LocalPlayer
        local Camera = workspace.CurrentCamera
        local closestPlayer = nil
        local closestDistance = math.huge
        local closestHead = nil
        for _, player in ipairs(Players:GetPlayers()) do
            if player == LocalPlayer then continue end
            if not player.Character then continue end
            local humanoid = player.Character:FindFirstChildOfClass("Humanoid")
            if not humanoid or humanoid.Health <= 0 then continue end
            if AttackTeam ~= "全部" then
                local playerTeam = getPlayerTeam(player)
                if playerTeam ~= AttackTeam then
                    continue
                end
            end
            local head = player.Character:FindFirstChild("Head")
            if not head then continue end
            local distance = (head.Position - Camera.CFrame.Position).Magnitude
            if distance < closestDistance then
                closestDistance = distance
                closestPlayer = player
                closestHead = head
            end
        end
        if closestPlayer and closestHead then
            if RagebotModule.DoAttack then
                pcall(function()
                    RagebotModule.DoAttack(closestHead, closestPlayer)
                end)
            end
        end
    end
    local RagebotConnection = game:GetService("RunService").Heartbeat:Connect(RagebotLoop)

    -- 静默自瞄
