local noclipConnection = nil
MovementTab:Toggle({
    Title = "穿墙模式",
    Default = false,
    Tooltip = "让你可以穿过墙壁",
    Callback = function(Value)
        local Players = game:GetService("Players")
        local RunService = game:GetService("RunService")
        local lp = Players.LocalPlayer
        local function enableNoclip()
            if noclipConnection then return end
            noclipConnection = RunService.Stepped:Connect(function()
                if lp.Character then
                    for _, part in pairs(lp.Character:GetDescendants()) do
                        if part:IsA("BasePart") then
                            part.CanCollide = false
                            part.CollisionGroup = "Default"
                        end
                    end
                end
            end)
        end
        local function disableNoclip()
            if noclipConnection then noclipConnection:Disconnect(); noclipConnection = nil end
            local char = lp.Character
            if not char then return end
            local collision = char:FindFirstChild("Collision")
            local crouch = collision and collision:FindFirstChild("CollisionCrouch")
            if collision and crouch then
                local crouching = collision.CollisionGroup == "PlayerCrouching"
                collision.CanCollide = not crouching
                crouch.CanCollide = crouching
            end
        end
        if Value then enableNoclip(); WindUI:Notify({ Title = "穿墙", Content = "穿墙模式已启用", Duration = 3 })
        else disableNoclip(); WindUI:Notify({ Title = "穿墙", Content = "穿墙模式已禁用", Duration = 3 }) end
    end
})

MovementTab:Keybind({
    Title = "穿墙电脑切换键",
    Default = "N",
    Mode = "Toggle",
    Callback = function(Value) end
})

