-- 裁判球功能加载函数 (服务器ID: 6161644667)
local function loadRefereeFeatures()
    if refereeFeaturesLoaded then
        WindUI:Notify({
            Title = "提示",
            Content = "裁判球功能已加载，请勿重复点击",
            Duration = 3,
            Icon = "info"
        })
        return
    end
    refereeFeaturesLoaded = true

    local refereeTab = Window:Tab({Title = "物品", Icon = "sports"})
    refereeTab:Button({
        Title = "直接获得裁判球",
        Icon = "download",
        Callback = function()
            local RemoteEvent = game:GetService("ReplicatedStorage").Project.RemoteEvent.ControlMessageEvent
            if not RemoteEvent then
                WindUI:Notify({
                    Title = "获取失败",
                    Content = "未找到目标RemoteEvent",
                    Duration = 3,
                    Icon = "x-circle"
                })
                return
            end

            WindUI:Notify({
                Title = "开始获取",
                Content = "正在获取500000个裁判球",
                Duration = 2,
                Icon = "play"
            })

            spawn(function()
                for i = 1, 500000 do
                    local args = {[1] = 2, [2] = {[1] = 1, [2] = 1, [3] = 19}}
                    RemoteEvent:FireServer(unpack(args))
                    
                    if i % 100 == 0 then
                        WindUI:Notify({
                            Title = "获取进度",
                            Content = "已获取 " .. i .. "/500000 个裁判球",
                            Duration = 1,
                            Icon = "check-circle"
                        })
                    end
                    
                    task.wait(0.1)
                end

                WindUI:Notify({
                    Title = "获取完成",
                    Content = "已成功获取500000个裁判球",
                    Duration = 4,
                    Icon = "success"
                })
            end)
        end
    })
end

