local carDestroyLoaded = false
local function loadCarDestroyFeatures()
    if carDestroyLoaded then
        WindUI:Notify({ Title = "提示", Content = "汽车破坏功能已加载", Duration = 3, Icon = "info" })
        return
    end
    carDestroyLoaded = true

    -- 获取服务
    local players = game:GetService("Players")
    local lp = players.LocalPlayer
    local carCollection = workspace.CarCollection
    local guiScript = getsenv(lp.PlayerGui:WaitForChild("GUIs"))
    local openFunc = guiScript["OpenDealership"]
    local spawnFunc = guiScript["SpawnButton"]
    local doBreak = false
    local AutofarmEnabled = false
    local heleicopterspawn = false

    -- 辅助函数
    local function getCurrentCar()
        local car = carCollection:FindFirstChild(lp.Name)
        if not car then return nil end

        local model = car:FindFirstChild("Car")
        if not model then return nil end

        local isNotBroken =
            model:FindFirstChild("Wheels"):FindFirstChildOfClass("Part") and
            model:FindFirstChild("Body"):FindFirstChild("Engine"):FindFirstChildOfClass("MeshPart")

        return isNotBroken and model or nil
    end

    local function getCharacter()
        return lp.Character or lp.CharacterAdded:Wait()
    end

    local function canSpawn()
        return lp.SpawnTimer.Value <= 0
    end

    local function spawnBestCar()
        openFunc()
        spawnFunc(true, Enum.UserInputState.Begin)
    end

    local function destroyCar()
        local hum = getCharacter():FindFirstChildOfClass("Humanoid")
        local hrp = getCharacter():FindFirstChild("HumanoidRootPart")

        if not hum or not hrp then return end

        local car = getCurrentCar()

        repeat task.wait() until car.PrimaryPart ~= nil

        repeat
            task.wait()
            car = getCurrentCar()
            if not car then return end

            task.wait(0.1)

            pcall(function()
                if not car.PrimaryPart then return end
                car.PrimaryPart.Velocity = Vector3.new(0, 300, 0)
                car.PrimaryPart.CFrame = car.PrimaryPart.CFrame * CFrame.Angles(math.rad(180), 0, 0)
            end)

            task.wait(0.1)

            pcall(function()
                if not car.PrimaryPart then return end
                car.PrimaryPart.Velocity = Vector3.new(0, -400, 0)
                car.PrimaryPart.CFrame = car.PrimaryPart.CFrame * CFrame.Angles(math.rad(180), 0, 0)
            end)

        until not doBreak
    end

    -- 创建标签页
    local CarTab = Window:Tab({ Title = "汽车破坏", Icon = "car" })
    CarTab:Section({ Title = "主要功能", Opened = true })

    CarTab:Toggle({
        Title = "自动刷钱",
        Desc = "自动生成并摧毁车辆",
        Value = false,
        Callback = function(bool)
            AutofarmEnabled = bool
            if bool then
                task.spawn(function()
                    while AutofarmEnabled do
                        task.wait(0.5)
                        if canSpawn() then
                            doBreak = true
                            task.delay(10, function() doBreak = false end)
                            pcall(function()
                                spawnBestCar()
                                destroyCar()
                            end)
                        end
                    end
                end)
            end
        end
    })

    CarTab:Button({
        Title = "生成车辆",
        Callback = function()
            spawnBestCar()
        end
    })

    CarTab:Button({
        Title = "摧毁车辆",
        Callback = function()
            doBreak = true
            task.delay(10, function() doBreak = false end)
            pcall(function()
                destroyCar()
            end)
        end
    })

    -- 基本防挂机（模拟点击）
    local VU = game:GetService("VirtualUser")
    lp.Idled:Connect(function()
        VU:Button2Down(Vector2.new(0,0), workspace.CurrentCamera.CFrame)
        task.wait(0.2)
        VU:Button2Up(Vector2.new(0,0), workspace.CurrentCamera.CFrame)
    end)

    -- 直升机检测
    workspace.ChildAdded:Connect(function(newpart)
        task.wait(1)
        if newpart.Name == "Helicopter" then
            task.wait(0.5)
            if heleicopterspawn then
                local char = lp.Character
                if char then
                    local hum = char:FindFirstChildOfClass("Humanoid")
                    local hrp = char:FindFirstChild("HumanoidRootPart")
                    if hum and hrp then
                        hum:ChangeState(Enum.HumanoidStateType.GettingUp)
                        task.wait(0.1)
                        hum:ChangeState(Enum.HumanoidStateType.Jumping)
                        task.wait(0.5)
                        hrp.CFrame = workspace.Helicopter.Start.CFrame
                    end
                end
            end
        end
    end)

    WindUI:Notify({
        Title = "汽车破坏加载成功",
        Content = "功能已就绪",
        Duration = 3,
        Icon = "check"
    })
end

