    function removeEsp()
        for _, player in pairs(game.Workspace.PlayerCharacters:GetChildren()) do
            if player.Name ~= LP.Name then
                if player.HumanoidRootPart:FindFirstChild("eyeesspee") then
                    player.HumanoidRootPart.eyeesspee:Destroy()
                end
                if player.Head:FindFirstChild("Head") then
                    player.Head.Head:Destroy()
                end
            end
        end
    end

    function getClosestHrp()
        local closest = nil
        local shortest = 999999
        local myHrp = game.Workspace.PlayerCharacters[LP.Name]:FindFirstChild("HumanoidRootPart")
        if not myHrp then return nil end

        for _, player in pairs(game.Workspace.PlayerCharacters:GetChildren()) do
            if player.Name ~= LP.Name and player.Humanoid and player.Humanoid.Health > 0 then
                local targetHrp = player:FindFirstChild("HumanoidRootPart")
                if targetHrp then
                    local dist = (myHrp.Position - targetHrp.Position).Magnitude
                    if dist < shortest and dist <= _G.Settings.range then
                        shortest = dist
                        closest = targetHrp
                    end
                end
            end
        end
        return closest
    end

    function walkToClosest()
        local myChar = game.Workspace.PlayerCharacters[LP.Name]
        if not myChar then return end
        local myHrp = myChar:FindFirstChild("HumanoidRootPart")
        if not myHrp then return end

        local target = nil
        local dist = 999999
        for _, player in pairs(game.Workspace.PlayerCharacters:GetChildren()) do
            if player.Name ~= LP.Name and player.Humanoid and player.Humanoid.Health > 0 then
                local hrp = player:FindFirstChild("HumanoidRootPart")
                if hrp then
                    local d = (myHrp.Position - hrp.Position).Magnitude
                    if d < dist then
                        dist = d
                        target = hrp
                    end
                end
            end
        end
        if target then
            myChar.Humanoid.WalkToPoint = target.Position
        end
    end

    function setAttachmentWorldCFrame(attachment, cframe)
        if attachment and cframe then
            attachment.CFrame = attachment.Parent.CFrame:ToObjectSpace(cframe)
        end
    end

