    local espTimer = 0
    local followTimer = 0
    local attackTimer = 0
    local stompTimer = 0

    RunService.RenderStepped:Connect(function()
        if LP.PlayerGui.RoactUI:FindFirstChild("MainMenu") and _G.Settings.autospawn then
            keypress(0x20)
            task.wait(0.1)
            keyrelease(0x20)
        end

        if _G.Settings.autoequip then
            local myChar = game.Workspace.PlayerCharacters[LP.Name]
            if myChar and not myChar:FindFirstChildOfClass("Tool") and not LP.PlayerGui.RoactUI:FindFirstChild("MainMenu") then
                keypress(0x31)
                task.wait(0.1)
                keyrelease(0x31)
            end
        end

        espTimer = espTimer + 1
        if espTimer >= 60 then
            if _G.Settings.esp then
                addEsp()
            else
                removeEsp()
            end
            espTimer = 0
        end

        followTimer = followTimer + 1
        if followTimer >= 10 then
            if _G.Settings.followclosest then
                walkToClosest()
            end
            followTimer = 0
        end

        attackTimer = attackTimer + 1
        stompTimer = stompTimer + 1

        local myChar = game.Workspace.PlayerCharacters[LP.Name]
        if not myChar then return end
        local tool = myChar:FindFirstChildOfClass("Tool")
        if not tool then return end

        if tool.Hitboxes:FindFirstChild("Hitbox2") then
            tool.Hitboxes.Hitbox2:Destroy()
        end

        local targetHrp = getClosestHrp()
        if not targetHrp then return end

        local equipProgress = tool:FindFirstChild("ClientEquipProgress")
        if not equipProgress then return end

        if not _G.Settings.usemethod2 then
            if attackTimer >= _G.Settings.loopspeed then
                attackTimer = 0
                for i, dmgPoint in pairs(tool.Hitboxes.Hitbox:GetChildren()) do
                    if dmgPoint.Name == "DmgPoint" then
                        if i <= _G.Settings.usehitbox then
                            if _G.Settings.antiparry then
                                if targetHrp.Parent.SemiTransparentShield and targetHrp.Parent.SemiTransparentShield.Transparency == 1 then
                                    equipProgress.Value = 1
                                    if _G.Settings.enabled then
                                        setAttachmentWorldCFrame(
                                            dmgPoint,
                                            CFrame.new(targetHrp.Position + Vector3.new(math.random(-1,1), math.random(-1,1), math.random(-1,1)))
                                        )
                                    end
                                else
                                    setAttachmentWorldCFrame(dmgPoint, CFrame.new(targetHrp.Position + Vector3.new(123,123,123)))
                                    equipProgress.Value = 0
                                end
                            else
                                if _G.Settings.enabled then
                                    setAttachmentWorldCFrame(
                                        dmgPoint,
                                        CFrame.new(targetHrp.Position + Vector3.new(math.random(-1,1), math.random(-1,1), math.random(-1,1)))
                                    )
                                end
                            end
                        else
                            setAttachmentWorldCFrame(dmgPoint, CFrame.new(myChar.Head.Position + Vector3.new(0,10,0)))
                        end
                    end
                end
            end
        end

        if _G.Settings.stompaura and myChar:FindFirstChild("Stomp") then
            for i, dmgPoint in pairs(myChar.Stomp.Hitboxes.RightLegHitbox:GetChildren()) do
                if dmgPoint.Name == "DmgPoint" then
                    dmgPoint.Visible = true
                    if i <= _G.Settings.usehitbox then
                        if targetHrp.Parent.Humanoid.Health <= 15 then
                            setAttachmentWorldCFrame(
                                dmgPoint,
                                CFrame.new(targetHrp.Position + Vector3.new(math.random(-1,1), math.random(-1,1), math.random(-1,1)))
                            )
                            if stompTimer >= 30 then
                                keypress(0x51)
                                task.wait(0.1)
                                keyrelease(0x51)
                                stompTimer = 0
                            end
                        end
                    end
                end
            end
        end
    end)

