    local function antiShield()
        local lp = LP
        local animationInfo = {}
        local attackAnimations = {'Slash', 'Swing', 'Sword'}

        local function getInfo(id)
            local s, i = pcall(function() return game:GetService("MarketplaceService"):GetProductInfo(id) end)
            return s and i or { Name = '' }
        end

        local function block()
            keypress(0x46)
            task.wait()
            keyrelease(0x46)
        end

        local function onPlayer(p)
            local function onChar(char)
                local hum = char:WaitForChild("Humanoid")
                hum.AnimationPlayed:Connect(function(track)
                    local animId = track.Animation.AnimationId
                    local info = animationInfo[animId] or getInfo(tonumber(animId:match("%d+")))
                    animationInfo[animId] = info
                    if lp.Character and p.Character then
                        local dist = (p.Character.Head.Position - lp.Character.Head.Position).Magnitude
                        if dist < 15 then
                            for _, name in ipairs(attackAnimations) do
                                if info.Name:match(name) then block() end
                            end
                        end
                    end
                end)
            end
            if p.Character then onChar(p.Character) end
            p.CharacterAdded:Connect(onChar)
        end

        for _, v in pairs(Players:GetPlayers()) do
            if v ~= lp then onPlayer(v) end
        end
        Players.PlayerAdded:Connect(onPlayer)
    end

    if _G.Settings.autohit then
        task.spawn(function()
            while _G.Settings.autohit do
                mouse1click()
                task.wait(1)
            end
        end)
    end

