-- ========== 星际穿越功能加载 ==========
local interstellarLoaded = false
local function loadInterstellarFeatures()
    if interstellarLoaded then
        WindUI:Notify({ Title = "提示", Content = "功能已加载", Duration = 3, Icon = "info" })
        return
    end
    interstellarLoaded = true

    -- 创建所有标签页
    local Main = Window:Tab({Title = "主要功能", Icon = "star"})
    local RaceTab = Window:Tab({Title = "比赛功能", Icon = "flag"})
    local EditTab = Window:Tab({Title = "数值修改", Icon = "edit"})
    local OrbTab = Window:Tab({Title = "能量球收集", Icon = "globe"})
    local CrystalTab = Window:Tab({Title = "水晶功能", Icon = "gem"})
    local PetTab = Window:Tab({Title = "宠物功能", Icon = "paw"})

    -- 状态表
    local Interstellar = {
        getorb = false,
        area = "City",
        mainexe = false,
        hoop = false,
        opencrystal = false,
        petshop = false,
        evolvepet = false,
        birth = 9e9,
        autobirth = false,
    }

    -- 主要功能
    Main:Toggle({
        Title = "自动重生",
        Default = false,
        Callback = function(state)
            Interstellar.mainexe = state
            if state then
                task.spawn(function()
                    while Interstellar.mainexe do
                        game:GetService("ReplicatedStorage").rEvents.rebirthEvent:FireServer("rebirthRequest")
                        task.wait()
                    end
                end)
            end
        end
    })

    Main:Button({
        Title = "获取所有宝箱",
        Callback = function()
            for _, v in pairs(game.ReplicatedStorage.chestRewards:GetChildren()) do
                game.ReplicatedStorage.rEvents.checkChestRemote:InvokeServer(v.Name)
            end
        end
    })

    Main:Button({
        Title = "获取所有通行证",
        Callback = function()
            for _, v in ipairs(game:GetService("ReplicatedStorage").gamepassIds:GetChildren()) do
                v.Parent = game.Players.LocalPlayer.ownedGamepasses
            end
        end
    })

    -- 比赛功能
    local Maps = {}
    for i, Map in pairs(game:GetService("Workspace").raceMaps:GetChildren()) do
        Maps[i] = Map.Name
    end
    local selectedMap = ""
    RaceTab:Dropdown({
        Title = "选择比赛地图",
        Values = Maps,
        Callback = function(Value) selectedMap = Value end
    })

    RaceTab:Button({
        Title = "传送到终点",
        Callback = function()
            if selectedMap ~= "" then
                local char = game.Players.LocalPlayer.Character
                if char and char:FindFirstChild("HumanoidRootPart") then
                    char.HumanoidRootPart.CFrame = game.workspace.raceMaps[selectedMap].finishPart.CFrame
                end
            end
        end
    })

    RaceTab:Toggle({
        Title = "自动参加比赛",
        Default = false,
        Callback = function(state)
            Interstellar.mainexe = state
            if state then
                local placeId = game.PlaceId
                task.spawn(function()
                    while Interstellar.mainexe do
                        game:GetService("ReplicatedStorage").rEvents.raceEvent:FireServer("joinRace")
                        local char = game.Players.LocalPlayer.Character
                        if char and char:FindFirstChild("HumanoidRootPart") then
                            if placeId == 3101667897 then
                                char.HumanoidRootPart.CFrame = game.workspace.raceMaps.Grassland.finishPart.CFrame
                                task.wait(0.1)
                                char.HumanoidRootPart.CFrame = game.workspace.raceMaps.Magma.finishPart.CFrame
                                task.wait(0.1)
                                char.HumanoidRootPart.CFrame = game.workspace.raceMaps.Desert.finishPart.CFrame
                            elseif placeId == 3276265788 then
                                char.HumanoidRootPart.CFrame = game.workspace.raceMaps.Speedway.finishPart.CFrame
                            elseif placeId == 3232996272 then
                                char.HumanoidRootPart.CFrame = game.workspace.raceMaps.Starway.finishPart.CFrame
                            end
                        end
                        task.wait(0.2)
                    end
                end)
            end
        end
    })

