-- ========== 子弹追踪 + 自瞄系统加载 ==========
local aimSystemLoaded = false
local function loadAimSystemFeatures()
    if aimSystemLoaded then
        WindUI:Notify({ Title = "提示", Content = "闪光已加载", Duration = 3, Icon = "info" })
        return
    end
    aimSystemLoaded = true

    -- 创建或获取标签页（避免重复创建）
    local FeatureTab = Window:Tab({ Title = "功能", Icon = "sword" })
    local AimTab = Window:Tab({ Title = "自瞄", Icon = "crosshair" })

    -- ==================== 功能标签页：子弹追踪 ====================
    local FeatureSection = FeatureTab:Section({ Title = "战斗", Opened = true })

    FeatureSection:Button({
        Title = "点击开启子弹追踪",
        Callback = function()
            local Workspace = game:GetService("Workspace")
            local Players = game:GetService("Players")
            local ReplicatedStorage = game:GetService("ReplicatedStorage")
            local RunService = game:GetService("RunService")

            local lp = Players.LocalPlayer
            local Cam = Workspace.CurrentCamera
            local BulletHandler = require(ReplicatedStorage.ModuleScripts.GunModules.BulletHandler)
            local originalFire = BulletHandler.Fire

            local function getNearestHead()
                local nearest = nil
                local minDist = 9999

                for _, plr in ipairs(Players:GetPlayers()) do
                    if plr == lp then continue end
                    local char = plr.Character
                    if not char then continue end
                    
                    local head = char:FindFirstChild("Head")
                    local hum = char:FindFirstChildOfClass("Humanoid")
                    if not head or not hum or hum.Health <= 0 then continue end
                    
                    local pos, onScreen = Cam:WorldToViewportPoint(head.Position)
                    if not onScreen then continue end
                    
                    local dist = (Vector2.new(pos.X, pos.Y) - Cam.ViewportSize/2).Magnitude
                    if dist < minDist then
                        minDist = dist
                        nearest = head
                    end
                end
                return nearest
            end

            BulletHandler.Fire = function(fireData)
                local target = getNearestHead()
                if target then
                    fireData.Direction = (target.Position - fireData.Origin).Unit
                    fireData.Force = fireData.Force * 1000
                end
                return originalFire(fireData)
            end

            game:GetService("StarterGui"):SetCore("SendNotification", {
                Title = "子弹追踪",
                Text = "已自动启用 ✅",
                Duration = 3
            })
        end
    })

    -- ==================== 自瞄系统（完整） ====================
    local AimLockSystem = {}
    local Players = game:GetService("Players")
    local RunService = game:GetService("RunService")
    local UserInputService = game:GetService("UserInputService")
    local Workspace = game:GetService("Workspace")
    local Camera = Workspace.CurrentCamera
    local LocalPlayer = Players.LocalPlayer

    AimLockSystem.Config = {
        enabled = false,
        smoothAim = false,
        aimType = "最近玩家",
        aimPart = "头部",
        fovEnabled = false,
        showFov = false,
        fovSize = 100,
        fovColor = Color3.fromRGB(255, 255, 255),
        fovLockDistance = 1000,
        nearestPlayerDistance = 1000,
        nearestMouseDistance = 500,
        wallCheckEnabled = true,
        lerpAlpha = 0.4,
        aimlockOffsetX = 0,
        aimlockOffsetY = 0,
        ignoredPlayers = {},
        prioritizedPlayers = {},
        aimlockCertainPlayer = false,
        selectedPlayer = nil,
        rainbowFov = false,
        fovStrokeThickness = 2,
        fovGui = nil,
        fovFrame = nil,
        fovStroke = nil
    }

    AimLockSystem.State = {
        isAimingLocked = false,
        aimlockConnection = nil
    }

    function AimLockSystem.GetLocalHRP()
        if not LocalPlayer.Character then return nil end
        return LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
    end

    function AimLockSystem.IsPlayerIgnored(player)
        return AimLockSystem.Config.ignoredPlayers[player.Name] == true
    end

    function AimLockSystem.GetAimPartPosition(targetPlayer)
        if not targetPlayer or not targetPlayer.Character then return nil end
        local part = nil
        if AimLockSystem.Config.aimPart == "头部" then
            part = targetPlayer.Character:FindFirstChild("Head")
        elseif AimLockSystem.Config.aimPart == "躯干" then
            part = targetPlayer.Character:FindFirstChild("UpperTorso") or 
                   targetPlayer.Character:FindFirstChild("Torso")
        elseif AimLockSystem.Config.aimPart == "脚部" then
            local hrp = targetPlayer.Character:FindFirstChild("HumanoidRootPart")
            if hrp then
                return hrp.Position + Vector3.new(0, -3, 0)
            end
        end
        return part and part.Position or nil
    end

    function AimLockSystem.GetPriorityScore(player)
        if not player.Character or not player.Character:FindFirstChild("HumanoidRootPart") then 
            return math.huge 
        end
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then return math.huge end
        if player == LocalPlayer then return math.huge end
        if AimLockSystem.IsPlayerIgnored(player) then return math.huge end

        local hrp = player.Character.HumanoidRootPart
        if AimLockSystem.Config.fovEnabled then
            local screenPos, onScreen = Camera:WorldToViewportPoint(hrp.Position)
            if not onScreen then return math.huge end
            local center = Vector2.new(Camera.ViewportSize.X/2, Camera.ViewportSize.Y/2)
            local distFromCenter = (Vector2.new(screenPos.X, screenPos.Y) - center).Magnitude
            if distFromCenter > AimLockSystem.Config.fovSize/2 then return math.huge end
            if (localHRP.Position - hrp.Position).Magnitude > AimLockSystem.Config.fovLockDistance then 
                return math.huge 
            end
        end

        if AimLockSystem.Config.wallCheckEnabled then
            local head = player.Character:FindFirstChild("Head")
            if head then
                local origin = localHRP.Parent:FindFirstChild("Head") and 
                              localHRP.Parent.Head.Position or localHRP.Position
                local direction = head.Position - origin
                local rayParams = RaycastParams.new()
                rayParams.FilterDescendantsInstances = {LocalPlayer.Character}
                rayParams.FilterType = Enum.RaycastFilterType.Exclude
                local result = Workspace:Raycast(origin, direction, rayParams)
                if result and not result.Instance:IsDescendantOf(player.Character) then
                    return math.huge
                end
            end
        end

        if AimLockSystem.Config.aimType == "最近玩家" then
            return (localHRP.Position - hrp.Position).Magnitude
        else
            local mousePos = UserInputService:GetMouseLocation()
            local screenPos = Camera:WorldToViewportPoint(hrp.Position)
            return (Vector2.new(screenPos.X, screenPos.Y) - mousePos).Magnitude
        end
    end

    function AimLockSystem.GetClosestPlayer()
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then return nil end

        local bestPlayer, bestScore = nil, math.huge
        for _, player in ipairs(AimLockSystem.Config.prioritizedPlayers) do
            local score = AimLockSystem.GetPriorityScore(player)
            if score < bestScore then
                bestScore = score
                bestPlayer = player
            end
        end
        if bestPlayer then return bestPlayer end

        for _, player in ipairs(Players:GetPlayers()) do
            if table.find(AimLockSystem.Config.prioritizedPlayers, player) then 
                continue 
            end
            local score = AimLockSystem.GetPriorityScore(player)
            if score < bestScore then
                bestScore = score
                bestPlayer = player
            end
        end
        return bestPlayer
    end

    function AimLockSystem.UpdateAimlock()
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then 
            AimLockSystem.State.isAimingLocked = false
            return 
        end

        local targetPlayer = nil
        if AimLockSystem.Config.aimlockCertainPlayer then
            targetPlayer = AimLockSystem.Config.selectedPlayer
        else
            targetPlayer = AimLockSystem.GetClosestPlayer()
        end

        if targetPlayer then
            AimLockSystem.State.isAimingLocked = true
            local targetPosition = AimLockSystem.GetAimPartPosition(targetPlayer)
            if targetPosition then
                targetPosition = targetPosition + Vector3.new(
                    AimLockSystem.Config.aimlockOffsetX,
                    AimLockSystem.Config.aimlockOffsetY,
                    0
                )
                local lookDirection = (targetPosition - Camera.CFrame.Position).Unit
                if AimLockSystem.Config.smoothAim then
                    local targetCFrame = CFrame.lookAt(
                        Camera.CFrame.Position,
                        Camera.CFrame.Position + lookDirection
                    )
                    Camera.CFrame = Camera.CFrame:Lerp(targetCFrame, AimLockSystem.Config.lerpAlpha)
                else
                    Camera.CFrame = CFrame.lookAt(
                        Camera.CFrame.Position,
                        Camera.CFrame.Position + lookDirection
                    )
                end
            end
        else
            AimLockSystem.State.isAimingLocked = false
        end
    end

    function AimLockSystem.UpdateFOVCircle()
        if not AimLockSystem.Config.showFov then
            if AimLockSystem.Config.fovFrame then
                AimLockSystem.Config.fovFrame.Visible = false
            end
            return
        end

        if not AimLockSystem.Config.fovGui then
            AimLockSystem.Config.fovGui = Instance.new("ScreenGui")
            AimLockSystem.Config.fovGui.Name = "FOVCircle"
            AimLockSystem.Config.fovGui.IgnoreGuiInset = true
            AimLockSystem.Config.fovGui.Parent = game:GetService("CoreGui")

            AimLockSystem.Config.fovFrame = Instance.new("Frame")
            AimLockSystem.Config.fovFrame.Name = "Circle"
            AimLockSystem.Config.fovFrame.AnchorPoint = Vector2.new(0.5, 0.5)
            AimLockSystem.Config.fovFrame.Position = UDim2.new(0.5, 0, 0.5, 0)
            AimLockSystem.Config.fovFrame.BackgroundTransparency = 1
            AimLockSystem.Config.fovFrame.BorderSizePixel = 0
            AimLockSystem.Config.fovFrame.Parent = AimLockSystem.Config.fovGui

            local corner = Instance.new("UICorner")
            corner.CornerRadius = UDim.new(1, 0)
            corner.Parent = AimLockSystem.Config.fovFrame

            AimLockSystem.Config.fovStroke = Instance.new("UIStroke")
            AimLockSystem.Config.fovStroke.Thickness = AimLockSystem.Config.fovStrokeThickness
            AimLockSystem.Config.fovStroke.Parent = AimLockSystem.Config.fovFrame
        end

        local color = AimLockSystem.Config.fovColor
        if AimLockSystem.State.isAimingLocked then
            color = Color3.fromRGB(0, 255, 0)
        elseif AimLockSystem.Config.rainbowFov then
            color = Color3.fromHSV(tick() % 1, 1, 1)
        end
        AimLockSystem.Config.fovStroke.Color = color
        AimLockSystem.Config.fovFrame.Size = UDim2.new(0, AimLockSystem.Config.fovSize, 0, AimLockSystem.Config.fovSize)
        AimLockSystem.Config.fovFrame.Visible = true
    end

    function AimLockSystem.ToggleAimlock(enabled)
        AimLockSystem.Config.enabled = enabled
        if enabled then
            if not AimLockSystem.State.aimlockConnection then
                AimLockSystem.State.aimlockConnection = RunService.RenderStepped:Connect(function()
                    AimLockSystem.UpdateAimlock()
                    AimLockSystem.UpdateFOVCircle()
                end)
            end
            WindUI:Notify({
                Title = "静默自瞄",
                Content = "已开启",
                Icon = "target",
                Duration = 3
            })
        else
            if AimLockSystem.State.aimlockConnection then
                AimLockSystem.State.aimlockConnection:Disconnect()
                AimLockSystem.State.aimlockConnection = nil
            end
            AimLockSystem.State.isAimingLocked = false
            if AimLockSystem.Config.fovFrame then
                AimLockSystem.Config.fovFrame.Visible = false
            end
            WindUI:Notify({
                Title = "静默自瞄",
                Content = "已关闭",
                Icon = "x-circle",
                Duration = 3
            })
        end
    end

    -- ==================== 自瞄UI控件 ====================
    local AimSection = AimTab:Section({ Title = "自瞄设置", Opened = true })

    AimSection:Toggle({
        Title = "启用自瞄",
        Value = false,
        Callback = function(Value)
            AimLockSystem.ToggleAimlock(Value)
        end
    })

    AimSection:Toggle({
        Title = "平滑瞄准",
        Value = false,
        Callback = function(Value)
            AimLockSystem.Config.smoothAim = Value
        end
    })

    AimSection:Toggle({
        Title = "启用FOV检测",
        Value = false,
        Callback = function(Value)
            AimLockSystem.Config.fovEnabled = Value
        end
    })

    AimSection:Toggle({
        Title = "显示FOV圆圈",
        Value = false,
        Callback = function(Value)
            AimLockSystem.Config.showFov = Value
        end
    })

    AimSection:Slider({
        Title = "FOV大小",
        Value = {
            Min = 50,
            Max = 500,
            Default = 100,
        },
        Callback = function(Value)
            AimLockSystem.Config.fovSize = Value
        end
    })

    AimSection:Slider({
        Title = "平滑度",
        Value = {
            Min = 0.1,
            Max = 1,
            Default = 0.4,
        },
        Callback = function(Value)
            AimLockSystem.Config.lerpAlpha = Value
        end
    })

    AimSection:Slider({
        Title = "最大距离",
        Value = {
            Min = 100,
            Max = 5000,
            Default = 1000,
        },
        Callback = function(Value)
            AimLockSystem.Config.fovLockDistance = Value
        end
    })

    AimSection:Dropdown({
        Title = "瞄准类型",
        Values = { "最近玩家", "鼠标最近" },
        Value = "最近玩家",
        Callback = function(Value)
            AimLockSystem.Config.aimType = Value
        end
    })

    AimSection:Dropdown({
        Title = "瞄准部位",
        Values = { "头部", "躯干", "脚部" },
        Value = "头部",
        Callback = function(Value)
            AimLockSystem.Config.aimPart = Value
        end
    })

    AimSection:Toggle({
        Title = "掩体检测",
        Value = true,
        Callback = function(Value)
            AimLockSystem.Config.wallCheckEnabled = Value
        end
    })

    -- 玩家列表
    local playerList = {}
    local function updatePlayerList()
        playerList = {"全部"}
        for _, player in ipairs(Players:GetPlayers()) do
            if player ~= LocalPlayer then
                table.insert(playerList, player.Name)
            end
        end
    end
    updatePlayerList()

    local targetDropdown = AimSection:Dropdown({
        Title = "锁定指定玩家",
        Values = playerList,
        Value = "全部",
        Callback = function(Value)
            if Value == "全部" then
                AimLockSystem.Config.aimlockCertainPlayer = false
                AimLockSystem.Config.selectedPlayer = nil
            else
                for _, player in ipairs(Players:GetPlayers()) do
                    if player.Name == Value then
                        AimLockSystem.Config.aimlockCertainPlayer = true
                        AimLockSystem.Config.selectedPlayer = player
                        break
                    end
                end
            end
        end
    })

    AimSection:Button({
        Title = "刷新玩家列表",
        Callback = function()
            updatePlayerList()
            targetDropdown:Refresh(playerList)
        end
    })

    AimSection:Colorpicker({
        Title = "FOV颜色",
        Default = Color3.fromRGB(255, 255, 255),
        Callback = function(Value)
            AimLockSystem.Config.fovColor = Value
        end
    })

    AimSection:Toggle({
        Title = "彩虹FOV",
        Value = false,
        Callback = function(Value)
            AimLockSystem.Config.rainbowFov = Value
        end
    })

    AimSection:Slider({
        Title = "水平偏移",
        Value = {
            Min = -50,
            Max = 50,
            Default = 0,
        },
        Callback = function(Value)
            AimLockSystem.Config.aimlockOffsetX = Value
        end
    })

    AimSection:Slider({
        Title = "垂直偏移",
        Value = {
            Min = -50,
            Max = 50,
            Default = 0,
        },
        Callback = function(Value)
            AimLockSystem.Config.aimlockOffsetY = Value
        end
    })

    WindUI:Notify({
        Title = "闪光",
        Content = "功能已加载完成",
        Duration = 3,
        Icon = "check"
    })
end

-- ========== 生存游戏功能加载（全新UI） ==========
local survivalLoaded = false
local function loadSurvivalFeatures()
    if survivalLoaded then
        WindUI:Notify({ Title = "提示", Content = "自然灾害功能已加载", Duration = 3, Icon = "info" })
        return
    end
    survivalLoaded = true

    local plr = game:GetService("Players").LocalPlayer

    -- 创建动态彩色横幅（用于显示灾难）
    local function createBanner()
        local screenGui = Instance.new("ScreenGui")
        screenGui.Name = "DisasterBanner"
        screenGui.Parent = game:GetService("CoreGui")
        screenGui.ResetOnSpawn = false
        screenGui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling

        local frame = Instance.new("Frame")
        frame.Size = UDim2.new(0, 400, 0, 60)
        frame.Position = UDim2.new(0.5, -200, 0.85, 0)
        frame.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
        frame.BackgroundTransparency = 0.2
        frame.BorderSizePixel = 0
        frame.Parent = screenGui

        local corner = Instance.new("UICorner")
        corner.CornerRadius = UDim.new(0, 12)
        corner.Parent = frame

        local uiStroke = Instance.new("UIStroke")
        uiStroke.Thickness = 2
        uiStroke.Color = Color3.fromRGB(255, 100, 100)
        uiStroke.Parent = frame

        local textLabel = Instance.new("TextLabel")
        textLabel.Size = UDim2.new(1, 0, 1, 0)
        textLabel.BackgroundTransparency = 1
        textLabel.TextColor3 = Color3.fromRGB(255, 255, 255)
        textLabel.TextScaled = true
        textLabel.Font = Enum.Font.GothamBold
        textLabel.Text = "等待灾难预测..."
        textLabel.Parent = frame

        -- 闪烁动画
        local tweenService = game:GetService("TweenService")
        local function startBlink()
            local blinkTween = tweenService:Create(uiStroke, TweenInfo.new(0.5, Enum.EasingStyle.Linear, Enum.EasingDirection.InOut, -1), {Color = Color3.fromRGB(255, 200, 100)})
            blinkTween:Play()
        end
        startBlink()

        return frame, textLabel, uiStroke
    end

    local bannerFrame, bannerText, bannerStroke = createBanner()
    bannerFrame.Visible = false

    -- 创建标签页
    local SurvivalTab = Window:Tab({ Title = "生存工具", Icon = "cloud-lightning" })
    SurvivalTab:Section({ Title = "特殊功能", Opened = true })

    -- 地图投票：改为按钮（点击一次显示，再点一次隐藏）
    SurvivalTab:Button({
        Title = "🔁 切换地图投票界面",
        Desc = "点击显示/隐藏投票面板",
        Callback = function()
            local mainGui = plr.PlayerGui:FindFirstChild("MainGui")
            local mapVotePage = mainGui and mainGui:FindFirstChild("MapVotePage")
            if mapVotePage then
                local newState = not mapVotePage.Visible
                mapVotePage.Visible = newState
                WindUI:Notify({
                    Title = "地图投票",
                    Content = newState and "✅ 投票界面已显示" or "❌ 投票界面已隐藏",
                    Duration = 1.5,
                    Icon = newState and "eye" or "eye-off"
                })
            else
                WindUI:Notify({
                    Title = "错误",
                    Content = "未找到地图投票界面",
                    Duration = 2,
                    Icon = "alert-circle"
                })
            end
        end
    })

    -- 预测灾害：改为滑块+彩色横幅，每次灾难变化时更新横幅内容并改变颜色
    local nextdis = false
    local disasterLoop = nil
    local lastDisaster = nil

    SurvivalTab:Toggle({
        Title = "🌀 动态灾难预警",
        Desc = "开启后屏幕下方显示动态彩色横幅，自动更新灾难",
        Value = false,
        Callback = function(val)
            nextdis = val
            
            if disasterLoop then
                task.cancel(disasterLoop)
                disasterLoop = nil
            end
            
            if nextdis then
                bannerFrame.Visible = true
                disasterLoop = task.spawn(function()
                    while nextdis do
                        local character = plr.Character
                        if character then
                            local survivalTag = character:FindFirstChild("SurvivalTag")
                            if survivalTag then
                                local disasterName = survivalTag.Value
                                if disasterName ~= lastDisaster then
                                    lastDisaster = disasterName
                                    local disasterText = ""
                                    local color = Color3.fromRGB(255, 100, 100) -- 默认红色
                                    
                                    if disasterName == "Blizzard" then
                                        disasterText = "❄️ 暴风雪来袭！快找避难所！"
                                        color = Color3.fromRGB(100, 200, 255)
                                    elseif disasterName == "Sandstorm" then
                                        disasterText = "🏜️ 沙尘暴！注意躲避！"
                                        color = Color3.fromRGB(210, 180, 140)
                                    elseif disasterName == "Tornado" then
                                        disasterText = "🌪️ 龙卷风！快跑！"
                                        color = Color3.fromRGB(150, 150, 150)
                                    elseif disasterName == "Volcanic Eruption" then
                                        disasterText = "🌋 火山爆发！岩浆来了！"
                                        color = Color3.fromRGB(255, 80, 40)
                                    elseif disasterName == "Flash Flood" then
                                        disasterText = "💧 洪水！快往高处跑！"
                                        color = Color3.fromRGB(0, 150, 255)
                                    elseif disasterName == "Deadly Virus" then
                                        disasterText = "🦠 致命病毒！寻找疫苗！"
                                        color = Color3.fromRGB(120, 220, 100)
                                    elseif disasterName == "Tsunami" then
                                        disasterText = "🌊 海啸！快往高处跑！"
                                        color = Color3.fromRGB(0, 100, 200)
                                    elseif disasterName == "Acid Rain" then
                                        disasterText = "☣️ 酸雨！快找遮蔽物！"
                                        color = Color3.fromRGB(150, 255, 100)
                                    elseif disasterName == "Fire" then
                                        disasterText = "🔥 火灾！远离火焰！"
                                        color = Color3.fromRGB(255, 80, 80)
                                    elseif disasterName == "Meteor Shower" then
                                        disasterText = "☄️ 流星雨！注意躲避！"
                                        color = Color3.fromRGB(255, 200, 100)
                                    elseif disasterName == "Earthquake" then
                                        disasterText = "🌍 地震！保持平衡！"
                                        color = Color3.fromRGB(139, 69, 19)
                                    elseif disasterName == "Thunder Storm" then
                                        disasterText = "⛈️ 暴风雨！小心雷电！"
                                        color = Color3.fromRGB(200, 200, 255)
                                    else
                                        disasterText = "⚠️ 未知灾难即将到来"
                                        color = Color3.fromRGB(255, 255, 255)
                                    end
                                    
                                    bannerText.Text = disasterText
                                    bannerStroke.Color = color
                                    bannerFrame.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
                                    bannerFrame.BackgroundTransparency = 0.3
                                    
                                    -- 额外弹出一条简短通知（可选）
                                    WindUI:Notify({
                                        Title = "灾难预警",
                                        Content = disasterText,
                                        Duration = 2.5,
                                        Icon = "alert-triangle"
                                    })
                                end
                            else
                                bannerText.Text = "⏳ 等待下一轮灾难..."
                                bannerStroke.Color = Color3.fromRGB(255, 255, 255)
                            end
                        else
                            bannerText.Text = "👤 角色未生成"
                            bannerStroke.Color = Color3.fromRGB(150, 150, 150)
                        end
                        task.wait(1)
                    end
                    bannerFrame.Visible = false
                    bannerText.Text = "等待灾难预测..."
                    lastDisaster = nil
                end)
            else
                bannerFrame.Visible = false
                if bannerText then bannerText.Text = "等待灾难预测..." end
                lastDisaster = nil
            end
        end
    })

    WindUI:Notify({
        Title = "",
        Content = "加载成功！",
        Duration = 3,
        Icon = "sparkles"
    })
end

-- ========== 武器透视 + 传送枪械功能加载 ==========
local weaponTeleportLoaded = false
local function loadWeaponTeleportFeatures()
    if weaponTeleportLoaded then
        WindUI:Notify({ Title = "提示", Content = "功能已加载", Duration = 3, Icon = "info" })
        return
    end
    weaponTeleportLoaded = true

    local Players = game:GetService("Players")
    local RunService = game:GetService("RunService")
    local Workspace = game:GetService("Workspace")
    local LocalPlayer = Players.LocalPlayer

    -- ==================== 武器透视标签页 ====================
    local WeaponESPTab = Window:Tab({ Title = "武器透视", Icon = "eye" })
    local WeaponSection = WeaponESPTab:Section({ Title = "武器透视设置", Opened = true })

    local CONFIG = {
        WEAPON_ESP_COLOR = Color3.fromRGB(0, 255, 0),
        UPDATE_INTERVAL = 0.5
    }

    local espCache = {}
    local espActive = false
    local espConnection = nil

    local function getDisplayNameFromPath(pathStr)
        local manualMap = {
            ["workspace.Weapons.P90:GetChildren()[3]"] = "P90",
            ["workspace.Weapons.MP5k:GetChildren()[3]"] = "MP5k",
            ["workspace.Weapons.M4A1:GetChildren()[3]"] = "M4A1",
            ["workspace.Weapons[\"Desert Eagle\"]:GetChildren()[3]"] = "Desert Eagle",
            ["workspace.Weapons.AWP:GetChildren()[3]"] = "AWP",
            ["workspace.Weapons[\"Colt Anaconda\"]:GetChildren()[3]"] = "Colt Anaconda",
            ["workspace.Weapons[\"AK-47\"]:GetChildren()[4]"] = "AK-47",
        }
        if manualMap[pathStr] then
            return manualMap[pathStr]
        end
        local name = pathStr:match("%[\"([^\"]+)\"%]$") or pathStr:match("%.([%w_]+)$")
        return name or "Weapon"
    end

    local weaponPaths = {
        "workspace.Weapons.SVD.SVD",
        "workspace.Weapons.R870.R870",
        "workspace.Weapons.P90:GetChildren()[3]",
        "workspace.Weapons.MP5k:GetChildren()[3]",
        "workspace.Weapons.M4A1:GetChildren()[3]",
        "workspace.Weapons.M1014.M1014",
        "workspace.Weapons.Flamethrower.Flamethrower",
        "workspace.Weapons.G36C.G36C",
        "workspace.Weapons[\"DB Shotgun\"][\"DB Shotgun\"]",
        "workspace.Weapons[\"Desert Eagle\"]:GetChildren()[3]",
        "workspace.Weapons.AWP:GetChildren()[3]",
        "workspace.Weapons[\"Colt Anaconda\"]:GetChildren()[3]",
        "workspace.Weapons[\"AK-47\"]:GetChildren()[4]",
        "workspace.Weapons[\"AN-94\"][\"AN-94\"]"
    }

    local pathDisplayNames = {}
    for _, path in ipairs(weaponPaths) do
        pathDisplayNames[path] = getDisplayNameFromPath(path)
    end

    local function getWeaponFromPath(pathStr)
        local success, result = pcall(function()
            local func = loadstring("return " .. pathStr)
            return func()
        end)
        if success and result and typeof(result) == "Instance" then
            return result
        end
        return nil
    end

    local function getAdorneePart(weapon)
        if weapon:IsA("BasePart") then
            return weapon
        elseif weapon:IsA("Model") then
            return weapon.PrimaryPart or weapon:FindFirstChildWhichIsA("BasePart")
        end
        return nil
    end

    local function addESPToWeapon(weapon, displayName)
        if not weapon or espCache[weapon] then return end

        local adornee = getAdorneePart(weapon)
        if not adornee then return end

        local highlight = Instance.new("Highlight")
        highlight.Name = "WeaponESP"
        highlight.FillColor = CONFIG.WEAPON_ESP_COLOR
        highlight.FillTransparency = 0.5
        highlight.OutlineColor = CONFIG.WEAPON_ESP_COLOR
        highlight.OutlineTransparency = 0
        highlight.Parent = weapon

        local billboard = Instance.new("BillboardGui")
        billboard.Name = "WeaponLabel"
        billboard.Adornee = adornee
        billboard.Size = UDim2.new(0, 200, 0, 30)
        billboard.StudsOffset = Vector3.new(0, 2.5, 0)
        billboard.AlwaysOnTop = true
        billboard.Parent = weapon

        local label = Instance.new("TextLabel")
        label.Size = UDim2.new(1, 0, 1, 0)
        label.BackgroundTransparency = 1
        label.Text = displayName
        label.TextColor3 = CONFIG.WEAPON_ESP_COLOR
        label.TextStrokeTransparency = 0.5
        label.TextSize = 16
        label.Font = Enum.Font.SourceSansBold
        label.Parent = billboard

        espCache[weapon] = { Highlight = highlight, Label = billboard }
    end

    local function cleanupESP()
        for weapon, components in pairs(espCache) do
            if not weapon or not weapon.Parent then
                if components.Highlight then components.Highlight:Destroy() end
                if components.Label then components.Label:Destroy() end
                espCache[weapon] = nil
            end
        end
    end

    local function scanWeapons()
        for _, path in ipairs(weaponPaths) do
            local weapon = getWeaponFromPath(path)
            if weapon then
                addESPToWeapon(weapon, pathDisplayNames[path])
            end
        end
        cleanupESP()
    end

    local function startESP()
        if espConnection then espConnection:Disconnect() end
        espConnection = RunService.Heartbeat:Connect(function()
            scanWeapons()
            task.wait(CONFIG.UPDATE_INTERVAL)
        end)
    end

    local function stopESP()
        if espConnection then
            espConnection:Disconnect()
            espConnection = nil
        end
        for weapon, components in pairs(espCache) do
            if components.Highlight then components.Highlight:Destroy() end
            if components.Label then components.Label:Destroy() end
        end
        espCache = {}
    end

    WeaponSection:Toggle({
        Title = "开启武器透视",
        Desc = "高亮显示地图上的武器",
        Value = false,
        Callback = function(state)
            if state then
                startESP()
                WindUI:Notify({ Title = "武器透视", Content = "已开启", Duration = 2, Icon = "eye" })
            else
                stopESP()
                WindUI:Notify({ Title = "武器透视", Content = "已关闭", Duration = 2, Icon = "eye-off" })
            end
        end
    })

    WeaponSection:Colorpicker({
        Title = "高亮颜色",
        Default = CONFIG.WEAPON_ESP_COLOR,
        Callback = function(color)
            CONFIG.WEAPON_ESP_COLOR = color
            -- 立即更新所有现有高亮
            for weapon, comp in pairs(espCache) do
                if comp.Highlight then
                    comp.Highlight.FillColor = color
                    comp.Highlight.OutlineColor = color
                end
                if comp.Label and comp.Label:FindFirstChildOfClass("TextLabel") then
                    comp.Label:FindFirstChildOfClass("TextLabel").TextColor3 = color
                end
            end
        end
    })

    -- ==================== 传送枪械标签页 ====================
    local TeleportTab = Window:Tab({ Title = "传送枪械", Icon = "map-pin" })
    local TeleportSection = TeleportTab:Section({ Title = "路点传送", Opened = true })

    -- 路点数据（来自原脚本）
    local waypoints = {
        {201.899994, 302, 161.499969, 1, 0, 0, 0, -1.1920929e-07, -1.00000012, 0, 1.00000012, -1.1920929e-07},
        {112.200027, 336.000031, 572.099976, -1.1920929e-07, 0, -1.00000012, 0, 1, 0, 1.00000012, 0, -1.1920929e-07},
        {136.200027, 334, 502.100006, 0, -1, 0, 0, 0, -1, 1, 0, 0},
        {-156.5, 303.5, 766.400024, -1, 0, 0, 0, 1, 0, 0, 0, -1},
        {230.199997, 373.5, 50.0999985, 0, 0, -1, 0, 1, 0, 1, 0, 0},
        {377.900024, 325.5, 652.900024, 1, 0, 0, 0, 1, 0, 0, 0, 1},
        {2.70000029, 268.200012, 188.099991, 0, 0, -1, 0, 1, 0, 1, 0, 0},
        {113.199997, 324, 674.700012, 0, 1, 0, 0, 0, -1, -1, 0, 0},
        {151.199997, 259.200043, 327.100067, 0, -1, 0, 0, 0, -1, 1, 0, 0},
        {-148.5, 316, 277.899994, -1, 0, 0, 0, 1, 0, 0, 0, -1},
        {465.199951, 312.400024, 759.099976, 0, 0, -1, 0, 1, 0, 1, 0, 0},
        {-104.500031, 314.5, 460.399994, 0, 0, -1, 0, 1, 0, 1, 0, 0},
        {56.5000038, 293.799988, 263.399963, -1, 0, 0, 0, 1, 0, 0, 0, -1},
        {70.1999969, 282.200012, 29.7000008, 0, 1, 0, 0, 0, -1, -1, 0, 0},
        {125.499969, 344.399994, 763.800049, -1, 0, -0, 0, 0, -1, 0, -1, -0},
        {320.899994, 273.699982, 139.800003, 0, 1, 0, 0, 0, -1, -1, 0, 0},
        {156.5, 343.5, 606.400024, -1, 0, 0, 0, 1, 0, 0, 0, -1}
    }

    TeleportSection:Button({
        Title = "传送所有枪械点位",
        Desc = "依次传送到所有路点并返回原点",
        Callback = function()
            local character = LocalPlayer.Character
            local rootPart = character and character:FindFirstChild("HumanoidRootPart")
            if not rootPart then
                WindUI:Notify({ Title = "错误", Content = "角色未就绪", Duration = 2, Icon = "alert-circle" })
                return
            end
            local originalCFrame = rootPart.CFrame
            for _, waypoint in ipairs(waypoints) do
                local x, y, z, m11, m12, m13, m21, m22, m23, m31, m32, m33 = unpack(waypoint)
                rootPart.CFrame = CFrame.new(x, y, z, m11, m12, m13, m21, m22, m23, m31, m32, m33)
                task.wait(0.05)
            end
            rootPart.CFrame = originalCFrame
            WindUI:Notify({ Title = "传送完成", Content = "已遍历所有枪械点位", Duration = 3, Icon = "check" })
        end
    })

    TeleportSection:Button({
        Title = "仅传送单个点位（测试）",
        Desc = "传送到第一个路点",
        Callback = function()
            local character = LocalPlayer.Character
            local rootPart = character and character:FindFirstChild("HumanoidRootPart")
            if not rootPart then return end
            local wp = waypoints[1]
            local x, y, z, m11, m12, m13, m21, m22, m23, m31, m32, m33 = unpack(wp)
            rootPart.CFrame = CFrame.new(x, y, z, m11, m12, m13, m21, m22, m23, m31, m32, m33)
            WindUI:Notify({ Title = "传送", Content = "已传送到第一个点位", Duration = 2, Icon = "map-pin" })
        end
