        Demon = {"EMFLevel5","Handprints","FreezingTemperatures"},
        Specter = {"EMFLevel5","FreezingTemperatures","LaserProjector"},
        Entity = {"SpiritBox","Handprints","LaserProjector"},
        Skinwalker = {"FreezingTemperatures","GhostWriting","SpiritBox"},
        Banshee = {"GhostOrb","Handprints","FreezingTemperatures"},
        Wendigo = {"GhostOrb","GhostWriting","LaserProjector"},
        Nightmare = {"EMFLevel5","SpiritBox","GhostOrb"},
        Leviathan = {"GhostOrb","GhostWriting","Handprints"},
        Oni = {"LaserProjector","SpiritBox","FreezingTemperatures"},
        Umbra = {"GhostOrb","LaserProjector","Handprints"},
        Revenant = {"GhostWriting","EMFLevel5","FreezingTemperatures"}
    }

    local function FetchRoomByPos(pos)
        if not Rooms then return "未知房间" end
        for _,v in Rooms:GetChildren() do
            if v:IsA("Model") and v:FindFirstChild("RoomTrigger") then
                local Trig = v.RoomTrigger
                local Region = Region3.new(Trig.Position-Trig.Size/2,Trig.Position+Trig.Size/2)
                if pos and Region:PointInside(pos) then
                    return v.Name
                end
            end
        end
        return "未知房间"
    end

    local function GetColdRoom()
        if not Rooms then return "未知",0 end
        local ColdName = "未知"
        local TempNum = 99
        for _,v in Rooms:GetChildren() do
            if v:IsA("Model") and v:FindFirstChild("Temperature") then
                local Val = v.Temperature.Value
                if Val < TempNum then
                    TempNum = Val
                    ColdName = v.Name
                end
            end
        end
        return ColdName,TempNum
    end

    local function SearchCursed()
        if not ItemFolder then return nil end
        for _,v in ItemFolder:GetChildren() do
            if v:GetAttribute("IsCursed") then
                return v
            end
        end
        return nil
    end

    local function CreateEsp(Obj,Name,Color,TableStore)
        if not Obj or not Obj.Parent then return end
        for _,a in TableStore do
            if a.Object == Obj then return end
        end
        local Highlight = Instance.new("Highlight")
        Highlight.Adornee = Obj
        Highlight.FillTransparency = 0.8
        Highlight.OutlineColor = Color
        Highlight.FillColor = Color
        Highlight.OutlineTransparency = 0
        Highlight.Parent = Obj
        local Billboard = Instance.new("BillboardGui")
        Billboard.Adornee = Obj
        Billboard.Size = UDim2.new(0,100,0,40)
        Billboard.StudsOffset = Vector3.new(0,3,0)
        Billboard.AlwaysOnTop = true
        Billboard.Parent = Obj
        local Label = Instance.new("TextLabel")
        Label.Size = UDim2.new(1,0,1,0)
        Label.BackgroundTransparency = 1
        Label.Text = Name
        Label.TextColor3 = Color3.new(1,1,1)
        Label.TextScaled = true
        Label.Font = Enum.Font.SourceSansBold
        Label.Parent = Billboard
        local InsertData = {Object = Obj,Highlight = Highlight,Billboard = Billboard,Hue = math.random(0,360)}
        table.insert(TableStore,InsertData)
        table.insert(EspStorage.Main,InsertData)
    end

    local function ClearEsp(Tb)
        for _,v in Tb do
            if v.Highlight and v.Highlight.Parent then v.Highlight:Destroy() end
            if v.Billboard and v.Billboard.Parent then v.Billboard:Destroy() end
        end
        table.clear(Tb)
    end

