    -- ==================== 击杀表情功能 ====================
    local killEmotes = {}
    local isAuraMode = false
    local isSpammingSelectedEmote = false
    local auraDelay = 0.5
    local spamDelay = 0.5
    local selectedEmote = ""
    local selectedKeybind = Enum.KeyCode.G
    local emoteDropdown
    local function useEmote(emoteName)
        local emoteModule = ReplicatedStorage:WaitForChild("Cosmetics"):WaitForChild("KillEmote"):FindFirstChild(emoteName)
        local myRoot = getHumanoidRootPart()
        if not myRoot then return end
        local closestTarget = nil
        local shortestDistance = math.huge
        for _, player in pairs(Players:GetPlayers()) do
            if player ~= LocalPlayer and player.Character then
                local targetRoot = getHumanoidRootPart(player.Character)
                if targetRoot then
                    local distance = (myRoot.Position - targetRoot.Position).Magnitude
                    if distance < shortestDistance then
                        shortestDistance = distance
                        closestTarget = player.Character
                    end
                end
            end
        end
        if closestTarget and emoteModule then
            task.spawn(function()
                _G.KillEmote = true
                pcall(function()
                    if core and core.Get then core.Get("Combat", "Ability").Activate(emoteModule, closestTarget) end
                end)
                _G.KillEmote = false
            end)
        end
    end
    local function useRandomEmote()
        if #killEmotes > 0 then
            local randomEmote = killEmotes[math.random(1, #killEmotes)]
            useEmote(randomEmote)
        end
    end
    task.spawn(function()
        while true do
            if isAuraMode then useRandomEmote(); task.wait(auraDelay) else task.wait(0.1) end
        end
    end)
    task.spawn(function()
        while true do
            if isSpammingSelectedEmote and selectedEmote ~= "" then useEmote(selectedEmote); task.wait(spamDelay) else task.wait(0.1) end
        end
    end)
    UserInputService.InputBegan:Connect(function(input, isGameProcessed)
        if isGameProcessed then return end
        if input.KeyCode == selectedKeybind and selectedEmote ~= "" then useEmote(selectedEmote) end
    end)
    local function createOrUpdateEmoteDropdown(emoteList)
        local values = emoteList
        if not values or #values == 0 then values = {"No emotes found"} end
        emoteDropdown = FeatureTab:Dropdown({
            Title = "击杀表情功能(要靠近别人)",
            Values = values,
            Multi = false,
            AllowNone = false,
            Callback = function(option)
                if option ~= "No emotes found" then selectedEmote = option; useEmote(option) end
            end
        })
    end
    FeatureTab:Button({
