            createOrUpdateEmoteDropdown(killEmotes)
        end
    })
    for _, emote in pairs(ReplicatedStorage:WaitForChild("Cosmetics"):WaitForChild("KillEmote"):GetChildren()) do
        table.insert(killEmotes, emote.Name)
    end
    createOrUpdateEmoteDropdown(killEmotes)
    FeatureTab:Toggle({
