-- ========== 自瞄+透视功能加载 ==========
local aimEspLoaded = false
local function loadAimEspFeatures()
    if aimEspLoaded then
        WindUI:Notify({ Title = "提示", Content = "功能已加载", Duration = 3, Icon = "info" })
        return
    end
    aimEspLoaded = true

    -- 创建两个标签页
    local AimTab = Window:Tab({ Title = "功能", Icon = "target" })
    local ESPTab = Window:Tab({ Title = "透视", Icon = "eye" })

    -- ==================== 自瞄系统 ====================
    local AimLockSystem = {}
    local Players = game:GetService("Players")
    local RunService = game:GetService("RunService")
    local UserInputService = game:GetService("UserInputService")
    local Workspace = game:GetService("Workspace")
    local Camera = Workspace.CurrentCamera
    local LocalPlayer = Players.LocalPlayer

    AimLockSystem.Config = {
        enabled = false,
        smoothAim = false,
        aimType = "最近玩家",
        aimPart = "头部",
        fovEnabled = false,
        showFov = false,
        fovSize = 100,
        fovColor = Color3.fromRGB(255, 255, 255),
        fovLockDistance = 1000,
        nearestPlayerDistance = 1000,
        nearestMouseDistance = 500,
        wallCheckEnabled = true,
        lerpAlpha = 0.4,
        aimlockOffsetX = 0,
        aimlockOffsetY = 0,
        ignoredPlayers = {},
        prioritizedPlayers = {},
        aimlockCertainPlayer = false,
        selectedPlayer = nil,
        rainbowFov = false,
        fovStrokeThickness = 2,
        fovGui = nil,
        fovFrame = nil,
        fovStroke = nil,
        teamCheckEnabled = false,
    }

    AimLockSystem.State = {
        isAimingLocked = false,
        aimlockConnection = nil
    }

    function AimLockSystem.GetLocalHRP()
        if not LocalPlayer.Character then return nil end
        return LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
    end

    function AimLockSystem.IsPlayerIgnored(player)
        return AimLockSystem.Config.ignoredPlayers[player.Name] == true
    end

    function AimLockSystem.GetAimPartPosition(targetPlayer)
        if not targetPlayer or not targetPlayer.Character then return nil end
        local part = nil
        if AimLockSystem.Config.aimPart == "头部" then
            part = targetPlayer.Character:FindFirstChild("Head")
        elseif AimLockSystem.Config.aimPart == "躯干" then
            part = targetPlayer.Character:FindFirstChild("UpperTorso") or targetPlayer.Character:FindFirstChild("Torso")
        elseif AimLockSystem.Config.aimPart == "脚部" then
            local hrp = targetPlayer.Character:FindFirstChild("HumanoidRootPart")
            if hrp then
                return hrp.Position + Vector3.new(0, -3, 0)
            end
        end
        return part and part.Position or nil
    end

    function AimLockSystem.GetPriorityScore(player)
        if not player.Character or not player.Character:FindFirstChild("HumanoidRootPart") then 
            return math.huge 
        end
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then return math.huge end
        if player == LocalPlayer then return math.huge end
        if AimLockSystem.IsPlayerIgnored(player) then return math.huge end

        if AimLockSystem.Config.teamCheckEnabled then
            local localTeam = LocalPlayer.Team
            local playerTeam = player.Team
            if localTeam and playerTeam and localTeam == playerTeam then
                return math.huge
            end
        end

        local hrp = player.Character.HumanoidRootPart
        if AimLockSystem.Config.fovEnabled then
            local screenPos, onScreen = Camera:WorldToViewportPoint(hrp.Position)
            if not onScreen then return math.huge end
            local center = Vector2.new(Camera.ViewportSize.X/2, Camera.ViewportSize.Y/2)
            local distFromCenter = (Vector2.new(screenPos.X, screenPos.Y) - center).Magnitude
            if distFromCenter > AimLockSystem.Config.fovSize/2 then return math.huge end
            if (localHRP.Position - hrp.Position).Magnitude > AimLockSystem.Config.fovLockDistance then 
                return math.huge 
            end
        end

        if AimLockSystem.Config.wallCheckEnabled then
            local head = player.Character:FindFirstChild("Head")
            if head then
                local origin = localHRP.Parent:FindFirstChild("Head") and localHRP.Parent.Head.Position or localHRP.Position
                local direction = head.Position - origin
                local rayParams = RaycastParams.new()
                rayParams.FilterDescendantsInstances = {LocalPlayer.Character}
                rayParams.FilterType = Enum.RaycastFilterType.Exclude
                local result = Workspace:Raycast(origin, direction, rayParams)
                if result and not result.Instance:IsDescendantOf(player.Character) then
                    return math.huge
                end
            end
        end

        if AimLockSystem.Config.aimType == "最近玩家" then
            return (localHRP.Position - hrp.Position).Magnitude
        else
            local mousePos = UserInputService:GetMouseLocation()
            local screenPos = Camera:WorldToViewportPoint(hrp.Position)
            return (Vector2.new(screenPos.X, screenPos.Y) - mousePos).Magnitude
        end
    end

    function AimLockSystem.GetClosestPlayer()
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then return nil end

        local bestPlayer, bestScore = nil, math.huge
        for _, player in ipairs(AimLockSystem.Config.prioritizedPlayers) do
            local score = AimLockSystem.GetPriorityScore(player)
            if score < bestScore then
                bestScore = score
                bestPlayer = player
            end
        end
        if bestPlayer then return bestPlayer end

        for _, player in ipairs(Players:GetPlayers()) do
            if table.find(AimLockSystem.Config.prioritizedPlayers, player) then continue end
            local score = AimLockSystem.GetPriorityScore(player)
            if score < bestScore then
                bestScore = score
                bestPlayer = player
            end
        end
        return bestPlayer
    end

    function AimLockSystem.UpdateAimlock()
        local localHRP = AimLockSystem.GetLocalHRP()
        if not localHRP then 
            AimLockSystem.State.isAimingLocked = false
            return 
        end

        local targetPlayer = nil
        if AimLockSystem.Config.aimlockCertainPlayer then
            targetPlayer = AimLockSystem.Config.selectedPlayer
        else
            targetPlayer = AimLockSystem.GetClosestPlayer()
        end

        if targetPlayer then
            AimLockSystem.State.isAimingLocked = true
            local targetPosition = AimLockSystem.GetAimPartPosition(targetPlayer)
            if targetPosition then
                targetPosition = targetPosition + Vector3.new(
                    AimLockSystem.Config.aimlockOffsetX,
                    AimLockSystem.Config.aimlockOffsetY,
                    0
                )
                local lookDirection = (targetPosition - Camera.CFrame.Position).Unit
                if AimLockSystem.Config.smoothAim then
                    local targetCFrame = CFrame.lookAt(Camera.CFrame.Position, Camera.CFrame.Position + lookDirection)
                    Camera.CFrame = Camera.CFrame:Lerp(targetCFrame, AimLockSystem.Config.lerpAlpha)
                else
                    Camera.CFrame = CFrame.lookAt(Camera.CFrame.Position, Camera.CFrame.Position + lookDirection)
                end
            end
        else
            AimLockSystem.State.isAimingLocked = false
        end
    end

    function AimLockSystem.UpdateFOVCircle()
        if not AimLockSystem.Config.showFov then
            if AimLockSystem.Config.fovFrame then
                AimLockSystem.Config.fovFrame.Visible = false
            end
            return
        end

        if not AimLockSystem.Config.fovGui then
            AimLockSystem.Config.fovGui = Instance.new("ScreenGui")
            AimLockSystem.Config.fovGui.Name = "AimFOVCircle"
            AimLockSystem.Config.fovGui.IgnoreGuiInset = true
            AimLockSystem.Config.fovGui.Parent = game:GetService("CoreGui")

            AimLockSystem.Config.fovFrame = Instance.new("Frame")
            AimLockSystem.Config.fovFrame.Name = "Circle"
            AimLockSystem.Config.fovFrame.AnchorPoint = Vector2.new(0.5, 0.5)
            AimLockSystem.Config.fovFrame.Position = UDim2.new(0.5, 0, 0.5, 0)
            AimLockSystem.Config.fovFrame.BackgroundTransparency = 1
            AimLockSystem.Config.fovFrame.BorderSizePixel = 0
            AimLockSystem.Config.fovFrame.Parent = AimLockSystem.Config.fovGui

            local corner = Instance.new("UICorner")
            corner.CornerRadius = UDim.new(1, 0)
            corner.Parent = AimLockSystem.Config.fovFrame

            AimLockSystem.Config.fovStroke = Instance.new("UIStroke")
            AimLockSystem.Config.fovStroke.Thickness = AimLockSystem.Config.fovStrokeThickness
            AimLockSystem.Config.fovStroke.Parent = AimLockSystem.Config.fovFrame
        end

        local color = AimLockSystem.Config.fovColor
        if AimLockSystem.State.isAimingLocked then
            color = Color3.fromRGB(0, 255, 0)
        elseif AimLockSystem.Config.rainbowFov then
            color = Color3.fromHSV(tick() % 1, 1, 1)
        end
        AimLockSystem.Config.fovStroke.Color = color
        AimLockSystem.Config.fovFrame.Size = UDim2.new(0, AimLockSystem.Config.fovSize, 0, AimLockSystem.Config.fovSize)
        AimLockSystem.Config.fovFrame.Visible = true
    end

    function AimLockSystem.ToggleAimlock(enabled)
        AimLockSystem.Config.enabled = enabled
        if enabled then
            if not AimLockSystem.State.aimlockConnection then
                AimLockSystem.State.aimlockConnection = RunService.RenderStepped:Connect(function()
                    AimLockSystem.UpdateAimlock()
                    AimLockSystem.UpdateFOVCircle()
                end)
            end
            WindUI:Notify({ Title = "静默自瞄", Content = "已开启", Icon = "target", Duration = 3 })
        else
            if AimLockSystem.State.aimlockConnection then
                AimLockSystem.State.aimlockConnection:Disconnect()
                AimLockSystem.State.aimlockConnection = nil
            end
            AimLockSystem.State.isAimingLocked = false
            if AimLockSystem.Config.fovFrame then
                AimLockSystem.Config.fovFrame.Visible = false
            end
            WindUI:Notify({ Title = "静默自瞄", Content = "已关闭", Icon = "x-circle", Duration = 3 })
        end
    end

    -- ==================== 自瞄 UI ====================
    local AimSection = AimTab:Section({ Title = "自瞄设置", Opened = true })

    AimSection:Toggle({ Title = "启用自瞄", Value = false, Callback = function(v) AimLockSystem.ToggleAimlock(v) end })
    AimSection:Toggle({ Title = "平滑瞄准", Value = false, Callback = function(v) AimLockSystem.Config.smoothAim = v end })
    AimSection:Toggle({ Title = "启用FOV检测", Value = false, Callback = function(v) AimLockSystem.Config.fovEnabled = v end })
    AimSection:Toggle({ Title = "显示FOV圆圈", Value = false, Callback = function(v) AimLockSystem.Config.showFov = v end })
    AimSection:Slider({ Title = "FOV大小", Value = { Min = 50, Max = 500, Default = 100 }, Callback = function(v) AimLockSystem.Config.fovSize = v end })
    AimSection:Slider({ Title = "平滑度", Value = { Min = 0.1, Max = 1, Default = 0.4 }, Callback = function(v) AimLockSystem.Config.lerpAlpha = v end })
    AimSection:Slider({ Title = "最大距离", Value = { Min = 100, Max = 5000, Default = 1000 }, Callback = function(v) AimLockSystem.Config.fovLockDistance = v end })
    AimSection:Dropdown({ Title = "瞄准类型", Values = { "最近玩家", "鼠标最近" }, Value = "最近玩家", Callback = function(v) AimLockSystem.Config.aimType = v end })
    AimSection:Dropdown({ Title = "瞄准部位", Values = { "头部", "躯干", "脚部" }, Value = "头部", Callback = function(v) AimLockSystem.Config.aimPart = v end })
    AimSection:Toggle({ Title = "掩体检测", Value = true, Callback = function(v) AimLockSystem.Config.wallCheckEnabled = v end })
    AimSection:Toggle({ Title = "队伍检测", Value = false, Callback = function(v) AimLockSystem.Config.teamCheckEnabled = v end })

    local playerList = {}
    local function updatePlayerList()
        playerList = { "全部" }
        for _, player in ipairs(Players:GetPlayers()) do
            if player ~= LocalPlayer then table.insert(playerList, player.Name) end
        end
    end
    updatePlayerList()

    local targetDropdown = AimSection:Dropdown({
        Title = "锁定指定玩家",
        Values = playerList,
        Value = "全部",
        Callback = function(v)
            if v == "全部" then
                AimLockSystem.Config.aimlockCertainPlayer = false
                AimLockSystem.Config.selectedPlayer = nil
            else
                for _, player in ipairs(Players:GetPlayers()) do
                    if player.Name == v then
                        AimLockSystem.Config.aimlockCertainPlayer = true
                        AimLockSystem.Config.selectedPlayer = player
                        break
                    end
                end
            end
        end
    })

    AimSection:Button({ Title = "刷新玩家列表", Callback = function() updatePlayerList(); targetDropdown:Refresh(playerList) end })
    AimSection:Colorpicker({ Title = "FOV颜色", Default = Color3.fromRGB(255,255,255), Callback = function(v) AimLockSystem.Config.fovColor = v end })
    AimSection:Toggle({ Title = "彩虹FOV", Value = false, Callback = function(v) AimLockSystem.Config.rainbowFov = v end })
    AimSection:Slider({ Title = "水平偏移", Value = { Min = -50, Max = 50, Default = 0 }, Callback = function(v) AimLockSystem.Config.aimlockOffsetX = v end })
    AimSection:Slider({ Title = "垂直偏移", Value = { Min = -50, Max = 50, Default = 0 }, Callback = function(v) AimLockSystem.Config.aimlockOffsetY = v end })

    -- ==================== 透视功能 ====================
    ESPTab:Toggle({
        Title = "透视",
        Desc = "启用透视功能",
        Default = false,
        Callback = function(state)
            if state then
                local FillColor = Color3.fromRGB(255, 0, 0)
                local DepthMode = "AlwaysOnTop"
                local FillTransparency = 0.5
                local OutlineColor = Color3.fromRGB(255,255,255)
                local OutlineTransparency = 0

                local CoreGui = game:GetService("CoreGui")
                local Players = game:GetService("Players")
                local connections = {}
                
                local Storage = Instance.new("Folder")
                Storage.Parent = CoreGui
                Storage.Name = "AimEsp_Highlight_Storage"

                local function Highlight(plr)
                    if not Storage or not Storage.Parent then return end
                    
                    local Highlight = Instance.new("Highlight")
                    Highlight.Name = plr.Name
                    Highlight.FillColor = FillColor
                    Highlight.DepthMode = DepthMode
                    Highlight.FillTransparency = FillTransparency
                    Highlight.OutlineColor = OutlineColor
                    Highlight.OutlineTransparency = 0
                    Highlight.Parent = Storage
                    
                    local plrchar = plr.Character
                    if plrchar then
                        Highlight.Adornee = plrchar
                    end

                    connections[plr] = plr.CharacterAdded:Connect(function(char)
                        if Highlight and Highlight.Parent then
                            Highlight.Adornee = char
                        end
                    end)
                end

                connections.playerAdded = Players.PlayerAdded:Connect(Highlight)
                
                for _, v in pairs(Players:GetPlayers()) do
                    if v ~= LocalPlayer then
                        Highlight(v)
                    end
                end

                connections.playerRemoving = Players.PlayerRemoving:Connect(function(plr)
                    if Storage and Storage.Parent then
                        local plrname = plr.Name
                        if Storage[plrname] then
                            Storage[plrname]:Destroy()
                        end
                    end
                    if connections[plr] then
                        connections[plr]:Disconnect()
                        connections[plr] = nil
                    end
                end)
                
                Storage:SetAttribute("Connections", connections)
            else
                local CoreGui = game:GetService("CoreGui")
                local Storage = CoreGui:FindFirstChild("AimEsp_Highlight_Storage")
                if Storage then
                    local connections = Storage:GetAttribute("Connections")
                    if connections then
                        for _, connection in pairs(connections) do
                            if connection and typeof(connection) == "RBXScriptConnection" then
                                connection:Disconnect()
                            end
                        end
                    end
                    Storage:Destroy()
                end
            end
        end
    })

    WindUI:Notify({ Title = "海战", Content = "功能已加载", Duration = 3, Icon = "check" })
end

-- ========== 悔/真无悔功能加载 ==========
local huiLoaded = false
local function loadHuiFeatures()
    if huiLoaded then
        WindUI:Notify({ Title = "提示", Content = "功能已加载", Duration = 3, Icon = "info" })
        return
    end
    huiLoaded = true

    -- 创建两个标签页（主要、娱乐）
    local MainTab = Window:Tab({ Title = "主要", Icon = "home" })
    local FunTab = Window:Tab({ Title = "娱乐", Icon = "gamepad" })

    -- ==================== 主要功能 ====================
    MainTab:Section({ Title = "实用功能" })

    local player = game.Players.LocalPlayer
    local replicatedStorage = game:GetService("ReplicatedStorage")

    -- 水上走路
    local waterEnabled = false
    local waterConnection = nil
    local function isWater(part)
        return part:IsA("BasePart") and (
            part.Material == Enum.Material.Water or
            part.Name:lower():find("water") or
            part:GetAttribute("Water") == true
        )
    end
    local function setWaterSolid(part, solid)
        if isWater(part) then
            part.CanCollide = solid
        end
    end
    local function enableWaterWalk()
        for _, obj in ipairs(workspace:GetDescendants()) do
            setWaterSolid(obj, true)
        end
        waterConnection = workspace.DescendantAdded:Connect(function(obj)
            setWaterSolid(obj, true)
        end)
    end
    local function disableWaterWalk()
        if waterConnection then
            waterConnection:Disconnect()
            waterConnection = nil
        end
        for _, obj in ipairs(workspace:GetDescendants()) do
            setWaterSolid(obj, false)
        end
    end
    MainTab:Toggle({
        Title = "水上走路",
        Icon = "droplet",
        Value = false,
        Callback = function(state)
            if state then enableWaterWalk() else disableWaterWalk() end
            waterEnabled = state
        end
    })

    -- 无跌落伤害
    local noFallEnabled = false
    local fallDamageHandler = nil
    local originalGetFallDamageHeights = nil
    local fallCharacterConnection = nil
    local function enableNoFall()
        local success, handler = pcall(function()
            return require(player:WaitForChild("PlayerScripts"):WaitForChild("AnimalGameFramework"):WaitForChild("FallDamageHandler"))
        end)
        if success then
            fallDamageHandler = handler
            originalGetFallDamageHeights = fallDamageHandler._getFallDamageHeights
            fallDamageHandler._getFallDamageHeights = function() return 999999, 999999 end
            fallCharacterConnection = player.CharacterAdded:Connect(function(char)
                task.wait(1)
                if fallDamageHandler and noFallEnabled then
                    fallDamageHandler._getFallDamageHeights = function() return 999999, 999999 end
                end
            end)
        end
    end
    local function disableNoFall()
        if fallCharacterConnection then fallCharacterConnection:Disconnect(); fallCharacterConnection = nil end
        if fallDamageHandler and originalGetFallDamageHeights then
            fallDamageHandler._getFallDamageHeights = originalGetFallDamageHeights
        end
    end
    MainTab:Toggle({
        Title = "无跌落伤害",
        Icon = "shield",
        Value = false,
        Callback = function(state)
            if state then enableNoFall() else disableNoFall() end
            noFallEnabled = state
        end
    })

    -- 无限耐力
    local infiniteStaminaEnabled = false
    local staminaHandler = nil
    local originalStaminaCleanup = nil
    local staminaCharacterConnection = nil
    local function enableInfiniteStamina()
        local playerScripts = player:WaitForChild("PlayerScripts")
        local staminaHandlerModule = playerScripts:WaitForChild("AnimalGameFramework"):WaitForChild("StatsHandler"):WaitForChild("StaminaHandler")
        staminaHandler = require(staminaHandlerModule)
        originalStaminaCleanup = staminaHandler.Cleanup
        staminaHandler.Cleanup = function()
            staminaHandler._loopEnabled = false
            if originalStaminaCleanup then originalStaminaCleanup() end
        end
        local function setupStamina(character)
            staminaHandler._loopEnabled = true
            task.spawn(function()
                while staminaHandler._loopEnabled do
                    task.wait(0.1)
                    if character and character.Parent then
                        character:SetAttribute("Stamina", 100)
                    else break end
                end
            end)
        end
        if player.Character then setupStamina(player.Character) end
        staminaCharacterConnection = player.CharacterAdded:Connect(setupStamina)
    end
    local function disableInfiniteStamina()
        if staminaCharacterConnection then staminaCharacterConnection:Disconnect(); staminaCharacterConnection = nil end
        if staminaHandler then
            staminaHandler.Cleanup()
            staminaHandler.Cleanup = originalStaminaCleanup
        end
    end
    MainTab:Toggle({
        Title = "无限耐力",
        Icon = "zap",
        Value = false,
        Callback = function(state)
            infiniteStaminaEnabled = state
            if state then enableInfiniteStamina() else disableInfiniteStamina() end
        end
    })

    -- 杀戮光环
    local killAuraEnabled = false
    local killAuraLoop = nil
    local function enableKillAura()
        local attackEvents = {
            replicatedStorage:FindFirstChild("TrampleDamageHandlerRemoteEvent"),
            replicatedStorage:FindFirstChild("SpecialAttackRemoteEvent_ChargedAttack"),
            replicatedStorage:FindFirstChild("SpecialAttackRemoteEvent_PounceAttack"),
            replicatedStorage:FindFirstChild("SpecialAttackRemoteEvent_RegularAttack"),
            replicatedStorage:FindFirstChild("AttackHandlerRemoteEvent"),
        }
        local validEvents = {}
        for _, event in ipairs(attackEvents) do
            if event then table.insert(validEvents, event) end
        end
        if #validEvents == 0 then
            warn("未找到任何攻击远程事件，杀戮光环无法启动")
            return
        end
        local function getNearbyTargets(radius)
            local myChar = player.Character
            if not myChar then return {} end
            local myRoot = myChar:FindFirstChild("HumanoidRootPart")
            if not myRoot then return {} end
            local myPos = myRoot.Position
            local targets = {}
            for _, otherPlayer in ipairs(game.Players:GetPlayers()) do
                if otherPlayer ~= player then
                    local otherChar = otherPlayer.Character
                    if otherChar then
                        local otherRoot = otherChar:FindFirstChild("HumanoidRootPart")
                        if otherRoot then
                            local dist = (myPos - otherRoot.Position).Magnitude
                            if dist <= radius then
                                local humanoid = otherChar:FindFirstChildOfClass("Humanoid")
                                if humanoid and humanoid.Health > 0 then
                                    table.insert(targets, {char = otherChar, hum = humanoid})
                                end
                            end
                        end
                    end
                end
            end
            return targets
        end
        local function damageTarget(target)
            for _, event in ipairs(validEvents) do
                pcall(function()
                    if event.Name == "TrampleDamageHandlerRemoteEvent" then
                        event:FireServer(player.Character, target.char)
                    elseif event.Name == "SpecialAttackRemoteEvent_ChargedAttack" then
                        event:FireServer(target.hum, 1)
                    elseif event.Name == "SpecialAttackRemoteEvent_PounceAttack" then
                        local hitPart = target.char:FindFirstChild("Head") or target.char:FindFirstChild("HumanoidRootPart")
                        event:FireServer(target.hum, hitPart)
                    elseif event.Name == "SpecialAttackRemoteEvent_RegularAttack" then
                        event:FireServer(target.hum)
                    elseif event.Name == "AttackHandlerRemoteEvent" then
                        event:FireServer(target.hum)
                    else
                        event:FireServer(target.hum, player.Character)
                    end
                end)
            end
        end
        killAuraLoop = task.spawn(function()
            while killAuraEnabled do
                task.wait(0.2)
                if not player.Character then continue end
                local targets = getNearbyTargets(50)
                for _, target in ipairs(targets) do
                    damageTarget(target)
                end
            end
        end)
    end
    local function disableKillAura()
        if killAuraLoop then task.cancel(killAuraLoop); killAuraLoop = nil end
    end
    MainTab:Toggle({
        Title = "杀戮光环(不要对多个目标开要不然会被踢)",
        Icon = "sword",
        Value = false,
        Callback = function(state)
            killAuraEnabled = state
            if state then enableKillAura() else disableKillAura() end
        end
    })

    -- 反黑夜
    local antiNightEnabled = false
    local antiNightLoop = nil
    local function enableAntiNight()
        local lighting = game:GetService("Lighting")
        local darkenModule = require(player.PlayerScripts.AnimalGameFramework.DarkenNightEffect)
        darkenModule.Setup = function() darkenModule._targetBrightnessReduction = 0 end
        antiNightLoop = task.spawn(function()
            while antiNightEnabled do
                task.wait(0.01)
                local cc = lighting:FindFirstChild("MakeNightDarkerColorCorrection")
                if cc then cc.Brightness = 0 end
            end
        end)
    end
    local function disableAntiNight()
        if antiNightLoop then task.cancel(antiNightLoop); antiNightLoop = nil end
    end
    MainTab:Toggle({
        Title = "反黑夜",
        Icon = "sun",
        Value = false,
        Callback = function(state)
            antiNightEnabled = state
            if state then enableAntiNight() else disableAntiNight() end
        end
    })

    -- 无限氧气
    local infiniteOxygenEnabled = false
    local oxygenConnection = nil
    local function setupOxygen(character)
        if not character then return end
        task.spawn(function()
            while infiniteOxygenEnabled and character.Parent do
                task.wait(0.2)
                character:SetAttribute("Oxygen", 100)
            end
        end)
    end
    MainTab:Toggle({
        Title = "无限氧气",
        Icon = "droplet",
        Value = false,
        Callback = function(state)
            infiniteOxygenEnabled = state
            if state then
                if player.Character then setupOxygen(player.Character) end
                if oxygenConnection then oxygenConnection:Disconnect() end
                oxygenConnection = player.CharacterAdded:Connect(setupOxygen)
            else
                if oxygenConnection then oxygenConnection:Disconnect(); oxygenConnection = nil end
            end
        end
    })

    -- ==================== 娱乐功能 ====================
    FunTab:Section({ Title = "娱乐功能" })
    FunTab:Button({
        Title = "秒成长",
        Icon = "zap",
        Callback = function()
            local char = player.Character
            if char then char:SetAttribute("GrowthPercentage", 100) end
            player.CharacterAdded:Connect(function(newChar)
                newChar:SetAttribute("GrowthPercentage", 100)
            end)
        end
    })

    WindUI:Notify({ Title = "萨凡纳", Content = "功能已加载", Duration = 3, Icon = "check" })
end
-- ========== 普通血色娃娃格斗功能加载 ==========

-- ========== 普通血色娃娃格斗功能加载（修复版） ==========
local fightLoaded = false
local function loadFightFeatures()
    if fightLoaded then
        WindUI:Notify({ Title = "提示", Content = "功能已加载", Duration = 3, Icon = "info" })
        return
    end
    fightLoaded = true

    -- 获取服务
    local Players = game:GetService("Players")
    local LocalPlayer = Players.LocalPlayer
    local RunService = game:GetService("RunService")
    local ReplicatedStorage = game:GetService("ReplicatedStorage")

    -- 安全获取 Assets 文件夹（添加超时保护，避免无限 yield）
    local AssetsFolder = nil
    local success, err = pcall(function()
        AssetsFolder = ReplicatedStorage:WaitForChild("Assets", 2)
    end)
    if not success or not AssetsFolder then
        warn("未找到 Assets 文件夹，杀戮光环功能将不可用")
        WindUI:Notify({
            Title = "警告",
            Content = "未找到游戏资源路径，杀戮光环无法启动",
            Duration = 5,
            Icon = "alert-circle"
        })
    end

    local PlaySoundRemote = nil
    local MeleeHitRemote = nil
    if AssetsFolder and AssetsFolder:FindFirstChild("Remotes") then
        PlaySoundRemote = AssetsFolder.Remotes:FindFirstChild("PlaySound")
        MeleeHitRemote = AssetsFolder.Remotes:FindFirstChild("meleeHit")
    end

    local function getCharacter(player)
        return player.Character
    end

    local function getTorso(character)
        return character:FindFirstChild("Torso") or character:FindFirstChild("UpperTorso")
    end

    local function getHumanoid(character)
        return character:FindFirstChild("Humanoid")
    end

    local function getCurrentWeapon()
        local char = LocalPlayer.Character
        if not char then return nil end
        local tool = char:FindFirstChildOfClass("Tool")
        if tool then return tool end
        for _, child in ipairs(char:GetChildren()) do
            if child:IsA("Model") and child:FindFirstChild("Handle") then
                return child
            end
        end
        return nil
    end

    local lastAttackTime = {}
    local currentRadius = 20
    local currentInterval = 0.5
    local auraEnabled = false
    local auraConnection = nil

    local function auraLoop()
        if not PlaySoundRemote or not MeleeHitRemote then
            warn("缺少远程事件，杀戮光环停止")
            return
        end
        while auraEnabled do
            local localChar = LocalPlayer.Character
            if localChar and localChar.Parent then
                local weapon = getCurrentWeapon()
                if weapon then
                    local rootPart = localChar:FindFirstChild("HumanoidRootPart") or localChar:FindFirstChild("Torso")
                    if rootPart then
                        local now = tick()
                        for _, player in ipairs(Players:GetPlayers()) do
                            if player ~= LocalPlayer then
                                local targetChar = getCharacter(player)
                                if targetChar and targetChar.Parent then
                                    local targetTorso = getTorso(targetChar)
                                    local targetHumanoid = getHumanoid(targetChar)
                                    if targetTorso and targetHumanoid and targetHumanoid.Health > 0 then
                                        local distance = (rootPart.Position - targetTorso.Position).Magnitude
                                        if distance <= currentRadius then
                                            local last = lastAttackTime[player] or 0
                                            if now - last >= currentInterval then
                                                lastAttackTime[player] = now
                                                pcall(function()
                                                    local soundArgs = { weapon, targetTorso, { pitch = 1.016, type = "hit" }, true }
                                                    PlaySoundRemote:FireServer(unpack(soundArgs))
                                                    local hitArgs = { weapon, targetHumanoid, 1 }
                                                    MeleeHitRemote:FireServer(unpack(hitArgs))
                                                end)
                                            end
                                        end
                                    end
                                end
                            end
                        end
                    end
                end
            end
            task.wait()
        end
    end

    local function startAura()
        if not PlaySoundRemote or not MeleeHitRemote then
            WindUI:Notify({
                Title = "错误",
                Content = "杀戮光环所需资源缺失，无法启动",
                Duration = 3,
                Icon = "x"
            })
            return
        end
        if auraConnection then return end
        auraEnabled = true
        auraConnection = task.spawn(auraLoop)
    end

    local function stopAura()
        auraEnabled = false
        if auraConnection then
            coroutine.close(auraConnection)
            auraConnection = nil
        end
    end

    -- 创建标签页（使用独特变量名，避免冲突）
    local FightMainTab = Window:Tab({ Title = "主要", Icon = "sword" })
    local FightEspTab = Window:Tab({ Title = "ESP", Icon = "eye" })

    FightMainTab:Section({ Title = "杀戮光环" })

    FightMainTab:Toggle({
        Title = "启用光环",
        Icon = "target",
        Value = false,
        Callback = function(state)
            if state then startAura() else stopAura() end
        end
    })

    FightMainTab:Slider({
        Title = "光环范围 (studs)",
        Value = { Min = 5, Max = 50, Default = 20 },
        Callback = function(value) currentRadius = value end
    })

    FightMainTab:Slider({
        Title = "攻击间隔 (秒)",
        Value = { Min = 0.1, Max = 2, Default = 0.5, Decimal = 2 },
        Callback = function(value) currentInterval = value end
    })

    -- ESP功能
    local espEnabled = false
    local espData = {}
    local currentHighlightColor = Color3.fromRGB(255, 0, 0)

    local function createESPForPlayer(player)
        if player == LocalPlayer then return end
        if espData[player] then return end
        
        local function onCharacterAdded(character)
            if not espEnabled then return end
            if espData[player] and espData[player].highlight then
                espData[player].highlight:Destroy()
                espData[player].highlight = nil
            end
            if espData[player] and espData[player].billboard then
                espData[player].billboard:Destroy()
                espData[player].billboard = nil
            end
            
            local humanoid = character:WaitForChild("Humanoid", 5)
            if not humanoid then return end
            
            local highlight = Instance.new("Highlight")
            highlight.FillColor = currentHighlightColor
            highlight.FillTransparency = 0.5
            highlight.OutlineTransparency = 0
            highlight.Adornee = character
            highlight.Parent = character
            
            local head = character:FindFirstChild("Head") or character:FindFirstChild("HumanoidRootPart")
            if not head then return end
            
            local billboard = Instance.new("BillboardGui")
            billboard.Size = UDim2.new(0, 200, 0, 50)
            billboard.StudsOffset = Vector3.new(0, 2.5, 0)
            billboard.AlwaysOnTop = true
            billboard.Parent = head
            
            local nameLabel = Instance.new("TextLabel")
            nameLabel.Size = UDim2.new(1, 0, 0.5, 0)
            nameLabel.BackgroundTransparency = 1
            nameLabel.TextColor3 = Color3.fromRGB(255, 255, 255)
            nameLabel.TextStrokeTransparency = 0
            nameLabel.TextStrokeColor3 = Color3.fromRGB(0, 0, 0)
            nameLabel.Font = Enum.Font.GothamBold
            nameLabel.TextSize = 14
            nameLabel.Text = player.Name
            nameLabel.Parent = billboard
            
            local healthLabel = Instance.new("TextLabel")
            healthLabel.Size = UDim2.new(1, 0, 0.5, 0)
            healthLabel.Position = UDim2.new(0, 0, 0.5, 0)
            healthLabel.BackgroundTransparency = 1
            healthLabel.TextColor3 = Color3.fromRGB(255, 100, 100)
            healthLabel.TextStrokeTransparency = 0
            healthLabel.TextStrokeColor3 = Color3.fromRGB(0, 0, 0)
            healthLabel.Font = Enum.Font.Gotham
            healthLabel.TextSize = 12
            healthLabel.Text = "血量 " .. math.floor(humanoid.Health)
            healthLabel.Parent = billboard
            
            local function updateHealth()
                if humanoid and humanoid.Parent then
                    healthLabel.Text = "血量 " .. math.floor(humanoid.Health)
                end
            end
            humanoid.HealthChanged:Connect(updateHealth)
            
            espData[player] = {
                highlight = highlight,
                billboard = billboard,
                healthConnection = humanoid.HealthChanged:Connect(updateHealth)
            }
        end
        
        if player.Character then
            onCharacterAdded(player.Character)
        end
        player.CharacterAdded:Connect(onCharacterAdded)
    end

    local function removeESPForPlayer(player)
        local data = espData[player]
        if data then
            if data.highlight then data.highlight:Destroy() end
            if data.billboard then data.billboard:Destroy() end
            if data.healthConnection then data.healthConnection:Disconnect() end
            espData[player] = nil
        end
    end

    local function enableESP()
        espEnabled = true
        for _, player in ipairs(Players:GetPlayers()) do
            createESPForPlayer(player)
        end
        Players.PlayerAdded:Connect(createESPForPlayer)
        Players.PlayerRemoving:Connect(removeESPForPlayer)
    end

    local function disableESP()
        espEnabled = false
        for player, _ in pairs(espData) do
            removeESPForPlayer(player)
        end
    end

    FightEspTab:Section({ Title = "视觉设置" })

    FightEspTab:Toggle({
        Title = "启用 ESP",
        Icon = "binoculars",
        Value = true,
        Callback = function(state)
            if state then enableESP() else disableESP() end
        end
    })

    FightEspTab:Colorpicker({
        Title = "高光颜色",
        Value = Color3.fromRGB(255, 0, 0),
        Callback = function(color)
            currentHighlightColor = color
            for player, data in pairs(espData) do
                if data.highlight then
                    data.highlight.FillColor = color
                end
            end
        end
    })

    WindUI:Notify({ Title = "普通血色娃娃格斗", Content = "功能已加载", Duration = 3, Icon = "check" })
end

-- ========== 种植花园功能加载 ==========
local plantingLoaded = false
local function loadPlantingFeatures()
    if plantingLoaded then
        WindUI:Notify({ Title = "提示", Content = "种植花园功能已加载", Duration = 3, Icon = "info" })
        return
    end
    plantingLoaded = true

    -- 获取必要对象
    local Players = game:GetService("Players")
    local a = Players.LocalPlayer
    local b = a.Character or a.CharacterAdded:Wait()
    local c = game:GetService("ReplicatedStorage")

    -- 修改运气值（全局生效）
    pcall(function()
        hookfunction(require(c.Modules.PlayerLuck).GetLuck, function() return math.huge end)
        hookfunction(require(c.Modules.PlayerLuck).GetModifiers, function()
            return { { Name = "Fake_Luck", Modifier = math.huge } }
        end)
        for _, v in ipairs(require(c.Data.SessionTimeLuckData).Timer) do
            if v.Luck then v.Luck = math.huge end
        end
        hookfunction(require(c.Modules.SessionTimeLuckController).GetCurrentLuck, function() return math.huge end)
    end)

    -- 控制开关
    local sbns = { c = false, s = false, p = false }

    -- 获取种子列表
    local function getSeeds()
        local seeds = {}
        local seedShop = a.PlayerGui:FindFirstChild("Seed_Shop")
        if seedShop and seedShop.Frame and seedShop.Frame.ScrollingFrame then
            for _, v in ipairs(seedShop.Frame.ScrollingFrame:GetChildren()) do
                if v:IsA("Frame") and not v.Name:find("Padding") then
                    table.insert(seeds, v.Name)
                end
            end
        end
        return seeds
    end

    -- 获取工具列表
    local function getGear()
        local gear = {}
        local gearShop = a.PlayerGui:FindFirstChild("Gear_Shop")
        if gearShop and gearShop.Frame and gearShop.Frame.ScrollingFrame then
            for _, v in ipairs(gearShop.Frame.ScrollingFrame:GetChildren()) do
                if v:IsA("Frame") and not v.Name:find("_") then
                    table.insert(gear, v.Name)
                end
            end
        end
        return gear
    end

    -- 自动收集循环
    local function autoCollectLoop()
        while sbns.c do
            pcall(function()
                if b and b:FindFirstChild("HumanoidRootPart") then
                    for _, e in pairs(workspace.Farm:GetChildren()) do
                        if e:FindFirstChild("Important") and e.Important:FindFirstChild("Data") and e.Important.Data:FindFirstChild("Owner") then
                            if e.Important.Data.Owner.Value == a.Name then
                                for _, g in ipairs(e.Important.Plants_Physical:GetDescendants()) do
                                    if g:IsA("ProximityPrompt") then
                                        b.Humanoid:MoveTo(g.Parent.Position)
                                        fireproximityprompt(g)
                                    end
                                end
                            end
                        end
                    end
                end
            end)
            task.wait()
        end
    end

    -- 自动售卖循环
    local function autoSellLoop()
        while sbns.s do
            pcall(function()
                if b and b:FindFirstChild("HumanoidRootPart") then
                    if #a.Backpack:GetChildren() > 20 then
                        local h = b.HumanoidRootPart.CFrame
                        b.HumanoidRootPart.CFrame = workspace.NPCS["Sell Stands"]["Shop Stand"].CFrame * CFrame.new(0, 0, 3)
                        task.wait(0.5)
                        c.GameEvents.Sell_Item:FireServer()
                        c.GameEvents.Sell_Inventory:FireServer()
                        task.wait(1)
                        b.HumanoidRootPart.CFrame = h
                    end
                end
            end)
            task.wait()
        end
    end

    -- 自动种植循环
    local function autoPlantLoop()
        while sbns.p do
            pcall(function()
                if b and b:FindFirstChild("HumanoidRootPart") then
                    local seedType, tool
                    for _, i in ipairs(b:GetChildren()) do
                        if i:IsA("Tool") and i.Name:find("Seed") then
                            seedType = i.Name:match("^(.-) Seed")
                            tool = i
                            break
                        end
                    end
                    if not tool then
                        for _, i in ipairs(a.Backpack:GetChildren()) do
                            if i:IsA("Tool") and i.Name:find("Seed") then
                                seedType = i.Name:match("^(.-) Seed")
                                tool = i
                                break
                            end
                        end
                    end
                    if tool and seedType then
                        if tool.Parent == a.Backpack then
                            b.Humanoid:EquipTool(tool)
                            repeat task.wait() until tool.Parent == b
                        end
                        c.GameEvents.Plant_RE:FireServer(
                            Vector3.new(math.floor(b.HumanoidRootPart.Position.X), 0.1, math.floor(b.HumanoidRootPart.Position.Z)),
                            seedType
                        )
                    end
                end
            end)
            task.wait()
        end
    end

    -- 创建标签页
    local PlantingTab = Window:Tab({ Title = "种植花园", Icon = "tree" })
    local MainSection = PlantingTab:Section({ Title = "主要", Opened = true })

    -- 自动收集
    MainSection:Toggle({
        Title = "自动收集",
        Icon = "package",
        Value = false,
        Callback = function(state)
            sbns.c = state
            if state then task.spawn(autoCollectLoop) end
        end
    })

    -- 自动售卖
    MainSection:Toggle({
        Title = "自动售卖",
        Icon = "dollar-sign",
        Value = false,
        Callback = function(state)
            sbns.s = state
            if state then task.spawn(autoSellLoop) end
        end
    })

    -- 自动种植
    MainSection:Toggle({
        Title = "自动种植",
        Icon = "sprout",
        Value = false,
        Callback = function(state)
            sbns.p = state
            if state then task.spawn(autoPlantLoop) end
        end
    })

    -- 种子选择与信息
    local seedsList = getSeeds()
    local selectseed = seedsList[1] or ""
    local seedDropdown = MainSection:Dropdown({
        Title = "选择种子",
        Values = seedsList,
        Value = selectseed,
        Callback = function(value) selectseed = value end
    })

    local SeedInfo = MainSection:Paragraph({
        Title = "种子信息",
        Desc = "无",
        Color = "White"
    })

    task.spawn(function()
        while true do
            task.wait(0.5)
            if selectseed and selectseed ~= "" then
                local seedFrame = a.PlayerGui:FindFirstChild("Seed_Shop") and
                                 a.PlayerGui.Seed_Shop.Frame.ScrollingFrame:FindFirstChild(selectseed)
                if seedFrame then
                    local cost = seedFrame.Main_Frame and seedFrame.Main_Frame.Cost_Text and seedFrame.Main_Frame.Cost_Text.Text or "?"
                    local stock = seedFrame.Main_Frame and seedFrame.Main_Frame.Stock_Text and seedFrame.Main_Frame.Stock_Text.Text or "?"
                    SeedInfo:SetDesc("价格: " .. cost .. "\n数量: " .. stock)
                else
                    SeedInfo:SetDesc("未找到种子信息")
                end
            end
        end
    end)


    -- 刷新种子/工具列表按钮
    MainSection:Button({
        Title = "刷新列表",
        Icon = "refresh-cw",
        Callback = function()
            local newSeeds = getSeeds()
            seedDropdown:SetValues(newSeeds)
            local newGear = getGear()
            gearDropdown:SetValues(newGear)
            WindUI:Notify({ Title = "刷新", Content = "列表已更新", Duration = 2 })
        end
    })

    WindUI:Notify({ Title = "种植花园", Content = "功能已加载", Duration = 3, Icon = "check" })
end

