local eatWorldLoaded = false
local function loadEatWorldFeatures()
    if eatWorldLoaded then
        WindUI:Notify({ Title = "提示", Content = "全部功能已加载", Duration = 3, Icon = "info" })
        return
    end
    eatWorldLoaded = true

    -- 创建标签页，标题为“全部功能”
    local AllTab = Window:Tab({ Title = "全部功能", Icon = "layers" })

    -- 功能开关状态
    local autoGrabEnabled = false
    local autoEatEnabled = false
    local autoSellEnabled = false
    local autoBuyMaxSizeEnabled = false
    local autoBuySpeedEnabled = false
    local autoBuySizeMultiplierEnabled = false
    local autoUpgradeEatSpeedEnabled = false
    local autoThrowEnabled = false

    -- 自动拿建筑
    local function autoGrabLoop()
        while autoGrabEnabled do
            pcall(function()
                game:GetService("Players").LocalPlayer.Character.Events.Grab:FireServer(false, false)
            end)
            task.wait(0.1)
        end
    end

    -- 自动吃建筑
    local function autoEatLoop()
        while autoEatEnabled do
            pcall(function()
                game:GetService("Players").LocalPlayer.Character.Events.Eat:FireServer()
            end)
            task.wait(0.1)
        end
    end

    -- 自动出售
