        while autoSellEnabled do
            pcall(function()
                game:GetService("Players").LocalPlayer.Character.Events.Sell:FireServer()
            end)
            task.wait(0.1)
        end
    end

    -- 自动买最大尺寸
    local function autoBuyMaxSizeLoop()
        local purchaseEvent = game:GetService("ReplicatedStorage"):WaitForChild("Events"):WaitForChild("PurchaseEvent")
        while autoBuyMaxSizeEnabled do
            pcall(function()
                purchaseEvent:FireServer("MaxSize")
            end)
            task.wait(0.1)
        end
    end

    -- 自动买步行速度
    local function autoBuySpeedLoop()
