local silentLoaded = false
local function loadSilentSwordsmanFeatures()
    if silentLoaded then
        WindUI:Notify({ Title = "提示", Content = "沉默的剑客功能已加载", Duration = 3, Icon = "info" })
        return
    end
    silentLoaded = true

    -- 创建标签页
    local MainTab = Window:Tab({ Title = "主要", Icon = "sword" })
    local ESPTab = Window:Tab({ Title = "透视", Icon = "eye" })

    -- 获取必要服务
    local Players = game:GetService("Players")
    local ReplicatedStorage = game:GetService("ReplicatedStorage")
    local Events = ReplicatedStorage:WaitForChild("Events")
    local GameRemoteFunction = Events:WaitForChild("GameRemoteFunction")

    local player = Players.LocalPlayer
    local character = player.Character or player.CharacterAdded:Wait()
    local rootPart = character:WaitForChild("HumanoidRootPart")

    -- 默认攻击数据
    local defaultAttackData = {
        hitboxOffset = Vector3.new(0, 0, -3),
        knockback = 112.5,
        shouldLock = true,
        shouldSlow = true,
        attackCycleData = {
            lungeMult = 2.25,
            hitboxOffsetAdd = Vector3.new(0, 0, -1.5),
            slowMult = 0.2,
            slowTime = 1.5,
            hitboxSizeAdd = Vector3.new(0, 0, 3),
            knockbackMult = 2.25,
            attackTime = 0.983
        },
        isCritical = false,
        weaponDefinition = nil,
        attackCooldown = 0,
        hitboxSize = Vector3.new(9, 14, 11),
        lungeKnockback = 123.75,
        slowTime = 1.5,
        slowMult = 0.2,
        cycleIndex = 4,
        damage = 100,
        tool = nil,
        shouldLunge = true
    }

    local function getCurrentWeapon()
        if not character or not character.Parent then return nil end
        local weapon = character:FindFirstChildWhichIsA("Tool")
        if not weapon then
            local backpack = player:FindFirstChild("Backpack")
            if backpack then
                weapon = backpack:FindFirstChildWhichIsA("Tool")
            end
        end
        return weapon
    end

    local function buildEnemiesList(origin, range)
        local enemies = {}
        local closestDistance = math.huge
        local closestIndex = nil
        for _, otherPlayer in ipairs(Players:GetPlayers()) do
            if otherPlayer ~= player then
                local otherChar = otherPlayer.Character
                if otherChar and otherChar:FindFirstChild("HumanoidRootPart") and otherChar:FindFirstChild("Humanoid") then
                    local humanoid = otherChar.Humanoid
                    if humanoid.Health > 0 then
                        local otherRoot = otherChar.HumanoidRootPart
                        local direction = (otherRoot.Position - origin).Unit
                        local distance = (otherRoot.Position - origin).Magnitude
                        if distance <= range then
                            local enemyData = {
                                knockback = 112.5,
                                isClosestEnemy = false,
                                origin = origin,
                                enemyModel = otherChar,
                                distance = distance,
                                direction = direction
                            }
                            table.insert(enemies, enemyData)
                            if distance < closestDistance then
                                closestDistance = distance
                                closestIndex = #enemies
                            end
                        end
                    end
                end
            end
        end
        if closestIndex then
            enemies[closestIndex].isClosestEnemy = true
        end
        return enemies
    end

    local function performAuraAttack(range)
        local weapon = getCurrentWeapon()
        if not weapon then return end
        local origin = rootPart.Position
        local enemies = buildEnemiesList(origin, range)
        if #enemies == 0 then return end
        local attackData = {}
        for k, v in pairs(defaultAttackData) do
            attackData[k] = v
        end
        attackData.tool = weapon
        local args = {
            "AttemptWeaponHit",
            attackData,
            enemies
        }
        task.spawn(function()
            pcall(function()
                GameRemoteFunction:InvokeServer(unpack(args))
            end)
        end)
    end

    local AURA_RANGE = 50
    local ATTACK_INTERVAL = 0.1
    local auraEnabled = false
    local auraThread = nil

    local function startAura()
        while auraEnabled and player and player.Parent do
            if character and character.Parent and rootPart and rootPart.Parent then
                performAuraAttack(AURA_RANGE)
            end
            task.wait(ATTACK_INTERVAL)
        end
    end

    player.CharacterAdded:Connect(function(newChar)
        character = newChar
        rootPart = character:WaitForChild("HumanoidRootPart")
    end)

    MainTab:Section({ Title = "杀戮光环" })

