    MainTab:Button({
        Title = "传送大厅",
        Callback = function()
            local char = player.Character
            if char and char:FindFirstChild("HumanoidRootPart") then
                char.HumanoidRootPart.CFrame = CFrame.new(-19.84, 3.00, 17.36)
            end
        end
    })

    MainTab:Button({
        Title = "传送战斗地图",
        Callback = function()
            local char = player.Character
            if char and char:FindFirstChild("HumanoidRootPart") then
                char.HumanoidRootPart.CFrame = CFrame.new(-37.01, -6.48, -52.45)
            end
        end
    })

    -- ==================== ESP 系统 ====================
    local ESPEnabled = false
    local ESPNames = false
    local ESPBoxes = false
    local ESPHealth = false
    local ESPLines = false
    local ESPHighlights = false
    local ESPDistance = false
    local ESPIgnoreTeam = true
    local ESPLineFrom = "bottom"
    local ESPInstances = {}
    local RunService = game:GetService("RunService")
    local LocalPlayer = Players.LocalPlayer

    local function createESP(plr)
        if ESPInstances[plr] then return end
        local esp = {
            Box = Drawing.new("Square"),
            Name = Drawing.new("Text"),
            HealthBar = Drawing.new("Square"),
            HealthText = Drawing.new("Text"),
            DistanceText = Drawing.new("Text"),
            Line = Drawing.new("Line"),
            Highlight = Instance.new("Highlight")
        }
        esp.Box.Visible = false
        esp.Box.Thickness = 2
        esp.Box.Color = Color3.fromRGB(255, 255, 255)
        esp.Box.Filled = false
        esp.Name.Visible = false
        esp.Name.Size = 16
        esp.Name.Color = Color3.fromRGB(255, 255, 255)
        esp.Name.Outline = true
        esp.Name.OutlineColor = Color3.fromRGB(0, 0, 0)
        esp.Name.Center = true
        esp.HealthBar.Visible = false
        esp.HealthBar.Thickness = 1
        esp.HealthBar.Filled = true
        esp.HealthText.Visible = false
        esp.HealthText.Size = 12
        esp.HealthText.Outline = true
        esp.HealthText.OutlineColor = Color3.fromRGB(0, 0, 0)
        esp.HealthText.Center = true
        esp.DistanceText.Visible = false
        esp.DistanceText.Size = 14
        esp.DistanceText.Color = Color3.fromRGB(255, 255, 255)
        esp.DistanceText.Outline = true
        esp.DistanceText.OutlineColor = Color3.fromRGB(0, 0, 0)
        esp.DistanceText.Center = true
        esp.Line.Visible = false
        esp.Line.Thickness = 2
        esp.Line.Color = Color3.fromRGB(255, 255, 255)
        esp.Highlight.FillColor = Color3.fromRGB(255, 255, 255)
        esp.Highlight.FillTransparency = 0.5
        esp.Highlight.OutlineColor = Color3.fromRGB(255, 0, 0)
        esp.Highlight.OutlineTransparency = 0
        esp.Highlight.Enabled = false
        esp.Highlight.Parent = game:GetService("CoreGui")
        ESPInstances[plr] = esp
    end

    local function safeRemoveESP(plr)
        local esp = ESPInstances[plr]
        if esp then
            if esp.Box then esp.Box:Remove() end
            if esp.Name then esp.Name:Remove() end
            if esp.HealthBar then esp.HealthBar:Remove() end
            if esp.HealthText then esp.HealthText:Remove() end
            if esp.DistanceText then esp.DistanceText:Remove() end
            if esp.Line then esp.Line:Remove() end
            if esp.Highlight then esp.Highlight:Destroy() end
            ESPInstances[plr] = nil
        end
    end

    local function updateESP()
        if not ESPEnabled then return end
        for plr, esp in pairs(ESPInstances) do
            local success, err = pcall(function()
                if not plr or not plr.Parent then
                    safeRemoveESP(plr)
                    return
                end
                if ESPIgnoreTeam and plr.Team and LocalPlayer.Team and plr.Team == LocalPlayer.Team then
                    esp.Box.Visible = false
                    esp.Name.Visible = false
                    esp.HealthBar.Visible = false
                    esp.HealthText.Visible = false
                    esp.DistanceText.Visible = false
                    esp.Line.Visible = false
                    esp.Highlight.Enabled = false
                    return
                end
                local character = plr.Character
                if not character then
                    esp.Box.Visible = false
                    esp.Name.Visible = false
                    esp.HealthBar.Visible = false
                    esp.HealthText.Visible = false
                    esp.DistanceText.Visible = false
                    esp.Line.Visible = false
                    esp.Highlight.Enabled = false
                    return
                end
                local humanoid = character:FindFirstChild("Humanoid")
                local head = character:FindFirstChild("Head")
                local root = character:FindFirstChild("HumanoidRootPart") or character:FindFirstChild("Torso") or character:FindFirstChild("UpperTorso")
                if not humanoid or not head or not root then
                    esp.Box.Visible = false
                    esp.Name.Visible = false
                    esp.HealthBar.Visible = false
                    esp.HealthText.Visible = false
                    esp.DistanceText.Visible = false
                    esp.Line.Visible = false
                    esp.Highlight.Enabled = false
                    return
                end
                local camera = workspace.CurrentCamera
                if not camera then return end
                local headPos, onScreen = camera:WorldToViewportPoint(head.Position)
                if not onScreen then
                    esp.Box.Visible = false
                    esp.Name.Visible = false
                    esp.HealthBar.Visible = false
                    esp.HealthText.Visible = false
                    esp.DistanceText.Visible = false
                    esp.Line.Visible = false
                    esp.Highlight.Enabled = false
                    return
                end
                local size = Vector2.new(2000 / headPos.Z, 3000 / headPos.Z)
                local position = Vector2.new(headPos.X - size.X / 2, headPos.Y - size.Y / 2)
                if ESPBoxes then
                    esp.Box.Size = size
                    esp.Box.Position = position
                    esp.Box.Visible = true
                else
                    esp.Box.Visible = false
                end
                if ESPNames then
                    esp.Name.Text = plr.Name
                    esp.Name.Position = Vector2.new(headPos.X, headPos.Y - size.Y / 2 - 20)
                    esp.Name.Visible = true
                else
                    esp.Name.Visible = false
                end
                if ESPDistance then
                    local localChar = LocalPlayer.Character
                    local localRoot = localChar and (localChar:FindFirstChild("HumanoidRootPart") or localChar:FindFirstChild("Torso") or localChar:FindFirstChild("UpperTorso"))
                    if localRoot then
                        local distance = math.floor((localRoot.Position - root.Position).Magnitude)
                        esp.DistanceText.Text = tostring(distance) .. "m"
                        if ESPNames then
                            esp.DistanceText.Position = Vector2.new(headPos.X, headPos.Y - size.Y / 2 - 40)
                        else
                            esp.DistanceText.Position = Vector2.new(headPos.X, headPos.Y - size.Y / 2 - 20)
                        end
                        esp.DistanceText.Visible = true
                    else
                        esp.DistanceText.Visible = false
                    end
                else
                    esp.DistanceText.Visible = false
                end
                if ESPHealth then
                    local healthPercent = humanoid.Health / humanoid.MaxHealth
                    local healthColor
                    if healthPercent > 0.5 then
                        healthColor = Color3.fromRGB(0, 255, 0)
                    elseif healthPercent > 0.25 then
                        healthColor = Color3.fromRGB(255, 255, 0)
                    else
                        healthColor = Color3.fromRGB(255, 0, 0)
                    end
                    esp.HealthBar.Color = healthColor
                    esp.HealthBar.Size = Vector2.new(size.X * healthPercent, 4)
                    if ESPDistance then
                        local offset = ESPNames and 55 or 35
                        esp.HealthBar.Position = Vector2.new(position.X, position.Y + size.Y + offset)
                        esp.HealthText.Position = Vector2.new(headPos.X, position.Y + size.Y + offset + 10)
                    else
                        esp.HealthBar.Position = Vector2.new(position.X, position.Y + size.Y + 5)
                        esp.HealthText.Position = Vector2.new(headPos.X, position.Y + size.Y + 15)
                    end
                    esp.HealthBar.Visible = true
                    esp.HealthText.Text = math.floor(humanoid.Health) .. "/" .. math.floor(humanoid.MaxHealth)
                    esp.HealthText.Color = healthColor
                    esp.HealthText.Visible = true
                else
                    esp.HealthBar.Visible = false
                    esp.HealthText.Visible = false
                end
                if ESPLines then
                    local lineStart
                    if ESPLineFrom == "top" then
                        lineStart = Vector2.new(camera.ViewportSize.X / 2, 0)
                    else
                        lineStart = Vector2.new(camera.ViewportSize.X / 2, camera.ViewportSize.Y)
                    end
                    esp.Line.From = lineStart
                    esp.Line.To = Vector2.new(headPos.X, headPos.Y)
                    esp.Line.Visible = true
                else
                    esp.Line.Visible = false
                end
                if ESPHighlights then
                    esp.Highlight.Adornee = character
                    esp.Highlight.Enabled = true
                else
                    esp.Highlight.Enabled = false
                end
            end)
            if not success then
                safeRemoveESP(plr)
            end
        end
    end

    local ESPConnection
    local function toggleESP()
        if not ESPEnabled then
            ESPEnabled = true
            for _, plr in pairs(Players:GetPlayers()) do
                if plr ~= LocalPlayer then
                    createESP(plr)
                end
            end
            if not ESPConnection then
                ESPConnection = RunService.RenderStepped:Connect(updateESP)
            end
        else
            ESPEnabled = false
            if ESPConnection then
                ESPConnection:Disconnect()
                ESPConnection = nil
            end
            for plr, _ in pairs(ESPInstances) do
                safeRemoveESP(plr)
            end
        end
    end

    local function onPlayerAdded(plr)
        if plr == LocalPlayer then return end
        plr.CharacterAdded:Connect(function()
            if ESPEnabled then
                task.wait(0.5)
                createESP(plr)
            end
        end)
        if ESPEnabled then
            task.wait(0.5)
            createESP(plr)
        end
    end

    local function onPlayerRemoving(plr)
        safeRemoveESP(plr)
    end

    Players.PlayerAdded:Connect(onPlayerAdded)
    Players.PlayerRemoving:Connect(onPlayerRemoving)

    for _, plr in pairs(Players:GetPlayers()) do
        if plr ~= LocalPlayer then
            onPlayerAdded(plr)
        end
    end

