    })

    ESPTab:Toggle({
        Title = "方框",
        Value = false,
        Callback = function(state)
            ESPBoxes = state
        end
    })

    ESPTab:Toggle({
        Title = "射线",
        Value = false,
        Callback = function(state)
            ESPLines = state
        end
    })

    ESPTab:Toggle({
        Title = "显示名字",
        Value = false,
        Callback = function(state)
            ESPNames = state
        end
    })

    ESPTab:Toggle({
        Title = "显示血量",
        Value = false,
        Callback = function(state)
            ESPHealth = state
        end
    })

    ESPTab:Toggle({
        Title = "显示距离",
        Value = false,
        Callback = function(state)
            ESPDistance = state
        end
    })

    ESPTab:Toggle({
        Title = "高光",
        Value = false,
        Callback = function(state)
            ESPHighlights = state
        end
    })

    ESPTab:Dropdown({
        Title = "射线位置",
        Values = { "top", "bottom" },
        Value = "bottom",
        Callback = function(selected)
            ESPLineFrom = selected
        end
    })

