-- ========== 建造一架飞机功能加载（修复版） ==========
local planeBuiltLoaded = false
local function loadPlaneBuiltFeatures()
    if planeBuiltLoaded then
        WindUI:Notify({ Title = "提示", Content = "功能已加载", Duration = 3, Icon = "info" })
        return
    end
    planeBuiltLoaded = true

    -- 创建功能标签页
    local FuncTab = Window:Tab({ Title = "功能", Icon = "settings" })

    local launchDistance = 20000

    -- 发射距离输入
    FuncTab:Input({
        Title = "发射距离",
        Placeholder = "输入数字 (例如 2000)",
        Callback = function(input)
            local num = tonumber(input)
            if num then
                launchDistance = num
            else
                WindUI:Notify({
                    Title = "输入无效",
                    Content = "请输入有效的数字",
                    Duration = 4,
                    Icon = "alert-triangle"
                })
            end
        end
    })

    -- 按设定距离发射
    FuncTab:Button({
        Title = "按设定距离发射",
        Callback = function()
            local ReplicatedStorage = game:GetService('ReplicatedStorage')
            local Players = game:GetService('Players')
            local player = Players.LocalPlayer

            local launchRemote = ReplicatedStorage
                :WaitForChild('Remotes')
                :WaitForChild('LaunchEvents')
                :WaitForChild('Launch')
            launchRemote:FireServer()
            task.wait(2)

            local character = player.Character or player.CharacterAdded:Wait()
            local humanoid = character:FindFirstChildOfClass('Humanoid')
            local seat = humanoid and humanoid.SeatPart

            if seat then
                local forwardVector = seat.CFrame.LookVector
                local targetCFrame = seat.CFrame + forwardVector * launchDistance
                seat.CFrame = targetCFrame

                local rootPart = character.PrimaryPart or character:FindFirstChild('HumanoidRootPart')
                if rootPart then
                    character:SetPrimaryPartCFrame(targetCFrame)
                end
            end
        end
    })

    WindUI:Notify({ Title = "建造一架飞机", Content = "功能已加载", Duration = 3, Icon = "check" })
end

