local qimuLoaded = false
local function loadQimuFeatures()
    if qimuLoaded then
        WindUI:Notify({ Title = "提示", Content = "启目录功能已加载", Duration = 3, Icon = "info" })
        return
    end
    qimuLoaded = true

    -- 创建标签页
    local QimuTab = Window:Tab({ Title = "启目录", Icon = "eye" })

    -- ==================== 物品透视开关 ====================
    -- 存储创建的 ESP 物体（高亮 + Billboard），以便清除
    local espObjects = {}
    local itemESPEnabled = false

    -- 物品名称中英文翻译表
    local nameTranslations = {
        ["Bloxiade"] = "布洛西亚德", ["Can"] = "罐子", ["Chips"] = "薯片", ["Mesh"] = "网格",
        ["Beans"] = "豆子", ["Fuel"] = "燃料", ["Handle"] = "把手", ["Lid"] = "盖子",
        ["Body"] = "主体", ["Label"] = "标签", ["Box"] = "盒子", ["Bag"] = "袋子",
        ["Bottle"] = "瓶子", ["Wrapper"] = "包装纸", ["Cap"] = "瓶盖", ["Top"] = "顶部",
        ["Bottom"] = "底部", ["Part"] = "零件", ["Union"] = "联合体", ["Cylinder"] = "圆柱体",
        ["Block"] = "方块", ["Sphere"] = "球体", ["Wedge"] = "楔形", ["CornerWedge"] = "角楔",
        ["Truss"] = "桁架", ["Seat"] = "座椅", ["Spawn"] = "出生点", ["Base"] = "底座",
        ["Plate"] = "板", ["Door"] = "门", ["Window"] = "窗户", ["Wheel"] = "轮子",
        ["Engine"] = "引擎", ["Tank"] = "油箱", ["Pipe"] = "管道", ["Valve"] = "阀门",
        ["Switch"] = "开关", ["Button"] = "按钮", ["Lever"] = "拉杆", ["Panel"] = "面板",
        ["Frame"] = "框架", ["Glass"] = "玻璃", ["Light"] = "灯", ["Screen"] = "屏幕",
        ["Wire"] = "电线", ["Gear"] = "齿轮", ["Spring"] = "弹簧", ["Axle"] = "轴",
        ["Clamp"] = "夹子", ["Tray"] = "托盘", ["Basket"] = "篮子", ["Crate"] = "板条箱",
        ["Pallet"] = "货板", ["Rack"] = "货架", ["Sign"] = "标牌",
    }

    local function translate(name)
        return nameTranslations[name] or name
    end

    -- 清除物品透视
    local function clearItemESP()
        for _, obj in ipairs(espObjects) do
            if obj.Highlight and obj.Highlight.Parent then obj.Highlight:Destroy() end
            if obj.Billboard and obj.Billboard.Parent then obj.Billboard:Destroy() end
        end
        espObjects = {}
    end

    -- 创建物品透视（一次性扫描并添加监听）
    local function enableItemESP()
        clearItemESP()  -- 先清除旧的
        local droppedItems = workspace:FindFirstChild("DroppedItems")
        if not droppedItems then
            WindUI:Notify({ Title = "警告", Content = "未找到 workspace.DroppedItems，物品透视无效", Duration = 3, Icon = "alert-circle" })
            return
        end

        local function addESPToPart(part)
            if not part:IsA("BasePart") then return end
            -- 避免重复添加
            for _, v in ipairs(espObjects) do
                if v.Part == part then return end
            end
            local h = Instance.new("Highlight")
            h.FillColor = Color3.new(1, 0, 0)
            h.FillTransparency = 0
            h.Parent = part

            local billboard = Instance.new("BillboardGui")
            billboard.Name = "NameTag"
            billboard.Size = UDim2.new(0, 200, 0, 50)
            billboard.StudsOffset = Vector3.new(0, 2, 0)
            billboard.AlwaysOnTop = true
            billboard.Parent = part

            local label = Instance.new("TextLabel")
            label.Size = UDim2.new(1, 0, 1, 0)
            label.BackgroundTransparency = 1
            label.Text = translate(part.Name)
            label.TextColor3 = Color3.new(1, 1, 1)
            label.TextStrokeTransparency = 0
            label.TextStrokeColor3 = Color3.new(0, 0, 0)
            label.Font = Enum.Font.SourceSansBold
            label.TextSize = 14
            label.Parent = billboard

            table.insert(espObjects, { Highlight = h, Billboard = billboard, Part = part })
        end

        -- 扫描现有物品
        local function scanAll(parent)
            for _, child in ipairs(parent:GetChildren()) do
                if child:IsA("BasePart") then
                    addESPToPart(child)
                else
                    scanAll(child)
                end
            end
        end
        scanAll(droppedItems)

        -- 监听新增物品
        droppedItems.DescendantAdded:Connect(function(newObj)
            if not itemESPEnabled then return end
            task.wait(0.1)
            if newObj:IsA("BasePart") then
                addESPToPart(newObj)
            else
                scanAll(newObj)
            end
        end)
    end

    QimuTab:Toggle({
        Title = "物品透视",
        Desc = "高亮掉落物品并显示中文名称",
        Value = false,
        Callback = function(state)
            itemESPEnabled = state
            if state then
                enableItemESP()
            else
                clearItemESP()
            end
        end
    })

    -- ==================== 无敌开关 ====================
    local invincibleEnabled = false
    local invincibleConnections = {}   -- 存储连接以便关闭时断开
    local originalHealthData = {}       -- 存储每个角色的原始 MaxHealth、FallDamage 等

    local function disableInvincible()
        for _, conn in pairs(invincibleConnections) do
            if conn and conn.Disconnect then conn:Disconnect() end
        end
        invincibleConnections = {}

        local char = LocalPlayer.Character
        if char then
            local hum = char:FindFirstChildOfClass("Humanoid")
            if hum then
                local orig = originalHealthData[char]
                if orig then
                    hum.MaxHealth = orig.MaxHealth
                    hum.Health = math.min(orig.Health, orig.MaxHealth)
                    hum.FallDamage = orig.FallDamage
                    hum:SetStateEnabled(Enum.HumanoidStateType.Dead, true)
                    hum:SetStateEnabled(Enum.HumanoidStateType.Stunned, true)
                else
                    hum.MaxHealth = 100
                    hum.Health = 100
                    hum.FallDamage = true
                    hum:SetStateEnabled(Enum.HumanoidStateType.Dead, true)
                    hum:SetStateEnabled(Enum.HumanoidStateType.Stunned, true)
                end
            end
        end
        originalHealthData = {}
    end

    local function makeInvincible(character)
        local hum = character:WaitForChild("Humanoid")
        task.wait(0.1)

        -- 保存原始数据
        if not originalHealthData[character] then
            originalHealthData[character] = {
                MaxHealth = hum.MaxHealth,
                Health = hum.Health,
                FallDamage = hum.FallDamage,
            }
        end

        hum.MaxHealth = math.huge
        hum.Health = math.huge
        hum.FallDamage = false
        hum:SetStateEnabled(Enum.HumanoidStateType.Dead, false)
        hum:SetStateEnabled(Enum.HumanoidStateType.Stunned, false)

        local healthConn = hum.HealthChanged:Connect(function()
            if hum.Health < math.huge then hum.Health = math.huge end
        end)
        local damageConn = hum.DamageTaken:Connect(function()
            hum.Health = math.huge
        end)
        local ancestryConn = hum.AncestryChanged:Connect(function(_, parent)
            if not parent then
                local newHum = character:WaitForChild("Humanoid", 5)
                if newHum then makeInvincible(character) end
            end
        end)

        table.insert(invincibleConnections, healthConn)
        table.insert(invincibleConnections, damageConn)
        table.insert(invincibleConnections, ancestryConn)

        local root = character:FindFirstChild("HumanoidRootPart")
        if root then
            local posConn = root:GetPropertyChangedSignal("Position"):Connect(function()
                if root.Position.Y < -500 then
                    root.CFrame = CFrame.new(0, 50, 0)
                end
            end)
            table.insert(invincibleConnections, posConn)
        end
    end

    local function enableInvincible()
        disableInvincible()  -- 先关闭旧的
        local LocalPlayer = game.Players.LocalPlayer
        if LocalPlayer.Character then
            makeInvincible(LocalPlayer.Character)
        end
        local addedConn = LocalPlayer.CharacterAdded:Connect(makeInvincible)
        table.insert(invincibleConnections, addedConn)
    end

    QimuTab:Toggle({
        Title = "无敌模式",
        Desc = "角色生命无限、免疫死亡和摔落",
        Value = false,
        Callback = function(state)
            invincibleEnabled = state
            if state then
                enableInvincible()
            else
                disableInvincible()
            end
        end
    })

    WindUI:Notify({ Title = "启目录", Content = "功能已加载，请通过开关启用子功能", Duration = 3, Icon = "check" })
end


