                showMsg("错误：请先选择一个稿子", Color3.new(1, 0, 0))
                return
            end
            local targetPos = pickaxePositions[selectedPickaxe]
            local player = game.Players.LocalPlayer
            local character = player.Character
            local hrp = character and character:FindFirstChild("HumanoidRootPart")
            if not hrp then return end
            task.wait(0.5)
            character:MoveTo(targetPos)
            task.wait(0.5)
            local prompts = {}
            for _, child in ipairs(workspace:GetDescendants()) do
                if child:IsA("ProximityPrompt") and (child.Parent.Position - targetPos).Magnitude < 4 then
                    table.insert(prompts, child)
                end
            end
            if #prompts > 0 then
                for _, prompt in ipairs(prompts) do
                    fireproximityprompt(prompt)
                end
                showMsg("购买成功！", Color3.new(0, 1, 0))
            else
                showMsg("成功", Color3.new(1, 1, 0))
            end
        end
    })

    local fishingRodPositions = {
