        ["普通钓鱼竿"] = Vector3.new(-51.93882369995117, 0.014909714460372925, -976.4150390625),
        ["高级钓鱼竿"] = Vector3.new(-55.99718475341797, 0.013977736234664917, -976.3984375)
    }
    local selectedFishingRod = ""
    QiongTab2:Dropdown({
