-- 提升模拟器功能（点击加载，无UI，仅功能面板）
local liftSimLoaded = false
function loadLiftSimFeatures()
    if liftSimLoaded then
        WindUI:Notify({ Title = "提示", Content = "提升模拟器功能已加载", Duration = 3, Icon = "info" })
        return
    end
    liftSimLoaded = true

    local LiftTab = Window:Tab({ Title = "提升模拟器", Icon = "dumbbell" })

    local autoLift = false
    local autoSell = false
    local liftThread = nil
    local sellThread = nil

    LiftTab:Toggle({
        Title = "自动锻炼",
        Value = false,
        Callback = function(state)
            autoLift = state
            if autoLift then
                if liftThread then task.cancel(liftThread) end
                liftThread = task.spawn(function()
                    while autoLift do
                        local ohTable1 = { [1] = "GainMuscle" }
                        game:GetService("ReplicatedStorage").RemoteEvent:FireServer(ohTable1)
                        task.wait()
                    end
                end)
            else
                if liftThread then task.cancel(liftThread); liftThread = nil end
            end
        end
    })

    LiftTab:Toggle({
        Title = "自动出售",
        Value = false,
        Callback = function(state)
            autoSell = state
            if autoSell then
                if sellThread then task.cancel(sellThread) end
                sellThread = task.spawn(function()
                    while autoSell do
                        local ohTable1 = { [1] = "SellMuscle" }
                        game:GetService("ReplicatedStorage").RemoteEvent:FireServer(ohTable1)
                        task.wait()
                    end
                end)
            else
                if sellThread then task.cancel(sellThread); sellThread = nil end
            end
        end
    })

    WindUI:Notify({ Title = "提升模拟器", Content = "功能已加载", Duration = 3, Icon = "check" })
end

-- 迷宫功能（点击加载，无UI，仅功能面板）
local mazeLoaded = false
function loadMazeFeatures()
    if mazeLoaded then
        WindUI:Notify({ Title = "提示", Content = "迷宫功能已加载", Duration = 3, Icon = "info" })
        return
    end
    mazeLoaded = true

    local Player = game.Players.LocalPlayer
    local Workspace = game:GetService("Workspace")
    local Lighting = game:GetService("Lighting")
    local RunService = game:GetService("RunService")

    local playerESPEnabled = false
    local npcESPEnabled = false
    local itemESPEnabled = false
    local batteryESPEnabled = false

    local autoAxeEnabled = false
    local autoStoneEnabled = false
    local autoBreakPlanksEnabled = false

    local itemPhaseEnabled = false
    local itemPhaseConnection

    local NoclipEnabled = false
    local NoclipConnection

    local fullBrightEnabled = false

    local autoCollectBatteryEnabled = false
    local autoCollectAxeEnabled = false

    local HighlightFolder = Instance.new("Folder", game.CoreGui)
    HighlightFolder.Name = "Maze_ESP_Highlights"

    local BatteryFolder = Workspace:FindFirstChild("SpawnedObjects")
    local BatteryNames = {"Battery1", "Battery2", "Battery3", "Battery4"}
    local BatteryChineseMap = {
        ["电池1"] = "Battery1",
        ["电池2"] = "Battery2",
        ["电池3"] = "Battery3",
        ["电池4"] = "Battery4",
    }

    local function createESPLabel(parent, text, color)
        local bb = Instance.new("BillboardGui")
        bb.Size = UDim2.new(0, 200, 0, 30)
        bb.AlwaysOnTop = true
        bb.Adornee = parent
        local label = Instance.new("TextLabel")
        label.Size = UDim2.new(1, 0, 1, 0)
        label.BackgroundTransparency = 1
        label.Text = text
        label.TextColor3 = color or Color3.new(1, 1, 1)
        label.TextStrokeTransparency = 0.5
        label.Font = Enum.Font.SourceSansBold
        label.TextSize = 14
        label.Parent = bb
        bb.Parent = parent
        return bb
    end

    local function addHighlight(target, color)
        local hl = Instance.new("Highlight")
        hl.FillColor = color
        hl.OutlineColor = Color3.new(1, 1, 1)
        hl.FillTransparency = 0.5
        hl.OutlineTransparency = 0
        hl.Parent = HighlightFolder
        hl.Adornee = target
        return hl
    end

    local function clearAllESP()
        HighlightFolder:ClearAllChildren()
    end

    local function grabTool(tool)
        local character = Player.Character
        if not character then return end
        local handle = tool:FindFirstChild("Handle") or tool:FindFirstChildWhichIsA("BasePart")
        if handle then
            firetouchinterest(character.PrimaryPart or character:FindFirstChild("HumanoidRootPart"), handle, 0)
            wait(0.1)
            firetouchinterest(character.PrimaryPart or character:FindFirstChild("HumanoidRootPart"), handle, 1)
        end
    end

    local function getBatteryPart(name)
        if not BatteryFolder then return nil end
        local battery = BatteryFolder:FindFirstChild(name)
        if not battery then return nil end
        if battery:IsA("BasePart") then return battery end
        if battery:IsA("Model") then
            if battery.PrimaryPart then return battery.PrimaryPart end
            for _, child in ipairs(battery:GetChildren()) do
                if child:IsA("BasePart") then return child end
            end
            return battery
        end
        return battery
    end

    local function getBatteryModel(name)
        if not BatteryFolder then return nil end
        return BatteryFolder:FindFirstChild(name)
    end

    local function getWorldPosition(obj)
        if obj:IsA("BasePart") then
            return obj.Position
        elseif obj:IsA("Model") then
            local cf = obj:GetPivot()
            return cf.Position
        else
            local success, pos = pcall(function() return obj:GetPivot().Position end)
            if success then return pos end
            return nil
        end
    end

    local function teleportTo(pos)
        local character = Player.Character
        if not character or not character.PrimaryPart then return end
        if not pos then return end
        local targetPos = pos + Vector3.new(0, 3, 0)
        character:SetPrimaryPartCFrame(CFrame.new(targetPos))
    end

    local function triggerPickup(obj)
        if not obj then return end
        local prompt = obj:FindFirstChildWhichIsA("ProximityPrompt", true)
        if prompt and prompt.Enabled then
            fireproximityprompt(prompt)
            return true
        end
        local click = obj:FindFirstChildWhichIsA("ClickDetector", true)
        if click then
            fireclickdetector(click)
            return true
        end
        if obj:IsA("BasePart") then
            local character = Player.Character
            if character then
                firetouchinterest(character.PrimaryPart or character:FindFirstChild("HumanoidRootPart"), obj, 0)
                wait(0.1)
                firetouchinterest(character.PrimaryPart or character:FindFirstChild("HumanoidRootPart"), obj, 1)
                return true
            end
        elseif obj:IsA("Model") then
            local primary = obj.PrimaryPart
            if primary then return triggerPickup(primary) end
        end
        return false
    end

    local function collectBatterySequence()
        if not autoCollectBatteryEnabled then return end
        task.spawn(function()
            for _, batName in ipairs(BatteryNames) do
                if not autoCollectBatteryEnabled then break end
                local model = getBatteryModel(batName)
                if model then
                    local pos = getWorldPosition(model)
                    if pos then
                        teleportTo(pos)
                        wait(0.5)
                        triggerPickup(model)
                        wait(1.5)
                    end
                else
                    WindUI:Notify({Title = "自动拾取", Content = batName .. " 已不存在", Duration = 2})
                end
            end
            WindUI:Notify({Title = "自动拾取", Content = "电池拾取完成", Duration = 2})
        end)
    end

    local function collectAxeSequence()
        if not autoCollectAxeEnabled then return end
        task.spawn(function()
            local axe = Workspace:FindFirstChild("Axe")
            if not axe then
                for _, tool in pairs(Workspace:GetDescendants()) do
                    if tool:IsA("Tool") and tool.Name:lower():find("axe") then
                        axe = tool
                        break
                    end
                end
            end
            if axe then
                local pos
                if axe:IsA("Tool") then
                    local handle = axe:FindFirstChild("Handle")
                    if handle then pos = handle.Position end
                else
                    pos = getWorldPosition(axe)
                end
                if pos then
                    teleportTo(pos)
                    wait(0.5)
                    triggerPickup(axe)
                    wait(1)
                end
                WindUI:Notify({Title = "自动拾取", Content = "斧头拾取完成", Duration = 2})
            else
                WindUI:Notify({Title = "自动拾取", Content = "未找到斧头", Duration = 2})
            end
        end)
    end

    -- 创建标签页
    local MazeTab = Window:Tab({ Title = "迷宫", Icon = "map-pin" })

    MazeTab:Slider({
        Title = "移动速度",
        Value = {Min = 1, Max = 500, Default = 16},
        Callback = function(value)
            local humanoid = Player.Character and Player.Character:FindFirstChild("Humanoid")
            if humanoid then
                humanoid.WalkSpeed = value
                WindUI:Notify({Title = "速度修改", Content = "移动速度已修改为: " .. value, Duration = 2})
            end
        end
    })

    MazeTab:Slider({
        Title = "跳跃高度",
        Value = {Min = 1, Max = 200, Default = 50},
        Callback = function(value)
            local humanoid = Player.Character and Player.Character:FindFirstChild("Humanoid")
            if humanoid then
                humanoid.JumpPower = value
                WindUI:Notify({Title = "跳跃修改", Content = "跳跃高度已修改为: " .. value, Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "高亮度",
        Default = false,
        Callback = function(value)
            fullBrightEnabled = value
            if value then
                Lighting.Brightness = 3
                Lighting.ClockTime = 14
                Lighting.FogEnd = 100000
                Lighting.GlobalShadows = false
                WindUI:Notify({Title = "高亮度", Content = "地图已全亮", Duration = 2})
            else
                Lighting.Brightness = 1
                Lighting.ClockTime = 14
                Lighting.FogEnd = 100000
                Lighting.GlobalShadows = true
                WindUI:Notify({Title = "高亮度", Content = "亮度已恢复正常", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "透视玩家",
        Default = false,
        Callback = function(value)
            playerESPEnabled = value
            if value then
                local function onPlayerAdded(player)
                    if player == Player then return end
                    local function onCharacterAdded(character)
                        if not playerESPEnabled then return end
                        local head = character:WaitForChild("Head", 5)
                        if not head then return end
                        addHighlight(character, Color3.new(1, 0, 0))
                        createESPLabel(head, "玩家: " .. player.Name, Color3.new(1, 0, 0))
                    end
                    if player.Character then onCharacterAdded(player.Character) end
                    player.CharacterAdded:Connect(onCharacterAdded)
                end
                for _, player in pairs(game.Players:GetPlayers()) do
                    onPlayerAdded(player)
                end
                game.Players.PlayerAdded:Connect(onPlayerAdded)
                WindUI:Notify({Title = "透视玩家", Content = "已显示所有玩家位置", Duration = 2})
            else
                clearAllESP()
                WindUI:Notify({Title = "透视玩家", Content = "已关闭玩家透视", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "透视NPC",
        Default = false,
        Callback = function(value)
            npcESPEnabled = value
            if value then
                local connection
                connection = RunService.Heartbeat:Connect(function()
                    if not npcESPEnabled then connection:Disconnect(); return end
                    for _, obj in pairs(Workspace:GetDescendants()) do
                        if obj:IsA("Model") and obj:FindFirstChild("Humanoid") and not game.Players:GetPlayerFromCharacter(obj) then
                            if not obj:FindFirstChild("ESP_NPC_Marker") then
                                local hl = addHighlight(obj, Color3.new(1, 1, 0))
                                hl.Name = "ESP_NPC_Marker"
                                local head = obj:FindFirstChild("Head")
                                if head and not head:FindFirstChild("BillboardGui") then
                                    createESPLabel(head, "怪物", Color3.new(1, 1, 0))
                                end
                            end
                        end
                    end
                end)
                WindUI:Notify({Title = "透视NPC", Content = "已显示所有怪物位置", Duration = 2})
            else
                for _, obj in pairs(Workspace:GetDescendants()) do
                    if obj.Name == "ESP_NPC_Marker" then obj:Destroy() end
                end
                WindUI:Notify({Title = "透视NPC", Content = "已关闭NPC透视", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "透视物品",
        Default = false,
        Callback = function(value)
            itemESPEnabled = value
            if value then
                local connection
                connection = RunService.Heartbeat:Connect(function()
                    if not itemESPEnabled then connection:Disconnect(); return end
                    local function handleObj(obj)
                        if obj:IsA("BasePart") then
                            local nameLower = obj.Name:lower()
                            local labelText = nil
                            local color = Color3.new(0, 1, 0)
                            if nameLower:find("stone") then
                                labelText = "石头"
                            elseif nameLower:find("plank") or nameLower:find("wood") then
                                labelText = "木板"
                            end
                            if labelText and not obj:FindFirstChild("ESP_Item_Marker") then
                                local hl = addHighlight(obj, color)
                                hl.Name = "ESP_Item_Marker"
                                createESPLabel(obj, labelText, color)
                            end
                        elseif obj.Name == "Axe" then
                            local part = obj:FindFirstChild("Handle") or (obj:IsA("Model") and obj.PrimaryPart) or obj
                            if part and part:IsA("BasePart") and not part:FindFirstChild("ESP_Item_Marker") then
                                local hl = addHighlight(part, Color3.new(1, 0.5, 0))
                                hl.Name = "ESP_Item_Marker"
                                createESPLabel(part, "斧头", Color3.new(1, 0.5, 0))
                            end
                        end
                    end
                    for _, obj in pairs(Workspace:GetDescendants()) do handleObj(obj) end
                    local axe = Workspace:FindFirstChild("Axe")
                    if axe then handleObj(axe) end
                end)
                WindUI:Notify({Title = "透视物品", Content = "已显示物品位置", Duration = 2})
            else
                for _, obj in pairs(Workspace:GetDescendants()) do
                    if obj.Name == "ESP_Item_Marker" then obj:Destroy() end
                end
                WindUI:Notify({Title = "透视物品", Content = "已关闭物品透视", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "电池透视",
        Default = false,
        Callback = function(value)
            batteryESPEnabled = value
            if value then
                local connection
                connection = RunService.Heartbeat:Connect(function()
                    if not batteryESPEnabled then connection:Disconnect(); return end
                    if not BatteryFolder then return end
                    for _, batName in ipairs(BatteryNames) do
                        local batteryPart = getBatteryPart(batName)
                        if batteryPart and batteryPart:IsA("BasePart") then
                            if not batteryPart:FindFirstChild("ESP_Battery_Marker") then
                                local hl = addHighlight(batteryPart, Color3.new(0, 0.5, 1))
                                hl.Name = "ESP_Battery_Marker"
                                createESPLabel(batteryPart, batName .. "号电池", Color3.new(0, 0.5, 1))
                            end
                        end
                    end
                end)
                WindUI:Notify({Title = "电池透视", Content = "已显示所有电池位置", Duration = 2})
            else
                if BatteryFolder then
                    for _, batName in ipairs(BatteryNames) do
                        local batteryPart = getBatteryPart(batName)
                        if batteryPart then
                            for _, child in pairs(batteryPart:GetDescendants()) do
                                if child.Name == "ESP_Battery_Marker" or child.Name == "BillboardGui" then
                                    child:Destroy()
                                end
                            end
                        end
                    end
                end
                WindUI:Notify({Title = "电池透视", Content = "已关闭电池透视", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "自动拿斧头",
        Default = false,
        Callback = function(value)
            autoAxeEnabled = value
            if value then
                local connection
                connection = RunService.Heartbeat:Connect(function()
                    if not autoAxeEnabled then connection:Disconnect(); return end
                    for _, tool in pairs(Workspace:GetDescendants()) do
                        if tool:IsA("Tool") and tool.Name:lower():find("axe") then
                            if tool.Parent ~= Player.Backpack and tool.Parent ~= Player.Character then
                                grabTool(tool)
                            end
                        end
                    end
                end)
                WindUI:Notify({Title = "自动拾取", Content = "正在自动拾取斧头", Duration = 2})
            else
                WindUI:Notify({Title = "自动拾取", Content = "已停止拾取斧头", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "自动拾取石头",
        Default = false,
        Callback = function(value)
            autoStoneEnabled = value
            if value then
                local connection
                connection = RunService.Heartbeat:Connect(function()
                    if not autoStoneEnabled then connection:Disconnect(); return end
                    for _, tool in pairs(Workspace:GetDescendants()) do
                        if tool:IsA("Tool") and tool.Name:lower():find("stone") then
                            if tool.Parent ~= Player.Backpack and tool.Parent ~= Player.Character then
                                grabTool(tool)
                            end
                        end
                    end
                end)
                WindUI:Notify({Title = "自动拾取", Content = "正在自动拾取石头", Duration = 2})
            else
                WindUI:Notify({Title = "自动拾取", Content = "已停止拾取石头", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "自动拾取电池",
        Default = false,
        Callback = function(value)
            autoCollectBatteryEnabled = value
            if value then
                WindUI:Notify({Title = "自动拾取", Content = "开始自动拾取四个电池", Duration = 2})
                collectBatterySequence()
            else
                WindUI:Notify({Title = "自动拾取", Content = "已停止自动拾取电池", Duration = 2})
            end
        end
    })

    MazeTab:Toggle({
        Title = "自动拾取斧子",
        Default = false,
        Callback = function(value)
            autoCollectAxeEnabled = value
            if value then
                WindUI:Notify({Title = "自动拾取", Content = "开始自动拾取斧头", Duration = 2})
                collectAxeSequence()
            else
                WindUI:Notify({Title = "自动拾取", Content = "已停止自动拾取斧子", Duration = 2})
            end
        end
    })

    MazeTab:Dropdown({
        Title = "传送",
        Values = {"出生点", "斧头位置", "电池1", "电池2", "电池3", "电池4"},
        Value = "出生点",
        Callback = function(selected)
            local character = Player.Character
            if not character or not character.PrimaryPart then
                WindUI:Notify({Title = "传送", Content = "角色未加载", Duration = 2})
                return
            end
            local targetPos = nil
            if selected == "出生点" then
                local spawnObj = Workspace:FindFirstChild("SpawnLocation") or Workspace:FindFirstChild("Spawn")
                if spawnObj then targetPos = getWorldPosition(spawnObj) end
                if not targetPos then targetPos = Vector3.new(0, 10, 0) end
            elseif selected == "斧头位置" then
                local axe = Workspace:FindFirstChild("Axe")
                if axe then
                    if axe:IsA("Tool") and axe:FindFirstChild("Handle") then
                        targetPos = axe.Handle.Position
                    else
                        targetPos = getWorldPosition(axe)
                    end
                end
                if not targetPos then
                    WindUI:Notify({Title = "传送", Content = "地图中未找到斧头", Duration = 2})
                    return
                end
            else
                local engName = BatteryChineseMap[selected]
                if not engName then
                    WindUI:Notify({Title = "传送", Content = "内部错误：映射失败", Duration = 2})
                    return
                end
                local batObj = BatteryFolder and BatteryFolder:FindFirstChild(engName)
                if not batObj then
                    WindUI:Notify({Title = "传送", Content = "未找到 " .. selected, Duration = 2})
                    return
                end
                targetPos = getWorldPosition(batObj)
                if not targetPos then
                    WindUI:Notify({Title = "传送", Content = selected .. " 位置获取失败", Duration = 2})
                    return
                end
            end
            if targetPos then
                teleportTo(targetPos)
                WindUI:Notify({Title = "传送", Content = "已传送到: " .. selected, Duration = 2})
            end
        end
    })

    local function noclipLoop()
        if not NoclipEnabled then return end
        local character = Player.Character
        if character then
            for _, part in pairs(character:GetDescendants()) do
                if part:IsA("BasePart") and part.CanCollide then
                    part.CanCollide = false
                end
            end
        end
    end

    MazeTab:Toggle({
        Title = "穿墙",
        Default = false,
        Callback = function(value)
            NoclipEnabled = value
            if value then
                WindUI:Notify({Title = "穿墙", Content = "穿墙功能已开启", Duration = 2})
                if NoclipConnection then NoclipConnection:Disconnect() end
                NoclipConnection = RunService.Stepped:Connect(noclipLoop)
                noclipLoop()
            else
                WindUI:Notify({Title = "穿墙", Content = "穿墙功能已关闭", Duration = 2})
                if NoclipConnection then
                    NoclipConnection:Disconnect()
                    NoclipConnection = nil
                end
                local character = Player.Character
                if character then
                    for _, part in pairs(character:GetDescendants()) do
                        if part:IsA("BasePart") then
                            part.CanCollide = true
                        end
                    end
                end
            end
        end
    })

    local function itemPhaseLoop()
        if not itemPhaseEnabled then return end
        for _, part in pairs(Workspace:GetDescendants()) do
            if part:IsA("BasePart") and part.CanCollide == true then
                local model = part.Parent
                if not model:FindFirstChild("Humanoid") then
                    part.CanCollide = false
                end
            end
        end
    end

    MazeTab:Toggle({
        Title = "穿透物品",
        Default = false,
        Callback = function(value)
            itemPhaseEnabled = value
            if value then
                WindUI:Notify({Title = "穿透物品", Content = "物品穿透已开启", Duration = 2})
                if itemPhaseConnection then itemPhaseConnection:Disconnect() end
                itemPhaseConnection = RunService.Stepped:Connect(itemPhaseLoop)
                itemPhaseLoop()
            else
                WindUI:Notify({Title = "穿透物品", Content = "物品穿透已关闭", Duration = 2})
                if itemPhaseConnection then
                    itemPhaseConnection:Disconnect()
                    itemPhaseConnection = nil
                end
                for _, part in pairs(Workspace:GetDescendants()) do
                    if part:IsA("BasePart") then
                        part.CanCollide = true
                    end
                end
            end
        end
    })

    MazeTab:Toggle({
        Title = "自动破开木板",
        Default = false,
        Callback = function(value)
            autoBreakPlanksEnabled = value
            if value then
                local connection
                connection = RunService.Heartbeat:Connect(function()
                    if not autoBreakPlanksEnabled then connection:Disconnect(); return end
                    local character = Player.Character
                    if not character or not character.PrimaryPart then return end
                    local rootPos = character.PrimaryPart.Position
                    for _, obj in pairs(Workspace:GetDescendants()) do
                        if obj:IsA("BasePart") and obj.Name:lower():find("plank") then
                            if (obj.Position - rootPos).Magnitude < 10 then
                                obj:Destroy()
                            end
                        end
                    end
                end)
                WindUI:Notify({Title = "破开木板", Content = "正在自动破坏木板", Duration = 2})
            else
                WindUI:Notify({Title = "破开木板", Content = "已停止破坏木板", Duration = 2})
            end
        end
    })

    WindUI:Notify({ Title = "迷宫", Content = "功能已加载", Duration = 3, Icon = "check" })
end


-- ========== 刀刃球功能加载 ==========
local bladeBallLoaded = false
function loadBladeBallFeatures()
    if bladeBallLoaded then
        WindUI:Notify({ Title = "提示", Content = "刀刃球功能已加载", Duration = 3, Icon = "info" })
        return
    end
    bladeBallLoaded = true

    -- 创建主标签页
    local MainTab = Window:Tab({ Title = "刀刃球", Icon = "sword" })

    -- ==================== 辅助函数 ====================
    local function GetBall()
        for _, Ball in ipairs(workspace.Balls:GetChildren()) do
            if Ball:GetAttribute("realBall") then
                return Ball
            end
        end
        return nil
    end

    local function IsTarget(ball)
        return ball:GetAttribute("target") == tostring(game.Players.LocalPlayer)
    end

    -- ==================== 预判击球 ====================
    local AP = false
    local apConnection = nil
    MainTab:Toggle({
        Title = "预判击球",
        Default = false,
        Callback = function(Value)
            AP = Value
            if apConnection then apConnection:Disconnect(); apConnection = nil end
            if Value then
                local RunService = game:GetService("RunService")
                local Players = game:GetService("Players")
                local VirtualInputManager = game:GetService("VirtualInputManager")
                local Player = Players.LocalPlayer
                apConnection = RunService.Heartbeat:Connect(function()
                    if not AP then if apConnection then apConnection:Disconnect(); apConnection = nil end return end
                    local character = Player.Character
                    if not character then return end
                    local HRP = character:FindFirstChild("HumanoidRootPart")
                    if not HRP then return end
                    local ball = GetBall()
                    if not ball then return end
                    local DY = ball.zoomies.VectorVelocity or ball.AssemblyLinearVelocity
                    local Distance = Player:DistanceFromCharacter(ball.Position) - 3
                    local Radius = ball.Velocity.Magnitude / 2.2 + (Player:GetNetworkPing() * 20)
                    if ((HRP.Position - ball.Position).Unit:Dot(DY.Unit) > 0) and IsTarget(ball) and Distance <= Radius then
                        VirtualInputManager:SendMouseButtonEvent(0, 0, 0, true, game, 0)
                    end
                end)
            end
        end
    })

    -- ==================== 自动闪避球 ====================
    local AT = false
    local atConnection = nil
    MainTab:Toggle({
        Title = "自动闪避球",
        Default = false,
        Callback = function(Value)
            AT = Value
            if atConnection then atConnection:Disconnect(); atConnection = nil end
            if Value then
                local RunService = game:GetService("RunService")
                local Players = game:GetService("Players")
                local VirtualInputManager = game:GetService("VirtualInputManager")
                local Player = Players.LocalPlayer
                atConnection = RunService.Heartbeat:Connect(function()
                    if not AT then if atConnection then atConnection:Disconnect(); atConnection = nil end return end
                    local character = Player.Character
                    if not character then return end
                    local HRP = character:FindFirstChild("HumanoidRootPart")
                    if not HRP then return end
                    local ball = GetBall()
                    if not ball then return end
                    local DY = ball.zoomies.VectorVelocity or ball.AssemblyLinearVelocity
                    local BallSpeed = DY.Magnitude
                    if ((HRP.Position - ball.Position).Unit:Dot(DY.Unit) > 0) and IsTarget(ball) then
                        HRP.CFrame = ball.CFrame + Vector3.new(0.9*BallSpeed, -(0.9*BallSpeed), 0)
                        VirtualInputManager:SendMouseButtonEvent(0, 0, 0, true, game, 0)
                    end
                end)
            end
        end
    })

    -- ==================== 传送击打 ====================
    local autoSpam = false
    local spamConnection = nil
    local originalPos = nil
    local function StopAuto()
        if spamConnection then spamConnection:Disconnect(); spamConnection = nil end
        originalPos = nil
        autoSpam = false
    end
    local function StartAuto()
        if spamConnection then spamConnection:Disconnect() end
        autoSpam = true
        local Player = game.Players.LocalPlayer
        local RunService = game:GetService("RunService")
        local VirtualInputManager = game:GetService("VirtualInputManager")
        spamConnection = RunService.Heartbeat:Connect(function()
            if not autoSpam then return end
            local character = Player.Character
            if not character then return end
            local HRP = character:FindFirstChild("HumanoidRootPart")
            local highlight = character:FindFirstChild("Highlight")
            if not HRP or not highlight then return end
            for _, Ball in ipairs(workspace.Balls:GetChildren()) do
                if Ball:GetAttribute("realBall") then
                    local Speed = Ball.zoomies.VectorVelocity.Magnitude
                    local Distance = (HRP.Position - Ball.Position).Magnitude
                    local ratio = Distance / Speed
                    if ratio <= 0.7 then
                        originalPos = HRP.Position
                        local ballVelocity = Ball.zoomies.VectorVelocity.Unit
                        local teleportPosition = Ball.Position - (ballVelocity * 5)
                        HRP.CFrame = CFrame.new(teleportPosition)
                        VirtualInputManager:SendMouseButtonEvent(0, 0, 0, true, game, 0)
                        task.delay(0, function()
                            if originalPos and HRP then
                                local hitTarget = Ball:GetAttribute("lastHit")
                                if hitTarget ~= Player.Name then
                                    HRP.CFrame = CFrame.new(originalPos)
                                end
                            end
                        end)
                        break
                    end
                end
            end
        end)
    end
    MainTab:Toggle({
        Title = "传送击打",
        Default = false,
        Callback = function(Value)
            if Value then StartAuto() else StopAuto() end
        end
    })

    -- ==================== 防近球传送 ====================
    local antiBall = false
    local antiBallConnection = nil
    local antiCooldown = false
    MainTab:Toggle({
        Title = "防近球传送",
        Default = false,
        Callback = function(Value)
            antiBall = Value
            if antiBallConnection then antiBallConnection:Disconnect(); antiBallConnection = nil end
            if Value then
                local RunService = game:GetService("RunService")
                local Players = game:GetService("Players")
                local Player = Players.LocalPlayer
                antiBallConnection = RunService.Heartbeat:Connect(function()
                    if not antiBall or antiCooldown then return end
                    local character = Player.Character
                    if not character then return end
                    local HRP = character:FindFirstChild("HumanoidRootPart")
                    if not HRP then return end
                    local combat = character:FindFirstChild("Combat")
                    if combat then
                        local hitCD = combat:FindFirstChild("HitCD")
                        if hitCD and hitCD.Value > 0 then
                            antiCooldown = true
                            local backwardVector = -HRP.CFrame.LookVector * 15
                            HRP.CFrame = CFrame.new(HRP.Position + backwardVector)
                            task.delay(0, function() antiCooldown = false end)
                            return
                        end
                    end
                    for _, Ball in ipairs(workspace.Balls:GetChildren()) do
                        if Ball:GetAttribute("realBall") then
                            local distance = (HRP.Position - Ball.Position).Magnitude
                            if distance < 5 then
                                antiCooldown = true
                                local backwardVector = -HRP.CFrame.LookVector * 30
                                HRP.CFrame = CFrame.new(HRP.Position + backwardVector)
                                task.delay(0, function() antiCooldown = false end)
                                break
                            end
                        end
                    end
                end)
            end
        end
    })

    -- ==================== 防CD传送 ====================
    local autoEvade = false
    local evadeConnection = nil
    MainTab:Toggle({
        Title = "防CD传送",
        Default = false,
        Callback = function(Value)
            autoEvade = Value
            if evadeConnection then evadeConnection:Disconnect(); evadeConnection = nil end
            if Value then
                local RunService = game:GetService("RunService")
                local Players = game:GetService("Players")
                local Player = Players.LocalPlayer
                evadeConnection = RunService.Heartbeat:Connect(function()
                    if not autoEvade then return end
                    local character = Player.Character
                    if not character then return end
                    local HRP = character:FindFirstChild("HumanoidRootPart")
                    if not HRP then return end
                    local canHit = true
                    local hitCooldown = character:FindFirstChild("HitCooldown")
                    if hitCooldown and hitCooldown.Value > 0 then canHit = false end
                    for _, Ball in ipairs(workspace.Balls:GetChildren()) do
                        if Ball:GetAttribute("realBall") then
                            local target = Ball:GetAttribute("target")
                            local isTargetingMe = target and target == Player.UserId
                            if not canHit and isTargetingMe then
                                local lookVector = HRP.CFrame.LookVector
                                local evadePosition = HRP.Position - (lookVector * 30)
                                evadePosition = Vector3.new(math.clamp(evadePosition.X, -100, 100), HRP.Position.Y, math.clamp(evadePosition.Z, -100, 100))
                                local direction = (evadePosition - Ball.Position).Unit
                                local velocity = direction * 5000
                                if Ball:FindFirstChild("zoomies") then
                                    Ball.zoomies.VectorVelocity = velocity
                                else
                                    Ball:PivotTo(CFrame.new(evadePosition))
                                end
                                break
                            end
                        end
                    end
                end)
            end
        end
    })

