    local statsGui = nil
    local statsConnection = nil
    local trailConnection = nil
    local visSection = MainTab:Section({ Title = "透视", Opened = true })
    visSection:Toggle({
        Title = "透视球状态",
        Value = false,
        Callback = function(value)
            if value then
                local player = game.Players.LocalPlayer
                statsGui = Instance.new("ScreenGui", player:WaitForChild("PlayerGui"))
                statsGui.Name = "BallStatsUI"
                statsGui.ResetOnSpawn = false
                local frame = Instance.new("Frame", statsGui)
                frame.Size = UDim2.new(0, 180, 0, 80)
                frame.Position = UDim2.new(1, -200, 0, 100)
                frame.BackgroundColor3 = Color3.fromRGB(15,15,30)
                frame.BackgroundTransparency = 0.2
                frame.BorderSizePixel = 0
                frame.Active = true
                frame.Draggable = true
                local label = Instance.new("TextLabel", frame)
                label.Size = UDim2.new(1, -10, 1, -10)
                label.Position = UDim2.new(0, 5, 0, 5)
                label.BackgroundTransparency = 1
                label.TextColor3 = Color3.new(1,1,1)
                label.TextScaled = true
                label.Font = Enum.Font.GothamBold
                label.TextXAlignment = Enum.TextXAlignment.Left
                label.TextYAlignment = Enum.TextYAlignment.Top
                label.Text = "加载中..."
                statsConnection = game:GetService("RunService").RenderStepped:Connect(function()
                    local ball = GetBall()
                    if not ball then label.Text = "未找到球"; return end
                    local char = player.Character or player.CharacterAdded:Wait()
                    local hrp = char:FindFirstChild("HumanoidRootPart")
                    if not hrp then return end
                    local speed = math.floor(ball.Velocity.Magnitude)
                    local distance = math.floor((ball.Position - hrp.Position).Magnitude)
                    local target = ball:GetAttribute("target") or "无"
                    label.Text = string.format("球状态 | DYHUB\n速度: %s\n距离: %s\n目标: %s", speed, distance, target)
                end)
            else
                if statsConnection then statsConnection:Disconnect(); statsConnection = nil end
                if statsGui then statsGui:Destroy(); statsGui = nil end
            end
        end
    })

