                end)
            else
                if trailConnection then trailConnection:Disconnect(); trailConnection = nil end
                for _, Ball in ipairs(workspace.Balls:GetChildren()) do
                    local trail = Ball:FindFirstChild("TriasTrail")
                    if trail then trail:Destroy() end
