        for i, v in pairs(game:GetService("Players").LocalPlayer.PlayerGui:GetDescendants()) do
            if v.ClassName == "TextLabel" and v.Text == "Stuttgart Lastkraft" or v.ClassName == "TextLabel" and v.Text == "Stuttgart Omnibus" then
