    weaponsGroup:Button({ Title = "应用主武器", Callback = function() player:SetAttribute("Primary", primary); if player.Character then player.Character.Humanoid.Health = 0 end end })
    weaponsGroup:Button({ Title = "应用主武器迷彩", Callback = function() player:SetAttribute("PrimaryCamo", primarycamo); if player.Character then player.Character.Humanoid.Health = 0 end end })
    weaponsGroup:Dropdown({ Title = "副武器", Values = weapons, Value = weapons[1], Callback = function(v) secondary = v end })
