end


-- ========== 举重模拟器功能加载 ==========
local weightLiftLoaded = false
function loadWeightLiftFeatures()
    if weightLiftLoaded then
        WindUI:Notify({ Title = "提示", Content = "举重模拟器功能已加载", Duration = 3, Icon = "info" })
        return
    end
    weightLiftLoaded = true

    local Tab = Window:Tab({ Title = "举重模拟器", Icon = "dumbbell" })

    local autoLift = false
    local autoSell = false
    local liftThread = nil
    local sellThread = nil

    Tab:Toggle({
        Title = "自动举重",
        Value = false,
        Callback = function(state)
            autoLift = state
            if autoLift then
                if liftThread then task.cancel(liftThread) end
                liftThread = task.spawn(function()
                    while autoLift do
                        local ohTable1 = { [1] = "GainMuscle" }
                        game:GetService("ReplicatedStorage").RemoteEvent:FireServer(ohTable1)
                        task.wait()
                    end
                end)
            else
                if liftThread then task.cancel(liftThread); liftThread = nil end
            end
        end
    })

    Tab:Toggle({
        Title = "自动售卖",
        Value = false,
        Callback = function(state)
            autoSell = state
            if autoSell then
                if sellThread then task.cancel(sellThread) end
                sellThread = task.spawn(function()
                    while autoSell do
                        local ohTable1 = { [1] = "SellMuscle" }
                        game:GetService("ReplicatedStorage").RemoteEvent:FireServer(ohTable1)
                        task.wait()
                    end
                end)
            else
                if sellThread then task.cancel(sellThread); sellThread = nil end
            end
        end
    })

    WindUI:Notify({ Title = "举重模拟器", Content = "功能已加载", Duration = 3, Icon = "check" })
end


-- ========== 迷你战争功能加载 ==========
local minigameLoaded = false
function loadMinigameFeatures()
    if minigameLoaded then
        WindUI:Notify({ Title = "提示", Content = "迷你战争功能已加载", Duration = 3, Icon = "info" })
        return
    end
    minigameLoaded = true

    -- 创建标签页
    local Tab = Window:Tab({ Title = "迷你战争", Icon = "sword" })

    local Players = game:GetService("Players")
    local LocalPlayer = Players.LocalPlayer
    repeat task.wait() until LocalPlayer.Character
    repeat task.wait() until LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
    local HRP = LocalPlayer.Character.HumanoidRootPart

    local function Harvest(obj)
        task.spawn(function()
            pcall(function()
                local prompt = obj:FindFirstChildWhichIsA("ProximityPrompt", true)
                if prompt then
                    fireproximityprompt(prompt)
                end
                if obj:IsA("BasePart") then
                    firetouchinterest(HRP, obj, 0)
                    task.wait()
                    firetouchinterest(HRP, obj, 1)
                elseif obj:IsA("Model") then
                    local part = obj:FindFirstChildWhichIsA("BasePart", true)
                    if part then
                        firetouchinterest(HRP, part, 0)
                        task.wait()
                        firetouchinterest(HRP, part, 1)
                    end
                end
            end)
        end)
    end

    local function IsCrop(v)
        local n = v.Name:lower()
        return n:find("wheat") or n:find("corn") or n:find("carrot") or n:find("tomato") or n:find("farm") or n:find("crop") or n:find("plant")
    end

    local collecting = false

    Tab:Toggle({
        Title = "自动收集",
        Default = false,
        Callback = function(state)
            if state then
                if collecting then return end
                collecting = true
                task.spawn(function()
                    while collecting do
                        for _, v in pairs(workspace:GetDescendants()) do
                            if not collecting then break end
                            pcall(function()
                                if IsCrop(v) then
                                    Harvest(v)
                                end
                            end)
                        end
                        task.wait(0.3)
                    end
                end)
            else
                collecting = false
            end
        end
    })

