end

-- ========== 失落的前线功能加载 ==========
local frontlineLoaded = false
function loadFrontlineFeatures()
    if frontlineLoaded then
        WindUI:Notify({ Title = "提示", Content = "失落的前线功能已加载", Duration = 3, Icon = "info" })
        return
    end
    frontlineLoaded = true

    local Tab = Window:Tab({ Title = "失落的前线", Icon = "eye" })

    -- 原脚本核心逻辑
    local Players = game:GetService("Players")
    local RunService = game:GetService("RunService")
    local LocalPlayer = Players.LocalPlayer
    local Camera = workspace.CurrentCamera
    local ESP_CACHE = {}
    local espEnabled = false
    local highlightColor = Color3.fromRGB(255, 0, 0)

    local function createText()
        local text = Drawing.new("Text")
        text.Size = 14
        text.Center = true
        text.Outline = true
        text.Font = 2
        text.Color = Color3.fromRGB(255, 0, 0)
        text.Visible = false
        return text
    end

    local function updateESP()
        if not espEnabled then return end
        for _, player in pairs(Players:GetPlayers()) do
            if player == LocalPlayer then continue end
            if not ESP_CACHE[player] then
                ESP_CACHE[player] = { Text = createText() }
            end
            local cache = ESP_CACHE[player]
            local char = player.Character
            if not char then
                cache.Text.Visible = false
                continue
            end
            local humanoid = char:FindFirstChildOfClass("Humanoid")
            local root = char:FindFirstChild("HumanoidRootPart") or char:FindFirstChild("Head")
            if not humanoid or humanoid.Health <= 0 or not root then
                cache.Text.Visible = false
                continue
            end
            local hl = char:FindFirstChild("LF_ESP")
            if not hl then
                hl = Instance.new("Highlight")
                hl.Name = "LF_ESP"
                hl.FillTransparency = 1
                hl.OutlineTransparency = 0
                hl.OutlineColor = highlightColor
                hl.DepthMode = Enum.HighlightDepthMode.AlwaysOnTop
                hl.Parent = char
            end
            local myRoot = LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
            local distance = 0
            if myRoot then
                distance = math.floor((myRoot.Position - root.Position).Magnitude)
            end
            local pos, onScreen = Camera:WorldToViewportPoint(root.Position)
            if not onScreen then
                cache.Text.Visible = false
                continue
            end
            cache.Text.Text = "血量: " .. math.floor(humanoid.Health) .. "\n距离: " .. distance
            cache.Text.Position = Vector2.new(pos.X, pos.Y - 35)
            cache.Text.Visible = true
        end
        -- 清理无效玩家
        for player, cache in pairs(ESP_CACHE) do
            if not player or not player.Parent then
                if cache.Text then cache.Text:Remove() end
                ESP_CACHE[player] = nil
            end
        end
    end

    local function enableESP()
        espEnabled = true
        RunService.RenderStepped:Connect(updateESP)
    end

    local function disableESP()
        espEnabled = false
        for _, cache in pairs(ESP_CACHE) do
            if cache.Text then cache.Text:Remove() end
        end
        ESP_CACHE = {}
        for _, player in pairs(Players:GetPlayers()) do
            local char = player.Character
            if char then
                local hl = char:FindFirstChild("LF_ESP")
                if hl then hl:Destroy() end
            end
        end
    end

    Tab:Toggle({
        Title = "ESP开关",
        Default = false,
        Callback = function(state)
            if state then
                enableESP()
            else
                disableESP()
            end
        end
    })

    WindUI:Notify({ Title = "失落的前线", Content = "ESP 功能已加载", Duration = 3, Icon = "check" })
end


