    -- 飞行
    local flying = false
    local flyBodyVel = nil
    local flyConn = nil
    local flySpeed = 0
    local flyMaxSpeed = 500
    local function updateFlySpeed()
        if flySpeed < flyMaxSpeed then flySpeed = flySpeed + 1 end
    end
    local function getFlyDirection()
        local camera = workspace.CurrentCamera
        local look = camera.CFrame.LookVector
        local right = camera.CFrame.RightVector
        local dir = Vector3.new(0,0,0)
        if UserInputService:IsKeyDown(Enum.KeyCode.W) then dir = dir + look end
        if UserInputService:IsKeyDown(Enum.KeyCode.S) then dir = dir - look end
        if UserInputService:IsKeyDown(Enum.KeyCode.A) then dir = dir - right end
        if UserInputService:IsKeyDown(Enum.KeyCode.D) then dir = dir + right end
        return dir
    end
    movementSection:Toggle({
        Title = "飞行",
        Value = false,
        Callback = function(state)
            flying = state
            if state then
                if flyConn then flyConn:Disconnect() end
                flyConn = RunService.RenderStepped:Connect(function()
                    if not flying then return end
                    local char = LocalPlayer.Character
                    if not char then return end
                    local root = char:FindFirstChild("HumanoidRootPart")
                    if not root then return end
                    if not flyBodyVel then
                        flyBodyVel = Instance.new("BodyVelocity", root)
                        flyBodyVel.MaxForce = Vector3.new(2e10, 2e10, 2e10)
                        updateFlySpeed()
                    else
                        local dir = getFlyDirection()
                        if dir.Magnitude > 0 then
                            flyBodyVel.Velocity = dir * flySpeed
                            updateFlySpeed()
                        else
                            flyBodyVel.Velocity = Vector3.new(0,0,0)
                            flySpeed = 0
                        end
                    end
                end)
            else
                if flyBodyVel then flyBodyVel:Destroy(); flyBodyVel = nil end
                if flyConn then flyConn:Disconnect(); flyConn = nil end
                flySpeed = 0
            end
        end
    })

