    -- ==================== 服务器跳转 ====================
    local serverSection = Tab:Section({ Title = "服务器", Opened = true })
    local function teleportToServer(urlSuffix)
        local HttpService = game:GetService("HttpService")
        local request = syn and syn.request or http and http.request or http_request or request or httprequest
        if not request then
            WindUI:Notify({ Title = "错误", Content = "当前执行器不支持 HTTP 请求", Duration = 3, Icon = "x" })
            return
        end
        local response = request({ Url = "https://games.roblox.com/v1/games/" .. game.PlaceId .. urlSuffix, Method = "GET" })
        local data = HttpService:JSONDecode(response.Body)
        if data and data.data and #data.data > 0 then
            local server = data.data[1]
            game:GetService("TeleportService"):TeleportToPlaceInstance(game.PlaceId, server.id, LocalPlayer)
        else
            WindUI:Notify({ Title = "错误", Content = "未找到服务器", Duration = 2, Icon = "x" })
        end
    end
    serverSection:Button({
        Title = "传送到人数最少服务器",
        Callback = function()
            teleportToServer("/servers/Public?sortOrder=Asc&limit=25")
        end
    })
    serverSection:Button({
        Title = "传送到人数最多服务器",
        Callback = function()
            teleportToServer("/servers/Public?sortOrder=Desc&limit=25&excludeFullGames=true")
        end
    })
