                    VirtualUser:ClickButton2(Vector2.new())
                end)
                WindUI:Notify({ Title = "反AFK", Content = "已开启", Duration = 2 })
            end
        end
    })

    -- ==================== 贪吃蛇小游戏 ====================
    local snakeSection = Tab:Section({ Title = "贪吃蛇小游戏", Opened = true })
    snakeSection:Button({
        Title = "启动贪吃蛇小游戏",
        Desc = "重置角色以移除游戏界面",
        Callback = function()
            local ScreenGui = Instance.new("ScreenGui")
            ScreenGui.Name = "SnakeGame"
            ScreenGui.Parent = LocalPlayer:WaitForChild("PlayerGui")
            ScreenGui.ResetOnSpawn = false

            local border = Instance.new("Frame")
            border.Name = "border"
            border.Parent = ScreenGui
            border.BackgroundColor3 = Color3.fromRGB(0,0,0)
            border.BorderSizePixel = 0
            border.Size = UDim2.new(0, 720, 0, 570)

            local playground = Instance.new("Frame")
            playground.Name = "playground"
            playground.Parent = border
            playground.BackgroundColor3 = Color3.fromRGB(70,210,70)
            playground.BorderSizePixel = 0
            playground.Position = UDim2.new(0,10,0,10)
            playground.Size = UDim2.new(0,700,0,550)

            local cellSize = 25
            local rows = math.floor(playground.Size.Y.Offset / cellSize)
            local cols = math.floor(playground.Size.X.Offset / cellSize)

            -- 绘制网格（仅装饰）
            for row = 1, rows do
                for col = 1, cols do
                    local cell = Instance.new("Frame")
                    cell.Size = UDim2.new(0, cellSize, 0, cellSize)
                    cell.Position = UDim2.new(0, (col-1)*cellSize, 0, (row-1)*cellSize)
                    cell.BackgroundColor3 = Color3.fromRGB(70,210,70)
                    cell.BackgroundTransparency = 0.2
                    cell.BorderSizePixel = 1
                    cell.BorderColor3 = Color3.fromRGB(0,0,0)
                    cell.Parent = playground
                end
            end

            local fruit = Instance.new("ImageLabel")
            fruit.BackgroundTransparency = 1
            fruit.Size = UDim2.new(0, cellSize, 0, cellSize)
            fruit.Image = "rbxassetid://13575694232"
            fruit.Parent = playground

            local snakeHead = Instance.new("ImageLabel")
            snakeHead.BackgroundTransparency = 1
            snakeHead.Size = UDim2.new(0, cellSize, 0, cellSize)
            snakeHead.Image = "rbxassetid://6811016328"
            snakeHead.Parent = playground

            local snake = { snakeHead }
            local function createSegment(pos)
                local seg = Instance.new("ImageLabel")
                seg.BackgroundTransparency = 1
                seg.Size = UDim2.new(0, cellSize, 0, cellSize)
                seg.Image = "rbxassetid://6811016328"
                seg.Position = pos
                seg.Parent = playground
                return seg
            end

            local direction = Vector2.new(0,0)
            local timed = 0.5
            local prevPositions = {}
            local died = false

            local function updateSnakeBody()
                for i = #snake, 1, -1 do
                    prevPositions[i] = snake[i].Position
                end
                for i = #snake, 2, -1 do
                    snake[i].Position = prevPositions[i-1]
                end
            end

            local function isOccupied(pos)
                for _, seg in ipairs(snake) do
                    if seg.Position == pos then return true end
                end
                return false
            end

            local function randomFruitPos()
                local x,y
                repeat
                    x = math.random(0, cols-1)
                    y = math.random(0, rows-1)
                until not isOccupied(UDim2.new(0, x*cellSize, 0, y*cellSize))
                return UDim2.new(0, x*cellSize, 0, y*cellSize)
            end

            fruit.Position = randomFruitPos()

            local function resetGame()
                for i = #snake, 2, -1 do
                    snake[i]:Destroy()
                    task.wait(timed*1.25)
                end
                snake = { snakeHead }
                local seg = createSegment(snakeHead.Position)
                table.insert(snake, seg)
                direction = Vector2.new(0,0)
                timed = 0.5
                died = false
                fruit.Position = randomFruitPos()
            end

            local function checkCollision()
                local headPos = snakeHead.Position
                for i=3, #snake do
                    if snake[i].Position == headPos then
                        died = true
                        break
                    end
                end
            end

            local function onInput(input)
                if input.KeyCode == Enum.KeyCode.W and direction ~= Vector2.new(0,1) then direction = Vector2.new(0,-1)
                elseif input.KeyCode == Enum.KeyCode.S and direction ~= Vector2.new(0,-1) then direction = Vector2.new(0,1)
                elseif input.KeyCode == Enum.KeyCode.A and direction ~= Vector2.new(1,0) then direction = Vector2.new(-1,0)
                elseif input.KeyCode == Enum.KeyCode.D and direction ~= Vector2.new(-1,0) then direction = Vector2.new(1,0)
                end
            end
            UserInputService.InputBegan:Connect(onInput)

            task.spawn(function()
                while true do
                    task.wait(timed)
                    if died then
                        resetGame()
                    end
                    local headX = snakeHead.Position.X.Offset / cellSize + direction.X
                    local headY = snakeHead.Position.Y.Offset / cellSize + direction.Y
                    if headX < 0 or headX >= cols or headY < 0 or headY >= rows then
                        died = true
                    else
                        local newPos = UDim2.new(0, headX*cellSize, 0, headY*cellSize)
                        if snakeHead.Position == fruit.Position then
                            local newSeg = createSegment(UDim2.new(0, headX*cellSize, 0, headY*cellSize))
                            table.insert(snake, newSeg)
                            timed = math.max(0.1, timed - 0.02)
                            fruit.Position = randomFruitPos()
                        end
                        checkCollision()
                        if not died then
                            snakeHead.Position = newPos
                            updateSnakeBody()
                        end
                    end
                end
            end)
        end
    })

    WindUI:Notify({ Title = "凶手与警长", Content = "功能已加载", Duration = 3, Icon = "check" })
end


-- ========== 植物大战脑红功能加载 ==========
local plantVSRedLoaded = false
function loadPlantVSRedFeatures()
    if plantVSRedLoaded then
