                        task.wait(0.1)
                    end
                end)
            end
        end
    })

    -- ==================== 出售植物 ====================
    local autoSellPlant = false
    local sellInterval = 0.1
    MainTab:Section({ Title = "出售植物" })
    MainTab:Toggle({
        Title = "自动出售植物",
        Value = false,
        Callback = function(state)
            autoSellPlant = state
            if state then
                task.spawn(function()
                    while autoSellPlant do
                        pcall(function()
                            local args = { [2] = true }
                            game:GetService("ReplicatedStorage").Remotes.ItemSell:FireServer(unpack(args))
                        end)
                        task.wait(sellInterval)
                    end
                end)
            end
        end
    })

    MainTab:Slider({
        Title = "出售间隔",
        Value = { Min = 0.05, Max = 1, Default = 0.1 },
        Callback = function(v) sellInterval = v end
    })

    -- ==================== 购买种子 ====================
    local BuyTab = Window:Tab({ Title = "购买种子", Icon = "shopping-cart" })

    local seedMap = {
        ["仙人掌种子"] = "Cactus Seed",
        ["草莓种子"] = "Strawberry Seed",
        ["南瓜种子"] = "Pumpkin Seed",
        ["向日葵种子"] = "Sunflower Seed",
        ["火龙果种子"] = "Dragon Fruit Seed",
        ["茄子种子"] = "Eggplant Seed",
        ["西瓜种子"] = "Watermelon Seed",
        ["葡萄种子"] = "Grape Seed",
        ["可可坦克种子"] = "Cocotank Seed",
        ["食人植物种子"] = "Carnivorous Plant Seed",
        ["胡萝卜先生种子"] = "Mr Carrot Seed",
        ["番茄三重奏种子"] = "Tomatrio Seed",
        ["蘑菇宾诺种子"] = "Shroombino Seed",
        ["芒果种子"] = "Mango Seed",
        ["柠檬王种子"] = "King Limone Seed"
    }
    local chineseSeedList = {}
    for cn, _ in pairs(seedMap) do table.insert(chineseSeedList, cn) end
    table.sort(chineseSeedList)

    local selectedSeeds = {}
    BuyTab:Dropdown({
        Title = "选择要购买的种子",
        Values = chineseSeedList,
        Value = {},
        Multi = true,
        Callback = function(selected)
            selectedSeeds = {}
            for _, cn in ipairs(selected) do
                if seedMap[cn] then table.insert(selectedSeeds, seedMap[cn]) end
            end
        end
    })

    BuyTab:Button({
        Title = "购买一次选中种子",
        Callback = function()
            for _, seed in ipairs(selectedSeeds) do
                local args = { seed, true }
                pcall(function()
                    game:GetService("ReplicatedStorage").Remotes.BuyItem:FireServer(unpack(args))
                end)
                WindUI:Notify({ Title = "购买", Content = "已购买 " .. seed, Duration = 1, Icon = "shopping-cart" })
                task.wait(0.1)
            end
        end
    })

    local autoBuyEnabled = false
    local buyConnection = nil
    BuyTab:Toggle({
        Title = "自动购买选中种子",
        Value = false,
        Callback = function(state)
            autoBuyEnabled = state
            if buyConnection then buyConnection:Disconnect(); buyConnection = nil end
            if state then
                buyConnection = game:GetService("RunService").Heartbeat:Connect(function()
                    for _, seed in ipairs(selectedSeeds) do
                        pcall(function()
                            game:GetService("ReplicatedStorage").Remotes.BuyItem:FireServer(seed, true)
                        end)
                        task.wait(0.2)
                    end
                end)
            end
        end
    })

    BuyTab:Button({
        Title = "强制停止自动购买",
        Callback = function()
            autoBuyEnabled = false
            if buyConnection then buyConnection:Disconnect(); buyConnection = nil end
            WindUI:Notify({ Title = "已停止", Content = "自动购买已停止", Duration = 2, Icon = "stop-circle" })
        end
    })

    WindUI:Notify({ Title = "植物大战脑红", Content = "功能已加载", Duration = 3, Icon = "check" })
end


